INSERT INTO "meta" VALUES('candidates','{"description": "Australian candidate transparency dataset: the federal 48th Parliament plus state/territory parliaments (see jurisdiction field). Federal roster from AEC Members Elected (House) and OpenAustralia (Senate) with AEC donor data; state rosters from data/sources/states/. Policy positions are added separately with their own sources. See ../CONTRIBUTING.md.", "house_source": "https://results.aec.gov.au/31496/Website/HouseDownloadsMenu-31496-Csv.htm", "senate_source": "https://www.openaustralia.org.au/senators/", "donor_source": "https://transparency.aec.gov.au/MemberOfParliament", "last_updated": "2026-06-26"}');
INSERT INTO "meta" VALUES('party_donations','{"description": "Disclosed donations to political parties (AEC detailed receipts, Donation Received only), summed per donor across the four most recent financial years. Branch returns are grouped into party families.", "source_url": "https://transparency.aec.gov.au/AnnualDetailedReceipts", "window": "2021-22 to 2024-25", "note": "Excludes public funding and electoral-commission payments. Only donations above the disclosure threshold are itemised in AEC returns.", "last_updated": "2026-06-26"}');
