INSERT INTO "party_donation" VALUES(2474,'Australian Christians','Mervyn Tomkins','2021-22',20050);
INSERT INTO "position" VALUES(1,'alicia-payne-canberra','immigration','Payne criticises Australia''s immigration detention as ''destructive and expensive'' and argues indefinite detention is unjustifiable. She supports abolishing temporary protection visas, expanding the government-funded humanitarian intake (citing Labor''s 27,000-place commitment) plus a 5,000-place community-sponsored program, increasing UNHCR funding, and accepting New Zealand''s offer to resettle refugees.',1);
INSERT INTO "position" VALUES(2,'alicia-payne-canberra','foreign_policy','In a 28 July 2025 interview, Payne said she has continually called for an immediate and permanent ceasefire in Gaza as the most effective way to protect innocent lives, stated that by not allowing aid into Gaza Israel is breaching international law, and said she longs to see Australia recognise a Palestinian state as soon as possible, at a time most advantageous to peace.',1);
INSERT INTO "position" VALUES(3,'andrew-leigh-fenner','faith','Andrew Leigh is a self-described atheist; he has written and spoken publicly about being an atheist while arguing that churches benefit society.',1);
INSERT INTO "position" VALUES(4,'andrew-leigh-fenner','immigration','Leigh, a Labor MP and economist, publicly defends immigration, stating in 2026 that the government has ''reduced migration from the record highs it was under the Coalition.'' He has more broadly framed Australia''s non-discriminatory and skilled migration system as a source of national strength.',1);
INSERT INTO "position" VALUES(5,'andrew-leigh-fenner','foreign_policy','Leigh has advocated for evidence-based foreign aid, stating the Australian Government understands its obligation to ensure aid delivered has the maximum positive impact and arguing that randomised trials and rigorous evaluation should determine which development interventions work.',1);
INSERT INTO "position" VALUES(6,'andrew-leigh-fenner','economic_nationalism','Andrew Leigh is a strong advocate for free trade and unilateral tariff reduction, opposing protectionism. He has argued Australia should continue advocating for tariff removal without imposing retaliatory tariffs, stating "Australia is a trading nation and a strong advocate for open and rules-based trade" and "Trade expands opportunity. Isolation shrinks it."',1);
INSERT INTO "position" VALUES(7,'david-smith-bean','faith','Having been educated at a Marist Brothers college, David Smith identifies as a Catholic.',1);
INSERT INTO "position" VALUES(8,'david-smith-bean','foreign_policy','Smith is listed as an Australian member of the Inter-Parliamentary Alliance on China (IPAC), a cross-party international group of legislators focused on relations with the People''s Republic of China.',1);
INSERT INTO "position" VALUES(9,'alex-hawke-mitchell','faith','Alex Hawke was raised as an Anglican but now attends Hillsong Church; in his maiden speech he affirmed Christian values such as grace, forgiveness and redemption.',1);
INSERT INTO "position" VALUES(10,'alex-hawke-mitchell','immigration','Hawke, a former Liberal Immigration Minister, has called for the government to resolve the status of roughly 7,500 long-term asylum seekers, saying: ''I think the Government should resolve this now. People have been here a long time and the reality of their condition is that they will be staying here.''',1);
INSERT INTO "position" VALUES(11,'alex-hawke-mitchell','foreign_policy','As Minister for International Development and the Pacific, Hawke called for closer ties to and development assistance for the Pacific region, stating ''their prosperity is our prosperity,'' while supporting a reduction in the overall foreign aid budget. He also argued his Pacific engagement did not require further action by Australia on climate change.',1);
INSERT INTO "position" VALUES(12,'alex-hawke-mitchell','economic_nationalism','In a 2019 keynote, Alex Hawke referenced the Coalition government''s legislation "establishing the kind of rules around foreign investment in critical national infrastructure" and "banning foreign donations into the Australian political system," stating this legislation "has really shored up the ability of Australia to stand strong" and that "a strong, secure sovereign region fundamentally enables economic prosperity."',1);
INSERT INTO "position" VALUES(13,'alex-hawke-mitchell','citizenship_eligibility','During the 2017 citizenship questions over members with foreign-born parents, Hawke stated he is ''an Australian citizen only and have never held or acquired or sought Greek or any other citizenship.'' He was not referred to the High Court.',1);
INSERT INTO "position" VALUES(14,'alison-byrnes-cunningham','economic_nationalism','In her first speech, Alison Byrnes voiced support for local steel manufacturing in the Illawarra, stating "We stand ready to use our skills to produce high quality steel in a more sustainable way," and emphasised local businesses and workers having the skills for the modern economy.',1);
INSERT INTO "position" VALUES(15,'alison-penfold-lyne','immigration','In her first speech, Penfold said: ''We must return to an immigration policy founded on "Team Australia" not "hotel Australia", one where our shared values matter—the basis of our multicultural success story,'' advocating a values-based, selective approach to immigration.',1);
INSERT INTO "position" VALUES(16,'alison-penfold-lyne','economic_nationalism','In her maiden speech, Alison Penfold highlighted local farming, dairy, beef, oyster and timber industries as "valued economic drivers" of family-run small businesses in Lyne, backed "small business as the engine room of the economy," and defended the live export industry, criticising regulation she said "bans industries" and "adds costs to business."',1);
INSERT INTO "position" VALUES(17,'allegra-spender-wentworth','immigration','Spender''s platform includes support for skilled migration and humanitarian treatment of refugees; she is a member of the Joint Standing Committee on Migration and authored an opinion piece (Australian Financial Review, June 2024) arguing for a rational, economically grounded approach to migration.',1);
INSERT INTO "position" VALUES(18,'allegra-spender-wentworth','foreign_policy','Spender signed a joint letter with other crossbench (teal) MPs requesting that Foreign Minister Penny Wong restore Australian funding to the UN Relief and Works Agency for Palestinian Refugees (UNRWA).',1);
INSERT INTO "position" VALUES(19,'andrew-gee-calare','immigration','Gee, an independent MP, championed the case of the Bathurst-based Nguyen family to remain in Australia, welcoming the Immigration Minister''s grant of visas after a petition of over 22,000 signatures, saying it ''brings to an end a decade of stress and uncertainty for this much-loved Bathurst family'' and was ''proof that people power can prevail.''',1);
INSERT INTO "position" VALUES(20,'andrew-gee-calare','economic_nationalism','In his maiden speech, Andrew Gee called for "a targeted, national manufacturing strategy," arguing "Other countries with high labour costs have been able to do it and we can too," and advocated value-adding to agriculture, noting "the vast majority of agricultural commodities produced in the central west leave the region without any value adding" and that food processing is a growth area for Australia.',1);
INSERT INTO "position" VALUES(21,'angus-taylor-hume','immigration','On becoming Liberal Party leader in February 2026, Taylor named immigration his "top priority" and called for lower immigration and a policy that "puts the interests of Australians first," stating Australia should "deny access of immigrants from high risk regions who bring violence and hate."',1);
INSERT INTO "position" VALUES(22,'angus-taylor-hume','foreign_policy','As Shadow Defence Minister, Taylor said on 15 July 2025 that Australia should raise its defence budget from around 2.3% of GDP to at least 3%, that this is vital to support commitments under the AUKUS pact, and that Australia must be prepared to act on Taiwan''s security with clear, principled commitments from Canberra.',1);
INSERT INTO "position" VALUES(23,'anthony-albanese-grayndler','faith','Anthony Albanese describes his Catholic faith as part of who he is, citing his Catholic upbringing as an influence on his values; he is generally described as a non-practising Catholic and was sworn in by affirmation rather than on a Bible.',1);
INSERT INTO "position" VALUES(24,'anthony-albanese-grayndler','immigration','As Prime Minister, Albanese''s government in February 2023 abolished temporary protection visas, allowing up to 19,000 asylum seekers to stay in Australia permanently. In his 1996 maiden speech he expressed support for multiculturalism.',1);
INSERT INTO "position" VALUES(25,'anthony-albanese-grayndler','foreign_policy','As Prime Minister, Albanese''s government formally recognised the State of Palestine (announced August 2025, effective 21 September 2025) as part of a coordinated push for a two-state solution; he officially commenced the AUKUS security pact on 13 March 2023 (acquiring nuclear-powered submarines); restored high-level dialogue with China, meeting Xi Jinping in November 2022 and visiting China in November 2023; and pledged a further $100 million in aid to Ukraine in July 2022.',1);
INSERT INTO "position" VALUES(26,'anthony-albanese-grayndler','economic_nationalism','Anthony Albanese has championed the "Future Made in Australia" agenda, stating "Our Government is investing in manufacturing to make more things here" and that government must "be more assertive in capitalising on our comparative advantages and building sovereign capability in areas of national interest." He cited "a new and widespread willingness to make economic interventions on the basis of national interest and national sovereignty."',1);
INSERT INTO "position" VALUES(27,'anthony-albanese-grayndler','citizenship_eligibility','Although birth to an Italian father would ordinarily confer Italian citizenship, his father was not recorded on his birth certificate, so he was not a dual citizen and met the eligibility requirements of section 44 of the Constitution.',1);
INSERT INTO "position" VALUES(28,'ash-ambihaipahar-barton','immigration','In her first speech, Ambihaipahar, of Tamil Sri Lankan and Papua New Guinean heritage, embraced multicultural Australia, stating ''While Barton championed the White Australia policy, I live and breathe multiculturalism'' and describing herself as ''the walking, talking embodiment of modern Australia,'' committing to fight racism and discrimination.',1);
INSERT INTO "position" VALUES(29,'barnaby-joyce-new-england','faith','Barnaby Joyce is a Roman Catholic.',1);
INSERT INTO "position" VALUES(30,'barnaby-joyce-new-england','immigration','In September 2015 Joyce called for Australia to accept more Syrian refugees, with a preference to prioritise Christian refugees. In 2016 he opposed One Nation''s proposed Muslim immigration ban, and he has stated his opposition to banning the burqa.',1);
INSERT INTO "position" VALUES(31,'barnaby-joyce-new-england','foreign_policy','On 10 August 2018, Joyce defended maintaining Australia''s foreign aid budget, framing aid to Pacific island nations as a strategic necessity, saying Australia needs to support island nations ''otherwise the Chinese government will just move in there and support them.''',1);
INSERT INTO "position" VALUES(32,'barnaby-joyce-new-england','economic_nationalism','Barnaby Joyce has stated a preference for Australian ownership of agricultural assets, saying "My preference is always for the Australian people to be owner of the Australian asset" and "I''ll never work to the exclusion of foreign investment but my preference is always for the Australian owner of the Australian asset." He supported blocking selected foreign bids (e.g. Kidman & Co) and warned against monopolistic foreign control of agricultural infrastructure.',1);
INSERT INTO "position" VALUES(33,'barnaby-joyce-new-england','citizenship_eligibility','Held New Zealand citizenship by descent from his father, which the High Court found rendered him ineligible under section 44(i); his 2016 election was declared invalid on 27 October 2017. Having renounced his New Zealand citizenship in August 2017, he was eligible to recontest and won the December 2017 New England by-election.',1);
INSERT INTO "position" VALUES(34,'chris-bowen-mcmahon','immigration','As Minister for Immigration and Citizenship (2010-2013), Bowen secured an offshore processing arrangement with Malaysia (the "Malaysia Solution") in 2011, under which Australia would transfer asylum seekers who arrived by boat to Malaysia in exchange for resettling refugees from there; the arrangement was struck down by the High Court in September 2011.',1);
INSERT INTO "position" VALUES(35,'chris-bowen-mcmahon','foreign_policy','In an ABC TV Insiders interview on 26 November 2023, Bowen said ''Israel can only really be secure and free when Palestine is secure and free, and ultimately, that is our long term objective,'' reaffirmed that Israel has rights and obligations under international law, and said the government wanted ceasefire arrangements to become more permanent as the pathway to peace.',1);
INSERT INTO "position" VALUES(36,'chris-bowen-mcmahon','economic_nationalism','Chris Bowen has backed bringing solar panel manufacturing to Australia under the Future Made in Australia agenda, stating "We invented the modern solar panel... We''ve been missing, by and large, the middle part of manufacturing solar panels," and that the Hunter "will be centre of our Future Made in Australia," linking the policy to local jobs and strengthened supply chains.',1);
INSERT INTO "position" VALUES(37,'dai-le-fowler','faith','Dai Le is a lapsed Catholic who has stated she still believes in God and prays to the Virgin Mary, crediting her election win to the intercession of the Blessed Virgin Mary.',1);
INSERT INTO "position" VALUES(38,'dai-le-fowler','immigration','Le, an independent and former refugee, takes a conditional view of migration, saying that if migration places are increased the government ''has the duty to ensure that there are immediate plans to build more housing, more public transport infrastructure and more local services,'' and that government should ''first look locally.'' She notes her electorate resettled nearly 10,000 refugees without additional infrastructure funding, and pledges to celebrate cultural diversity.',1);
INSERT INTO "position" VALUES(39,'dai-le-fowler','economic_nationalism','Dai Le has advocated for support of local small and medium manufacturing businesses, noting "Manufacturing is the largest employer in Fowler, standing at 40% yet the plan doesn''t really invest in our local community, many of whom are small to medium sized manufacturing companies." She criticised the Future Made in Australia plan as inadequately supporting local manufacturers facing rising utility and input costs.',1);
INSERT INTO "position" VALUES(40,'dai-le-fowler','citizenship_eligibility','After her 2022 election, questions were raised about her section 44 eligibility given her refugee background; she stated on her AEC declaration that she had never been a subject or citizen of any country other than Australia and confirmed the AEC accepted her nomination, rejecting suggestions of ineligibility.',1);
INSERT INTO "position" VALUES(41,'dan-repacholi-hunter','economic_nationalism','In his maiden speech, Dan Repacholi backed the Hunter''s coal industry and mining workforce, stating "coal will continue to play a role for many years to come in powering the world" and "I will make sure the Hunter remains at the forefront of supplying coal to the world," while also pointing to future local industries such as hydrogen, batteries, wind and solar.',1);
INSERT INTO "position" VALUES(42,'ed-husic-chifley','faith','Husic was born to Bosnian Muslim immigrant parents and is the first Muslim elected to Australia''s federal parliament; his household practised Islam while also celebrating Christmas and Easter, and after the September 11 attacks he described himself as a ''non-practising'' Muslim. He took his ministerial oath on the Quran.',1);
INSERT INTO "position" VALUES(43,'ed-husic-chifley','immigration','In his maiden speech, Husic, the first Muslim member of federal parliament, praised migrants and multiculturalism, stating ''multiculturalism represents a vast reservoir of energy this nation can tap into,'' and that harnessing talent ''from the first owners to the recently arrived'' builds ''one of the greatest countries on the planet.''',1);
INSERT INTO "position" VALUES(44,'ed-husic-chifley','foreign_policy','Husic supports recognition of a Palestinian state and, after being dropped from cabinet, said on 12 May 2025 the government should do whatever it could to back Palestinian statehood as quickly as possible; he described mass starvation in Gaza as a conscious decision and the use of starvation as a war crime, and in May 2025 called for targeted sanctions against Israeli government ministers overseeing the military campaign in Gaza.',1);
INSERT INTO "position" VALUES(45,'ed-husic-chifley','economic_nationalism','Ed Husic has advocated for rebuilding Australian domestic manufacturing and self-sufficiency, stating "Australia ranks last in a list of OECD countries in terms of manufacturing self-sufficiency" and "We want to send this signal to industry and its workers: Australian Labor is on the side of Australian manufacturing," describing manufacturing as "in the DNA of the Australian Labor Party."',1);
INSERT INTO "position" VALUES(46,'emma-mcbride-dobell','citizenship_eligibility','Obtained Irish citizenship by descent (through a grandfather born in Northern Ireland) in 2001 but renounced it before standing for parliament at the 2013 federal election, resolving her foreign citizenship for section 44 eligibility purposes.',1);
INSERT INTO "position" VALUES(47,'fiona-phillips-gilmore','faith','In a parliamentary speech on the Religious Discrimination Bill, Phillips stated she was raised as a Christian and that she has had ministers and missionaries in her family going back many generations.',1);
INSERT INTO "position" VALUES(48,'fiona-phillips-gilmore','economic_nationalism','Fiona Phillips criticised the federal Manufacturing Modernisation Fund for allocating only $100,000 to one company in her South Coast electorate, calling it "disgraceful" and "a drop in the ocean," and argued "the government needs to be providing more stimulus funds for the South Coast" to support local manufacturers.',1);
INSERT INTO "position" VALUES(49,'jamie-chaffey-parkes','faith','In his first speech to federal parliament (delivered July 2025), Chaffey explicitly referred to his Christian faith, saying it ''aligns with my Christian faith,'' and thanked his ''church family.''',1);
INSERT INTO "position" VALUES(50,'jamie-chaffey-parkes','immigration','In his first speech, Chaffey (Nationals) highlighted ''the need for targeted immigration'' as a longstanding regional priority and emphasised attracting ''skilled and talented workers, and professionals'' to grow the population of the Parkes electorate.',1);
INSERT INTO "position" VALUES(51,'jason-clare-blaxland','immigration','As Education Minister, Clare announced a cap of 270,000 international student enrolments for 2025 to create ''a better and a fairer system'' by returning enrolments toward pre-pandemic levels, framing it as a response to housing affordability concerns linked to record migration and a crackdown on ''shonks'' exploiting the sector.',1);
INSERT INTO "position" VALUES(52,'jason-clare-blaxland','foreign_policy','On 10 October 2024, Clare said that while every country has a right to defend itself it must comply with international law, and when asked whether Israel was complying he said ''the bombing of schools and hospitals, I think, are not complying with international law,'' adding that his constituents were asking for a ceasefire and for the war to end.',1);
INSERT INTO "position" VALUES(53,'jerome-laxale-bennelong','immigration','Laxale emphasises support for multiculturalism in one of Australia''s most multicultural electorates, stating ''I am incredibly proud to represent an electorate which is among the most multicultural in this country'' and listing ''enhancing multiculturalism'' among his priorities.',1);
INSERT INTO "position" VALUES(54,'jerome-laxale-bennelong','foreign_policy','In a 2022 parliamentary speech on the Iran protests following the death of Mahsa Amini in morality-police custody, Laxale said he stood for his local Iranian community in Bennelong and used his position to ensure their message and that of their families was heard.',1);
INSERT INTO "position" VALUES(55,'jerome-laxale-bennelong','citizenship_eligibility','Inherited French and Mauritian citizenship from his parents and renounced both (recorded as held until 2022) before standing at the 2022 federal election, in order to comply with section 44 of the Constitution.',1);
INSERT INTO "position" VALUES(56,'julian-leeser-berowra','faith','Leeser is Jewish; he is described as the first Jewish Liberal member of the House of Representatives from New South Wales and a member of the Emanuel Synagogue in Woollahra. He announced he would wear a kippah in federal parliament for one week as a statement against rising antisemitism in Australia.',1);
INSERT INTO "position" VALUES(57,'julian-leeser-berowra','foreign_policy','Leeser supports Australian recognition of West Jerusalem as Israel''s capital and called the Albanese government''s 2022 reversal ''shambolic''. He opposes an immediate Gaza ceasefire while hostages are held and Hamas remains, saying a ceasefire would let terrorist organisations ''regroup and reform'', and opposes imposing a timetable on a two-state solution ''without full and proper negotiations on the final-status issues''. After the October 2023 Hamas attack he called on Australia to suspend diplomatic relations with Iran.',1);
INSERT INTO "position" VALUES(58,'kevin-hogan-page','economic_nationalism','As Shadow Minister for Trade, Hogan called for the Government to give Australian producers and exporters impacted by US tariffs the same high-level advocacy shown in trade engagement with China, saying the Prime Minister must deliver trade outcomes for Australian exporters with all major partners.',1);
INSERT INTO "position" VALUES(59,'matt-thistlethwaite-kingsford-smith','faith','Wikipedia states Thistlethwaite ''grew up in the suburb of Maroubra in a Catholic family.'' This describes his upbringing; no source explicitly states his current personal religious belief.',1);
INSERT INTO "position" VALUES(60,'matt-thistlethwaite-kingsford-smith','foreign_policy','In a House of Representatives debate (2 June 2026) Thistlethwaite presented the government''s supportive position on AUKUS, stating that nuclear-propelled submarines ''have a longer range and endurance and greater stealth, which means that they can go undetected for longer'' than conventional alternatives, and framing AUKUS and the three-phase submarine acquisition plan as essential to Australia''s security through strong partnerships and alliances.',1);
INSERT INTO "position" VALUES(61,'michael-mccormack-riverina','faith','McCormack is a Roman Catholic; Wikipedia notes he, ''a Roman Catholic, married Catherine (nee Shaw) in Saint Michael''s Cathedral, Wagga Wagga in 1986,'' and he publicly identified himself ''as a proud Catholic'' when selected to represent Australia at Pope Francis'' 2025 funeral.',1);
INSERT INTO "position" VALUES(62,'michael-mccormack-riverina','immigration','In a 2018 interview on regional migration, McCormack said "all options are on the table" for improving migration policy and supported "encouraging strategic targeted migration" to fill regional skill shortages, stating "Migrants bring a willingness to work. They start small businesses and their contribution is highly valued" and that regional migration "needs to be at the forefront of our immigration system."',1);
INSERT INTO "position" VALUES(63,'michael-mccormack-riverina','foreign_policy','Responding to a protest outside his Wagga office, McCormack stated that protest organisers ''do not represent the majority of the Riverina who support Israel'', and added: ''Palestine has been recognised as a state by the Australian government and the people there do need to live in peace.''',1);
INSERT INTO "position" VALUES(64,'michelle-rowland-greenway','faith','Wikipedia''s ''Personal life'' section states that Michelle Rowland and her family are Catholic Christians.',1);
INSERT INTO "position" VALUES(65,'mike-freelander-macarthur','faith','Freelander identifies as Jewish, describing himself as ''not a particularly religious Jew, but I still describe myself as Jewish''; he comes from one of the oldest Jewish families in Australia and had his bar mitzvah at Temple Emanuel, Woollahra.',1);
INSERT INTO "position" VALUES(66,'mike-freelander-macarthur','foreign_policy','In a parliamentary statement (16 October 2023) Freelander affirmed ''Israel has a right to exist ... and Israel has the right to protect itself'' and condemned Hamas, saying it had ''opened the gates of hell''. He also grieved for civilian casualties on all sides, stating ''in this conflict the Palestinians will be victims just as much as the Israelis'', and expressed hope for the safe release of hostages and a resolution with minimal further loss of life.',1);
INSERT INTO "position" VALUES(67,'mike-freelander-macarthur','economic_nationalism','In his maiden speech, Freelander said he intends to make sure that in Macarthur ''we foster local jobs so that people can work locally''.',1);
INSERT INTO "position" VALUES(68,'nicolette-boele-bradfield','foreign_policy','Boele has called twice for a parliamentary inquiry into the AUKUS deal. In a June 2025 interview she said there is ''a muddiness ... between the proposed AUKUS plan and what it''s trying to achieve'' and that ''if it''s deterrence, putting all our eggs into this basket doesn''t seem ... a really good strategy'', describing an inquiry as a prudent investment.',1);
INSERT INTO "position" VALUES(69,'pat-conaghan-cowper','economic_nationalism','Conaghan stated that ''collaboration is crucial if we are to build scale in Australian manufacturing and create the jobs we need now in the COVID-19 recovery and for generations to come'', and said the aim is to support collaborations that spur private sector investment and help Australian manufacturers innovate and become more competitive.',1);
INSERT INTO "position" VALUES(70,'pat-conroy-shortland','foreign_policy','As Minister for Defence Industry and Pacific Island Affairs, Conroy stated (December 2024) that ''AUKUS is not about charity. AUKUS is about increasing the collective security of the three nations involved'' and that it would endure because it is in all three countries'' self-interest. On China he emphasised arguing ''for that rules-based order'', and on the Pacific said Australia will demonstrate it ''will not enter into security or policing agreements with a third country without agreement by Australia'', citing the Nauru treaty framework.',1);
INSERT INTO "position" VALUES(71,'pat-conroy-shortland','economic_nationalism','As Minister for Defence Industry, Conroy stated that building a sovereign defence industry and ecosystem is at the heart of the Government''s efforts and that this is the best way to ensure a defence future ''made in Australia, by Australians'', adding the Government is committed to a defence future made in Australia to make the nation more prepared and resilient.',1);
INSERT INTO "position" VALUES(72,'sally-sitou-reid','immigration','In her 2022 first speech, Sitou, the daughter of refugees who fled Indochina, celebrated Australia''s transformation "from an embrace of a White Australia policy to a country that is now a majority-migrant nation," describing the White Australia policy as based on "fear and a failure of imagination." She praised former PM Malcolm Fraser''s 1977 refugee policy as "on the right side of history" and said diverse representatives "make our parliament better and our democracy stronger."',1);
INSERT INTO "position" VALUES(73,'sharon-claydon-newcastle','foreign_policy','As co-chair of the Parliamentary Friends of Palestine, Claydon co-signed a statement (25 October 2023) calling for ''an immediate ceasefire and an end to the violence in Israel and Palestine'', condemning both Hamas attacks and Israeli attacks on Gaza civilians as breaches of humanitarian law, stating ''the protection of civilian lives is paramount and international humanitarian law must be observed'', and affirming that peace ''rests on a two-state solution''.',1);
INSERT INTO "position" VALUES(74,'sharon-claydon-newcastle','economic_nationalism','Speaking on the Future Made in Australia legislation, Claydon said ''we want Australians in secure jobs and we want Australians building things here'' and that ''a future made in Australia means a future made in Newcastle'', stating the Government is ''not interested in just simply shipping things overseas and then importing them back as more expensive finished products''.',1);
INSERT INTO "position" VALUES(75,'simon-kennedy-cook','immigration','In his 2024 first speech, Kennedy criticised high migration levels, saying "record migration is being used to paper over the weakness of the Australian economy" and that population was growing faster than at any time since 1952, outpacing housing supply. He called to "match migration levels with the ability of the building industry to supply new homes," while arguing "the one area where we do need to dramatically increase migration is migrants with skills in construction related industries."',1);
INSERT INTO "position" VALUES(76,'sophie-scamps-mackellar','foreign_policy','In February 2024 Scamps called for the Australian government to restore UNRWA funding and for an immediate ceasefire in the Gaza war. In October 2024 she voted for a resolution condemning the Hamas-led attack on Israel and supported a Greens amendment condemning ''war crimes perpetrated by the State of Israel''. She also targeted an AUKUS adviser appointment in her 2023 ''Ending Jobs for Mates Bill'' and in February 2023 called for federal recognition of the Armenian, Assyrian and Greek genocides.',1);
INSERT INTO "position" VALUES(77,'susan-templeman-macquarie','immigration','In February 2019, Templeman supported the ''medevac'' bill enabling medical transfers of refugees from offshore processing facilities, saying the amendments "are about making sure sick and vulnerable people in regional processing facilities can receive the medical care they need, without compromising existing border protection arrangements," and accusing the Coalition of "misrepresenting ALP policy on this issue."',1);
INSERT INTO "position" VALUES(78,'susan-templeman-macquarie','foreign_policy','Speaking at Labor''s national conference (18 August 2023), Templeman supported prioritising recognition of Palestine, saying ''the extreme right-wing policies of the Netanyahu government that speed up the expansion of settlements are a serious impediment to the two-state solution that we are all committed to'', and backed ''the call our platform makes for the recognition of Palestine as an issue of priority''.',1);
INSERT INTO "position" VALUES(79,'sussan-ley-farrer','immigration','As Opposition Leader, Ley stated that "strong borders keep us safe, they also allow us to be generous and compassionate to those fleeing conflict."',1);
INSERT INTO "position" VALUES(80,'sussan-ley-farrer','foreign_policy','Ley publicly supported admission of the State of Palestine to the UN in 2011 but said her view changed after a 2022 visit to Israel; she reaffirmed the Coalition''s commitment to West Jerusalem as Israel''s capital. As Opposition Leader in August 2025 she stated she would reverse the Albanese government''s decision to recognise a Palestinian state should she win office, saying recognition must come only at the end of a genuine two-state process.',1);
INSERT INTO "position" VALUES(81,'sussan-ley-farrer','economic_nationalism','As a Coalition minister, Ley promoted the Coalition Government''s foreign investment regime to improve scrutiny and transparency around foreign ownership of Australia''s agricultural production, noting the screening threshold for foreign purchases of agricultural land by private investors had been reduced to $15 million, and said sales of critical infrastructure to foreign investors must be properly scrutinised so that foreign investment is not contrary to the national interest.',1);
INSERT INTO "position" VALUES(82,'sussan-ley-farrer','citizenship_eligibility','Ley was born overseas (in Kano, Nigeria, to English parents) and has publicly stated that she renounced her other citizenship before sitting in the Australian Parliament, taking a few months to do so in order to satisfy section 44(i) eligibility.',1);
INSERT INTO "position" VALUES(83,'tanya-plibersek-sydney','faith','Plibersek has said she was raised Catholic. In her 2022 Archbishop Daniel Mannix Lecture she said ''I was raised firmly within the arms of the Catholic Church,'' describing her first communion, confirmation, Sunday mass and weekly confession, and adding that ''growing up Catholic has influenced my politics.'' She does not state whether she currently practises.',1);
INSERT INTO "position" VALUES(84,'tanya-plibersek-sydney','immigration','In a 2003 workshop talk on multiculturalism, Plibersek argued that "the first and biggest lie is the one that suggests asylum seekers are a threat to this nation," noting Australia accepts a small number of refugees by world standards. She criticised Australia for choosing "the most expensive system for dealing with refugees - locking them up - or even more expensive, putting them on Nauru or Manus Island," and is a vocal advocate for multiculturalism.',1);
INSERT INTO "position" VALUES(85,'tanya-plibersek-sydney','foreign_policy','In 2002 Plibersek described Israel as ''a rogue state'' and Ariel Sharon as a ''war criminal'', though she later developed friendly relations with the Jewish community and visited Israel and Palestine in 2014. As Shadow Foreign Minister in 2016 she advocated redrawing Australia''s maritime border with East Timor. She opposed the 2003 invasion of Iraq and presented a letter signed by 43 Labor MPs opposing invasion without UN approval, and has opposed foreign aid cuts.',1);
INSERT INTO "position" VALUES(86,'tony-burke-watson','faith','Burke was raised Catholic; his Wikipedia article states he ''was raised in a Catholic family of Irish descent.'' The source does not characterise his current practice.',1);
INSERT INTO "position" VALUES(87,'tony-burke-watson','immigration','As Minister for Home Affairs and Immigration, Burke has defended immigration and multiculturalism, saying "Without immigration, we would be a very different country" and "Modern Australia and multicultural Australia are the same thing," and that "what matters is who you are, not where you''re from." He has also said "there is no place in our country for people who seek to divide and undermine our social cohesion," and rejected the Coalition''s proposed values-based screening of migrants.',1);
INSERT INTO "position" VALUES(88,'tony-burke-watson','foreign_policy','Responding to Israeli PM Netanyahu (20 August 2025, ABC Radio National), Home Affairs Minister Burke said ''strength is not measured by how many people you can blow up or how many children you can leave hungry'', defended the Albanese government''s recognition of Palestinian statehood as a principled decision made after consulting Netanyahu, and stated ''what is happening in Gaza is beyond belief''.',1);
INSERT INTO "position" VALUES(89,'zali-steggall-warringah','foreign_policy','In August 2024 Steggall accused Liberal leader Peter Dutton of racism over his support for prohibiting Gazans from obtaining Australian visas amid the Gaza war.',1);
INSERT INTO "position" VALUES(90,'zali-steggall-warringah','economic_nationalism','Speaking on the National Reconstruction Fund Corporation Bill, Steggall said ''it''s incredibly important that the National Reconstruction Fund be used to support emerging technologies and key manufacturing sectors—not to prop up mature technologies, such as fossil fuel extraction''.',1);
INSERT INTO "position" VALUES(91,'luke-john-gosling-solomon','foreign_policy','In his Lowy Institute paper ''Deterring at a distance: The strategic logic of AUKUS'' (24 June 2024), Gosling argued that ''China''s military build-up is the largest and most ambitious of any country since the end of the Second World War'', that nuclear-powered submarines ''are optimal deterrence machines'' and a ''goldilocks long-distance capability'', and defended AUKUS as giving Australia ''added strategic weight to deter a more powerful adversary''.',1);
INSERT INTO "position" VALUES(92,'marion-scrymgour-lingiari','immigration','Speaking as Labor candidate for Lingiari, Scrymgour said she wants ''to be able to put the compassion back into politics, especially when we talk about important issues like Indigenous affairs and immigration.''',1);
INSERT INTO "position" VALUES(93,'ali-france-dickson','immigration','In November 2016, before entering Parliament, Ali France publicly urged then-PM Malcolm Turnbull to reconsider a proposed lifetime ban on asylum seekers who arrived by boat, writing an open letter and citing her surgeon, an Iraqi refugee who came to Australia by boat; she said genuine refugees ''should be given a chance.'' Wikipedia characterises her as a critic of offshore detention. Her July 2025 first speech did not address immigration.',1);
INSERT INTO "position" VALUES(94,'andrew-wallace-fisher','faith','Wallace is described as a practising Catholic; his Wikipedia article states he and his wife Leonie are ''Practising Catholics,'' and that at age 19 he entered a Pallottine monastery in Victoria intending to become a priest before being asked to leave within a year. His initial opposition to same-sex marriage was on religious grounds.',1);
INSERT INTO "position" VALUES(95,'andrew-wallace-fisher','foreign_policy','Wallace is a strong supporter of Israel and serves as Oceania Chair of the Israel Allies Foundation Caucus; he supports Israel''s military response to Hamas after the 2023 attack and has urged action against antisemitism in Australia. He urged Australia to provide military support to Ukraine and, as Speaker, arranged for President Zelensky to address Parliament (31 March 2022). He has argued Iran''s Revolutionary Guard Corps must be kept "weak, broke and totally under control" and sought to minimise Chinese access to sensitive Australian military sites.',1);
INSERT INTO "position" VALUES(96,'andrew-willcox-dawson','immigration','Willcox backs the Coalition''s values-based migration plan, saying "Since Labor took office, the migration program has lacked direction: numbers have soared while standards have plummeted" and that "Living in Australia is a privilege, not a right: those who come here must respect our laws, share our values, and contribute to our nation." He supports reducing immigration numbers, raising standards, and making the Australian Values Statement binding for all visa holders.',1);
INSERT INTO "position" VALUES(97,'andrew-willcox-dawson','economic_nationalism','As Shadow Assistant Minister for Manufacturing and Sovereign Capability, Willcox said it is vital to drive the manufacturing industry forward, become more self-reliant and strengthen Australia''s ability to ''stand on our own two feet as a nation'', and that he would fight for policies that boost innovation, create long-term employment and restore confidence in Australia''s industry.',1);
INSERT INTO "position" VALUES(98,'angie-bell-moncrieff','foreign_policy','In an August 2025 interview, Bell criticised the Albanese Government''s move to recognise Palestine, saying the Prime Minister had "decided to put the cart before the horse, before a proper peace process." She said she wants to see the war end, the hostages returned, and a proper peace process before recognition.',1);
INSERT INTO "position" VALUES(99,'angie-bell-moncrieff','economic_nationalism','In a 2023 speech on the National Reconstruction Fund Corporation Bill, Bell said the Coalition''s focus in government had been to modernise manufacturing, with an emphasis on sovereign capability, jobs, medical products and defence. She opposed Labor''s National Reconstruction Fund, arguing manufacturers instead needed action on energy prices and labour shortages.',1);
INSERT INTO "position" VALUES(100,'anika-wells-lilley','immigration','In response to the nationwide anti-immigration ''March for Australia'' rallies of 31 August 2025, Wells condemned them as ''awful scenes'' involving ''known racists,'' saying ''we all have a responsibility to speak up and assure people from migrant communities ... that we stand with them and this isn''t Australia.''',1);
INSERT INTO "position" VALUES(101,'bob-katter-kennedy','faith','Katter is Roman Catholic; his Wikipedia article states ''Katter is Roman Catholic, with his father Bob Sr. and grandfather Carl being Roman Catholic and Maronite Catholic, respectively.''',1);
INSERT INTO "position" VALUES(102,'bob-katter-kennedy','immigration','Bob Katter (KAP) called in February 2024 for Australia''s migrant intake to be ''cut in half'' and the student intake reduced by two-thirds, saying migration preference ''has to come from countries with democracy, egalitarian traditions, rule of law, Christian principles and industrial awards.'' On asylum seekers he advocates turning back boats ''with, of course, fuel and food.'' In January 2026 he reiterated a policy of ''No migration without assimilation.''',1);
INSERT INTO "position" VALUES(103,'bob-katter-kennedy','economic_nationalism','Katter holds protectionist and economic-nationalist views: he supports traditional Country Party statutory marketing for agriculture, opposes privatisation and economic deregulation, and has pioneered protests against imported produce (such as bananas) and championed mandating domestic ethanol fuel content. He resigned from the National Party in 2001 citing its abandonment of rural protectionist principles.',1);
INSERT INTO "position" VALUES(104,'david-batt-hinkler','faith','David Batt explicitly identifies as Catholic, describing his Catholic faith journey in his first parliamentary speech: his mother took him to church at St Mary''s which ''formed the cornerstone in my faith journey'', he returned to regular Sunday mass at Bundaberg''s Holy Rosary about ten years ago, and remains rostered to clean the church.',1);
INSERT INTO "position" VALUES(105,'david-batt-hinkler','immigration','Batt promotes the Coalition''s Australian Values Migration Plan, stating "Since Labor came to power, Australia''s migration program has been in chaos. Numbers have been too high, and standards have been too low," and "To protect our way of life and restore Australians'' standard of living, we must reduce immigration numbers and lift migration standards." He supports a values-based migration system that prioritises the Australian Values Statement in assessing permanent visa applications.',1);
INSERT INTO "position" VALUES(106,'david-littleproud-maranoa','economic_nationalism','Littleproud called on the Treasurer to revise parts of the Australia-US free trade agreement that allow US companies to buy Australian farming ventures worth up to $1.46 billion without Foreign Investment Review Board approval, a threshold not applied to other foreign investors. He said the current rules let cashed-up foreign buyers outcompete Australian farming families for farmland.',1);
INSERT INTO "position" VALUES(107,'elizabeth-watson-brown-ryan','immigration','No personal position was found in fetched sources. Per the Australian Greens platform (the party she represents): seeking asylum is treated as a human right, with commitments to end offshore processing, oppose indefinite/arbitrary detention, increase the humanitarian intake, and run a migration program prioritising family reunion and humanitarian programs.',1);
INSERT INTO "position" VALUES(108,'elizabeth-watson-brown-ryan','foreign_policy','Per Australian Greens platform: the party (of which Watson-Brown is the MP for Ryan) calls to cancel the AUKUS agreement and renegotiate ANZUS to reduce reliance on the United States, to stop all Australian military exports to Israel, and to end the occupation of Palestinian territories occupied since 1967.',1);
INSERT INTO "position" VALUES(109,'elizabeth-watson-brown-ryan','economic_nationalism','In her first speech, Watson-Brown advocated a planned phase-out of coal and gas in favour of renewables and green manufacturing, and argued that public infrastructure should be in public hands, criticising the development and ownership of public infrastructure by private corporations.',1);
INSERT INTO "position" VALUES(110,'garth-hamilton-groom','immigration','Hamilton publicly rebuked One Nation''s Pauline Hanson over her call for a "monocultural" Australia, saying her "appeal to a monoculture had more in common with sharia law or North Korea than it did with western liberal democracies." He defended Australian multiculturalism against One Nation''s calls to end multiculturalism and cut migration.',1);
INSERT INTO "position" VALUES(111,'henry-pike-bowman','faith','Henry Pike is described as a Christian; the Christian Business Network''s Redlands page promoting his appearance states he ''shares his experience as a Christian in the Political world''. This is a third-party event-host description rather than a self-statement, and no denomination is specified.',1);
INSERT INTO "position" VALUES(112,'jim-chalmers-rankin','faith','Jim Chalmers identifies as a Catholic, though described as more ''tribal than Bible''; his three children were baptised in the same church as himself, indicating his Catholicism is more cultural/family tradition than devotional.',1);
INSERT INTO "position" VALUES(113,'jim-chalmers-rankin','immigration','As Treasurer, Chalmers defended the government''s migration management, stating migration was ''already down 45 per cent since its peak,'' and the government emphasises housing supply over migration cuts; per Labor platform, Labor caps permanent migration at 185,000 and targets net overseas migration of around 225,000.',1);
INSERT INTO "position" VALUES(114,'jim-chalmers-rankin','foreign_policy','On 31 July 2025, Treasurer Jim Chalmers said Australian recognition of a Palestinian state is a matter of "when, not if," framing Palestinian statehood as an important step toward a two-state solution and an end to the "cycle of violence," while conditioning support on Hamas having no role in future Palestinian leadership.',1);
INSERT INTO "position" VALUES(115,'jim-chalmers-rankin','economic_nationalism','As Treasurer, Chalmers announced the Future Made in Australia plan, framing it around building domestic sovereign capability to protect national security and economic resilience. He identified priority sectors critical to resilience and vulnerable to supply disruptions, backed value-adding to critical minerals, and announced support for battery and solar panel supply chains and sovereign defence industrial priorities.',1);
INSERT INTO "position" VALUES(116,'kara-cook-bonner','immigration','Cook condemned the anti-immigration "March for Australia" rallies, saying they "were not patriotic gatherings; they were parades of division, fear and prejudice" and that "those who preach division tear at the social fabric of our nation." She stated Australia "was at its best when it was inclusive, diverse and welcoming."',1);
INSERT INTO "position" VALUES(117,'leon-rebello-mcpherson','immigration','In his first speech, Rebello argued Australia "face[s] a population surge fuelled by a reckless immigration profile, one that no longer reflects the careful planning or national interest," and that "the desire to come to Australia, while admirable, should not be the sole qualification. It is the willingness to contribute to Australia that must be the true test." He warned poorly managed migration risks "rising social tensions, buckling infrastructure, divided communities," while describing a multicultural society as "a strength, not a strain" when migration is well managed.',1);
INSERT INTO "position" VALUES(118,'leon-rebello-mcpherson','foreign_policy','In his maiden speech on 30 July 2025, Rebello called for Australia to invest in "a strong, sovereign defence capability," to seize the strategic and diplomatic advantages of trusted allies and the Commonwealth, and to diversify import and export markets "so we don''t rely on any one country" and avoid being "held ransom by adversaries."',1);
INSERT INTO "position" VALUES(119,'leon-rebello-mcpherson','economic_nationalism','In his first speech, Rebello said Australia should support the expansion of its domestic manufacturing sector in line with its strategic and comparative advantage, and stated he is a firm believer in diversifying import and export markets so the country does not rely on any single country. He also called for an environment that welcomes foreign investment in the national interest.',1);
INSERT INTO "position" VALUES(120,'llew-o-brien-wide-bay','economic_nationalism','O''Brien said sustainable, world-class timber is produced in Wide Bay and that he is committed to ensuring the local timber industry remains viable, thrives and creates more jobs into the future, citing Hyne Timber as one of the region''s major employers and government investment in the industry.',1);
INSERT INTO "position" VALUES(121,'llew-o-brien-wide-bay','citizenship_eligibility','After the Parliament of Canada passed Bill C-3 (in force 15 December 2025), O''Brien acquired Canadian citizenship by descent through his Canadian-born father and grandfather; on 6 February 2026 he announced his intention to renounce that Canadian citizenship because section 44(i) of the Constitution prohibits parliamentarians from holding dual citizenship.',1);
INSERT INTO "position" VALUES(122,'milton-dick-oxley','faith','Milton Dick is Anglican; he has maintained the Anglican faith of his childhood and has opposed moves to remove the Lord''s Prayer from parliamentary proceedings.',1);
INSERT INTO "position" VALUES(123,'milton-dick-oxley','immigration','In his first speech to Parliament (12 October 2016), Dick described Labor as "proudly the party of multiculturalism" and said "multiculturalism is not just a great social strength of our nation but increasingly a great economic strength." Referencing migrants and refugees, he said they "proudly call Australia home and are entitled to feel welcome—not targeted or demonised" and pledged he "will never judge anyone by their race or religion."',1);
INSERT INTO "position" VALUES(124,'milton-dick-oxley','foreign_policy','Dick has been described by the Australian Jewish News as a strong supporter of Israel; after a 2017 sponsored visit to Israel he characterised terms such as "settlements, occupation, apartheid and the wall" as "easy catchphrases and cliches" that often lacked counterbalance.',1);
INSERT INTO "position" VALUES(125,'phillip-thompson-herbert','immigration','Thompson supports the Coalition''s plan to reduce migration, saying "Right now, the system is out of control. Numbers are too high and standards are too low," and "To protect our way of life and restore living standards, we must reduce migration and raise the bar." He argues that Australians should not be competing with foreigners for housing and that "Australians must come first."',1);
INSERT INTO "position" VALUES(126,'phillip-thompson-herbert','foreign_policy','In his maiden speech on 4 July 2019, Thompson, a former infantry soldier, said that as a member of the Joint Standing Committee on Foreign Affairs, Defence and Trade he would spotlight veterans'' issues, and he expressed support for the Australia-Singapore Military Training Initiative as creating jobs and economic growth.',1);
INSERT INTO "position" VALUES(127,'scott-buchholz-wright','economic_nationalism','In his maiden speech, Buchholz said he would fight to get farmers a better price at the farm gate and emphasised agricultural self-reliance, warning that ''without these people we become captive to overseas producers and overseas markets; without these people we lose our dignity and our sovereignty.''',1);
INSERT INTO "position" VALUES(128,'shayne-neumann-blair','faith','Shayne Neumann is described as a Christian; he and his wife attend their local Baptist Church in Ipswich.',1);
INSERT INTO "position" VALUES(129,'ted-o-brien-fairfax','foreign_policy','In September 2020, O''Brien called for Australia to negotiate a free-trade agreement with Taiwan, citing Australia''s existing agreements with New Zealand and Singapore. He has also publicly linked the AUKUS agreement to the case for adopting nuclear technology, stating that adopting nuclear-propelled submarines under AUKUS takes Australia''s engagement with nuclear technology to a new level.',1);
INSERT INTO "position" VALUES(130,'terry-young-longman','economic_nationalism','In his first speech (31 July 2019), Young emphasised local small business and local employment, describing Longman as made up of over 12,000 small businesses and praising local operators as "hardworking locals, employing locals and spending their money locally." He said "the onset of online businesses and multinationals has made the life of the local business owner that much more difficult" and pledged to break Longman''s tradition of higher-than-average unemployment.',1);
INSERT INTO "position" VALUES(131,'amanda-rishworth-kingston','economic_nationalism','On her campaign page promoting "A Future Made in Australia," Rishworth''s stated position is that she "wants to see more manufacturing and jobs in the South," linked to government infrastructure projects in South Australia she says will create local employment.',1);
INSERT INTO "position" VALUES(132,'matt-burnell-spence','economic_nationalism','Burnell''s official member profile states he "wants the Northern suburbs of Adelaide to be the hub of manufacturing once again, securing jobs for our future and generations to come," and lists fighting for "good, secure jobs" among his priorities.',1);
INSERT INTO "position" VALUES(133,'rebekha-sharkie-mayo','faith','Rebekha Sharkie has publicly self-identified as a Christian, stating "As a Christian, I support protections against discrimination on the grounds of religion" in 2022; no denomination is specified.',1);
INSERT INTO "position" VALUES(134,'rebekha-sharkie-mayo','immigration','On her ''Where I Stand'' page Sharkie states that ''Our immigration intake should be matched to our capacity to appropriately accommodate new migrants and balanced with social and economic benefits,'' arguing immigration policy should be considered holistically alongside capacity in healthcare, housing and transport, with regular reviews of intake numbers.',1);
INSERT INTO "position" VALUES(135,'rebekha-sharkie-mayo','economic_nationalism','Under her "Primary Production" policy, Sharkie states that as SA''s food bowl, Mayo requires "preservation of Australia''s farmland and support for local grown produce and local manufacture."',1);
INSERT INTO "position" VALUES(136,'rebekha-sharkie-mayo','citizenship_eligibility','Sharkie was born in England and held British citizenship by birth; she had not completed renunciation before nominating for the 2016 election, so following the High Court''s Gallagher ruling she resigned in May 2018 and recontested. She was re-elected at the Mayo by-election on 28 July 2018 after her British citizenship was renounced, resolving her section 44(i) eligibility.',1);
INSERT INTO "position" VALUES(137,'steve-georganas-adelaide','immigration','In his maiden speech, Georganas, the son of Greek migrants, spoke positively about immigration''s contribution to Australia, stating ''There is no doubt that Australia''s migrants have made this country a better place'' and that the hopes and dreams of migrants ''have given this country an optimism, resilience, diversity and vitality that must be valued and nurtured.'' He noted his electorate''s many nationalities and languages.',1);
INSERT INTO "position" VALUES(138,'steve-georganas-adelaide','economic_nationalism','Georganas''s official member profile describes him as "a strong advocate for local jobs, fighting the offshoring of call centre work," and states he "supported a shift to onshore slaughter and meat processing to create more jobs."',1);
INSERT INTO "position" VALUES(139,'tom-venning-grey','economic_nationalism','On his official website, Venning states "Primary industries are the backbone of our economy. We provide the nation with minerals, food, fibre and energy," and says "As an economist and a 5th generation farmer, I know the importance of protecting these industries from inequitable taxes and unfair climate policy." He cites the farmer-paid biosecurity levy and the ban on live sheep exports as attacks on rural livelihoods.',1);
INSERT INTO "position" VALUES(140,'tony-pasin-barker','immigration','In his 2013 first speech, Pasin, the son of Italian immigrants, said "I honour the rich contribution that immigrants have made to my home state of South Australia and the nation," and added he was "proud to be part of a government that is working to ensure that once again those who come to our great nation ... do so in a safe and orderly manner, respectful of proper processes."',1);
INSERT INTO "position" VALUES(141,'tony-zappia-makin','foreign_policy','Zappia has stated in Parliament that he acknowledges the Palestinian people''s right to self-determination, including the need to recognise a sovereign and independent State of Palestine, and the need to address the root causes of the conflict including dismantling Israel''s ''system of apartheid against all Palestinians.'' In an October 2023 speech he said ''the killing of innocent Palestinians in Gaza must also stop'' and that ''Israel must show restraint and respect for international law,'' and he has called for a permanent two-state resolution.',1);
INSERT INTO "position" VALUES(142,'tony-zappia-makin','citizenship_eligibility','Zappia was born in Italy in 1952 and naturalised as an Australian citizen in 1958. He stated he ceased to be an Italian citizen automatically upon acquiring Australian citizenship in 1958 (Italy then stripping citizenship from those naturalising elsewhere), a position he said the Italian Consul confirmed by letter dated July 2004, supporting his section 44(i) eligibility.',1);
INSERT INTO "position" VALUES(143,'andrew-wilkie-clark','immigration','Wilkie considers Australia''s bipartisan policy of mandatory detention ''immoral and illegal under numerous international agreements.'' His Ending Indefinite and Arbitrary Immigration Detention Bill 2022 would effectively abolish offshore detention and move asylum seekers and refugees into the community with access to housing, support and the right to work. He cites detention costs of about $360,000 per person per year versus about $4,429 for someone living in the community, and condemns Australia''s offshore processing on Nauru and Manus.',1);
INSERT INTO "position" VALUES(144,'andrew-wilkie-clark','foreign_policy','Wilkie advocates a more independent Australian foreign policy underpinned by adherence to international law, supports increased overseas development assistance, and calls for Russian withdrawal from Ukraine. On Israel/Palestine he states Israel has been engaged in a ''decades-long, systematic campaign of occupation and oppression in Palestine'' and that ''peace can only come with formal recognition of Palestine by all parties and a two-state solution,'' calling for an end to Israel''s campaign in Gaza and the West Bank. He argues Australia would be better served by a more independent security posture ''not beholden to'' partnerships like ANZUS, the Quad and AUKUS.',1);
INSERT INTO "position" VALUES(145,'andrew-wilkie-clark','economic_nationalism','On his "Where I stand" page, Wilkie states "Foreign investment needs much better regulation. Yes, Australia needs it, but only on our terms and only when it''s genuinely in the national interest." He adds that "Assessment criteria must always include a national security test, and strategic assets including energy, transport infrastructure and broadacre prime agricultural land must never be sold or leased."',1);
INSERT INTO "position" VALUES(146,'anne-urquhart-braddon','economic_nationalism','Urquhart''s official member profile lists among her priorities "supporting well-paid jobs, strong local manufacturing," access to childcare and aged care, and education.',1);
INSERT INTO "position" VALUES(147,'julie-collins-franklin','economic_nationalism','As Minister for Agriculture, Fisheries and Forestry, Collins said the government is looking at "how do we do more manufacturing and more value-adding in terms of our supply chain, but importantly, of our raw product here in Australia," referencing the National Reconstruction Fund and supply-chain resilience.',1);
INSERT INTO "position" VALUES(148,'andrew-giles-scullin','immigration','As Immigration Minister, Giles issued Ministerial Direction 99 (2023), which tightened deportation criteria by weighting a non-citizen''s community ties and time in Australia. After criticism, on 7 June 2024 he replaced it with Ministerial Direction 110, which he said makes ''community protection'' and ''the safety of the Australian community'' the highest priority in visa cancellation decisions; he stated he had cancelled 40 visas ''in the national interest'' that week. As Shadow Minister he led Labor''s campaign against privatising Australia''s visa system and established a Multicultural Caucus Committee.',1);
INSERT INTO "position" VALUES(149,'andrew-giles-scullin','citizenship_eligibility','Giles was a British citizen by descent through his UK-born mother. He renounced his British citizenship before standing for parliament in 2013, resolving his section 44(i) eligibility.',1);
INSERT INTO "position" VALUES(150,'anne-webster-mallee','faith','In her maiden speech to the House of Representatives, Anne Webster explicitly identified as a Christian, stating: "My upbringing has provided the foundation of my worldview as a Christian."',1);
INSERT INTO "position" VALUES(151,'anne-webster-mallee','immigration','Webster has stated ''Albanese Labor has brought in 1.4 million people in just 3 1/2 years,'' arguing excess immigration has added pressure to housing, infrastructure and services and that Labor has ''flooded'' the economy with population growth driven by immigration. She endorses the Coalition''s tougher immigration stance, citing measures such as a binding Australian Values Statement visa condition, restoring Temporary Protection Visas, a Safe Country List, and enhanced visa screening.',1);
INSERT INTO "position" VALUES(152,'anne-webster-mallee','economic_nationalism','Advocating local urea production, Webster said "in today''s global climate, we need to be on the front foot with sovereign manufacturing capabilities" and "It''s time for us to move away from foreign dependence on these and other essential products, and to become more self-reliant." She described investing in domestic urea production on "Aussie soil" as helping secure reliable fertiliser supply for growers.',1);
INSERT INTO "position" VALUES(153,'basem-abdo-calwell','faith','Wikipedia explicitly states that Basem Abdo is a Muslim ("He married Natascha and is a Muslim.").',1);
INSERT INTO "position" VALUES(154,'basem-abdo-calwell','foreign_policy','Abdo, the first person of Palestinian Arab descent in the Australian Parliament, has stated ''My position on this is very clear. I support the recognition of a Palestinian state,'' framing it as the right to self-determination rather than symbolism. Drawing on a 2011 visit to the West Bank, he described being confronted by ''how overarching the occupation is, how it impacts the daily lives in all aspects for the Palestinian people there,'' and said party-room discussions on timing would be held in caucus.',1);
INSERT INTO "position" VALUES(155,'basem-abdo-calwell','economic_nationalism','Abdo''s official member profile states that "Calwell, once a vibrant hub for manufacturing, has the potential to lead Australia''s resurgence in this sector," that he "wants to see secure, well-paying jobs back in his community," and that "Australia''s capacity to make things here starts by investing in the local workforce, fostering skills development, and providing strong support for industry growth."',1);
INSERT INTO "position" VALUES(156,'carina-garland-chisholm','economic_nationalism','Garland''s profile states she "is passionate about bringing manufacturing back to Australia and is fighting for opportunities for local manufacturers," wants "a Future Made in Australia, where our nation capitalises on our natural resources to become a renewable energy superpower," and is working to build "secure local jobs."',1);
INSERT INTO "position" VALUES(157,'cassandra-fernando-holt','immigration','Fernando, who came to Australia from Sri Lanka in 1999 and sits on the House Standing Committee for Migration, said in a July 2023 interview that "Labor is the party that has ... promoted multiculturalism and ensured a ''fair go'' for all Australians" and described Australia as "a diverse, inclusive and accepting country." On Sri Lankan boat arrivals she said the Australian Government "has full faith in their Sri Lankan counterparts when working on challenges of mutual interest, such as people smuggling."',1);
INSERT INTO "position" VALUES(158,'clare-o-neil-hotham','immigration','As Minister for Home Affairs, in a National Press Club address on 27 April 2023 O''Neil described Australia''s migration system as ''broken'' after ''a decade of genuinely breathtaking neglect,'' saying it ''is failing our businesses, it is failing migrants themselves. And most importantly, it is failing Australians.'' She commissioned a review of the migration system and indicated her proposed reforms would likely produce ''a slightly smaller migration program over time.''',1);
INSERT INTO "position" VALUES(159,'clare-o-neil-hotham','economic_nationalism','In her 2013 first speech, O''Neil said government "should not be building great tariff walls or controlling the big macroeconomic levers," arguing instead that government supports business competitiveness through a skilled population, world-class infrastructure, safe cities and a culture of invention. She referenced modern manufacturing (the Corning NBN-fibre factory) as "made possible by a clever and adaptable workforce."',1);
INSERT INTO "position" VALUES(160,'dan-tehan-wannon','immigration','As Shadow Minister for Immigration and Citizenship, Tehan has criticised Labor over migration levels, stating ''this Labor Government is pursuing Rudd''s agenda by stealth'' and ''Labor is delivering a big Australia without being upfront with the Australian people.'' He has argued the government lacks a migration plan addressing impacts on rents, infrastructure and congestion, and raised concern about the whereabouts of tens of thousands of unsuccessful asylum-seeker applicants.',1);
INSERT INTO "position" VALUES(161,'dan-tehan-wannon','economic_nationalism','As Minister for Trade, Tourism and Investment, Tehan took over and concluded the Australia-United Kingdom Free Trade Agreement, having earlier been involved in negotiating the Australia-United States Free Trade Agreement in 2004. His Wikipedia biography records his role advancing trade liberalisation agreements.',1);
INSERT INTO "position" VALUES(162,'daniel-mulino-fraser','faith','Daniel Mulino describes himself as a "lapsed Catholic" (i.e. a Catholic background but non-practising).',1);
INSERT INTO "position" VALUES(163,'daniel-mulino-fraser','immigration','In his maiden speech, Mulino, who was born in Italy and migrated to Australia with his family in 1970, praised Australia''s multicultural tradition, saying ''Australia is not unique in having a large foreign-born population, but I don''t believe that any other country is better at knitting together disparate communities.'' He highlighted the diversity of his electorate of Fraser and framed migrants as central contributors to the community.',1);
INSERT INTO "position" VALUES(164,'daniel-mulino-fraser','citizenship_eligibility','Mulino was born in Brindisi, Italy, and stated in his 2019 maiden speech that he had renounced his (Italian) citizenship "long ago," addressing his eligibility to sit under section 44(i).',1);
INSERT INTO "position" VALUES(165,'darren-chester-gippsland','economic_nationalism','Announcing a $3 million grant to DefendTex in Gippsland, Chester supported domestically producing commercial rocket boosters to fill a gap where there are "no commercially available, domestically manufactured rocket boosters for launch in Australia," saying this would "allow for responsive sovereign space launch to occur" and grow local jobs in Gippsland.',1);
INSERT INTO "position" VALUES(166,'ged-kearney-cooper','immigration','In her first speech (May 2018), Kearney advocated for a ''humane refugee policy'' and called for an end to offshore detention of asylum seekers, describing indefinite offshore immigration detention as ''shameful.'' She has supported medevac legislation allowing detained refugees to access medical care.',1);
INSERT INTO "position" VALUES(167,'ged-kearney-cooper','foreign_policy','In a Federation Chamber speech, Kearney condemned Hamas''s actions as "evil" while stating "the answer to the senseless killings of Hamas cannot be the collective punishment of the Palestinian people," calling for Israel "to operate by the rules of international law" and referencing the UN call for "a suspension of hostilities... without any delay." She affirmed the "legitimate aspirations for the Palestinian people" and support for "a just and enduring peace, a two-state solution."',1);
INSERT INTO "position" VALUES(168,'ged-kearney-cooper','economic_nationalism','In her first speech, Kearney argued that money from corporate tax cuts could instead "build skills, support innovative projects and target and fund growth strategies for high-wage, high-skill industries, like niche manufacturing, science and technology, logistics, education, health and social services."',1);
INSERT INTO "position" VALUES(169,'helen-haines-indi','immigration','Haines criticised the Coalition''s immigration policy (April 2026) as ''disingenuous at best, divisive at worst,'' arguing humanitarian obligations to refugees and asylum seekers are ''separate to skilled and temporary migration'' and that existing laws already require migrants to commit to Australian values and pass language tests. She celebrated Australia''s diversity and opposed ''singling people out based on where they come from, including people fleeing the war in Gaza.''',1);
INSERT INTO "position" VALUES(170,'helen-haines-indi','economic_nationalism','Launching her plan for community-owned renewable energy in regional Australia, Haines advocated that "everyday people develop, build or benefit from an energy project," saying that doing renewables right would mean "lower bills, stronger energy security, and new job and industries" and a "regional jobs boom" if every school, council, hospital, sporting club and community group could access the benefits.',1);
INSERT INTO "position" VALUES(171,'jason-wood-la-trobe','immigration','Wood chaired the Joint Standing Committee on Migration from 2013 and served as Assistant Minister for Customs, Community Safety and Multicultural Affairs (2019-2022). During 2016-2019 he campaigned prominently on law-and-order issues relating to so-called ''African gangs'', later saying he had ''no regrets'' and rejecting accusations of racism. From 2022 he held shadow responsibility for community safety, migrant services and multicultural affairs.',1);
INSERT INTO "position" VALUES(172,'josh-burns-macnamara','faith','Josh Burns is Jewish. His maternal grandmother came to Australia as a Jewish refugee from Nazi Germany, he was educated at Mt Scopus Memorial College (a Jewish day school) and was active in the Jewish Labour Bund youth movement; he has spoken publicly as a Jewish person and is categorised among Jewish members of the Australian parliament.',1);
INSERT INTO "position" VALUES(173,'josh-burns-macnamara','immigration','Burns has advocated for refugees and asylum seekers, moving a parliamentary motion urging the government to free refugees held in onshore and offshore detention (referenced June 2021). His advocacy is shaped by his family''s history as migrants who fled persecution in Europe.',1);
INSERT INTO "position" VALUES(174,'josh-burns-macnamara','foreign_policy','Burns, a Jewish Labor MP, supports a two-state solution and says he "desperately want[s] to see a peace agreement signed between the Israelis and the Palestinians." Following the 7 October 2023 attack he opposed an immediate ceasefire, arguing it would allow Hamas to regroup, and he opposed the government''s vote in favour of UN General Assembly Resolution ES-10/22 on Gaza. In October 2022 he criticised the Albanese government for revoking Australia''s recognition of Jerusalem as Israel''s capital.',1);
INSERT INTO "position" VALUES(175,'julian-hill-bruce','immigration','Hill has championed Australian multiculturalism and ''the importance of Australia embracing its human diversity.'' He made ''no apology'' for championing reforms to the regulation of international education that were likely to reduce the number of international students granted visas, drawing criticism from the international education industry.',1);
INSERT INTO "position" VALUES(176,'julian-hill-bruce','foreign_policy','In a July 2024 statement, Hill said "Israel''s Knesset vote against a Palestinian State is profoundly disappointing" and that "a two-state solution is the only realistic resolution to decades of violence," describing alternatives (one state) as "fantasies" or (apartheid or genocide) as "horrific." He called the acceleration of illegal West Bank settlements "appalling" and said major countries need to "collectively intervene... to impose consequences on Israel" to stop them.',1);
INSERT INTO "position" VALUES(177,'julian-hill-bruce','economic_nationalism','In a 2023 statement titled "Australia must make more things here," Hill said "We can make more things here. We should make more things here and we must make more things here," warning Australia is "around the lowest for manufacturing self-sufficiency of any developed country in the world" and "too vulnerable to supply shocks" and "to military blockades." He called for urgently boosting "sovereign manufacturing capability" while acknowledging "we can''t make everything here."',1);
INSERT INTO "position" VALUES(178,'kate-thwaites-jagajaga','immigration','In her maiden speech (July 2019), Thwaites supported a ''humane approach to asylum seekers,'' adding ''I believe this can be achieved while maintaining our sovereignty and our borders.'' She has criticised the holding of asylum seekers in hotels as ''unsafe and cruel conditions,'' said ''unnecessary cruelty is a hallmark of this government when it comes to treatment of asylum seekers,'' and criticised refusal to take up New Zealand''s resettlement offers.',1);
INSERT INTO "position" VALUES(179,'kate-thwaites-jagajaga','foreign_policy','In a February 2024 parliamentary speech, Thwaites said she shared "the horror... at the destruction and death that have been occurring in Gaza under Israel''s military action" and expressed devastation at Israel''s planned Rafah ground offensive. She noted "Australia has voted for an immediate humanitarian ceasefire," said any ceasefire "cannot be a one-sided ceasefire" and "will also require Hamas to cease its attacks and to release the Israeli hostages," and said Australia expects Israel to act in accordance with the ICJ ruling.',1);
INSERT INTO "position" VALUES(180,'libby-coker-corangamite','economic_nationalism','In her 2019 first speech, Coker said "We shouldn''t stand idly by and watch high-skilled, well-paid manufacturing and public sector jobs disappear while the market replaces them with low-paid, low-skill insecure work," and called for "sector plans, like the famous Button car and steel plants, for each targeted industry" plus investment in research, technology, start-ups and value-adding industries.',1);
INSERT INTO "position" VALUES(181,'lisa-chesters-bendigo','economic_nationalism','In her 2013 first speech, Chesters highlighted Bendigo manufacturers (Australian Turntables, Industrial Conveying Australia, Keech Casting and Hofmann Engineering) as "world leaders in their fields exporting to countries all over the world," and said it was "ideologically driven policies of governments" rather than red tape that created roadblocks hindering their growth, criticising policies she said blocked Hofmann from expanding into wind energy generation.',1);
INSERT INTO "position" VALUES(182,'mark-dreyfus-isaacs','faith','Mark Dreyfus is Jewish and has spoken of his personal Jewish faith, stating ''the central themes of law and justice in both Jewish religious and secular traditions have great meaning for me and have helped to shape my worldview'' and referring to himself observing the holiday of Chanukah. Three of his great-grandparents perished in the Holocaust.',1);
INSERT INTO "position" VALUES(183,'mark-dreyfus-isaacs','immigration','As Attorney-General, Dreyfus promoted the Albanese Government''s reforms to the refugee protection system (October 2023), stating Australians are ''rightly proud of our country''s generous refugee program'' and that reforms would give ''a fair go to genuine asylum seekers'' while breaking ''the business model of people who seek to exploit the system'' and not allowing ''people traffickers and other bad actors to exploit vulnerable migrants.''',1);
INSERT INTO "position" VALUES(184,'mark-dreyfus-isaacs','foreign_policy','In a parliamentary motion condemning Hamas, Dreyfus said "Australia unambiguously supports the right of Israel to defend itself" and that "the Australian Government stands as one with Israel and the people of Israel against Hamas," while also stating the government "will continue to support the legitimate rights and aspirations of the Palestinian people" and endorsing "a just and enduring two state solution – in which Israel and a future Palestinian state coexist in peace and security." He described Hamas as having "no interest in making peace with Israel."',1);
INSERT INTO "position" VALUES(185,'mary-aldred-monash','economic_nationalism','As candidate/Member for Monash, Aldred said "We need to protect our industries. If the timber industry dies, that will have a devastating impact on local schools, on local businesses, on local community spirit," and pledged to "look after small businesses" and to "fight very hard for all our farmers to continue to have the right to farming."',1);
INSERT INTO "position" VALUES(186,'monique-ryan-kooyong','immigration','Ryan states that ''having clearly-defined, realistic, sustainable, and transparent immigration policies doesn''t have to erode our humanity,'' and says she has ''consistently voted against the Albanese Government''s punitive laws criminalising asylum seekers and punishing those seeking refuge in this country,'' describing such laws as contravening human rights obligations.',1);
INSERT INTO "position" VALUES(187,'monique-ryan-kooyong','foreign_policy','Per her Wikipedia article, Ryan voted for a parliamentary resolution condemning Hamas''s October 2023 attack on Israel and voted against a Greens amendment that would also have condemned "war crimes perpetrated by the State of Israel." She called for a "humanitarian pause" in the conflict, describing the "human suffering in Gaza" as "intolerable."',1);
INSERT INTO "position" VALUES(188,'peter-khalil-wills','faith','Peter Khalil is a Coptic Christian, born in Melbourne to Egyptian Coptic parents, and became the first Coptic Christian elected to the Australian Federal Parliament.',1);
INSERT INTO "position" VALUES(189,'peter-khalil-wills','immigration','Khalil advocates a welcoming posture toward immigrants, crediting his parents'' 1970 migration from Egypt, and stated migrants commit to Australia because of ''our values of freedom, of equality of opportunity, of a fair go.'' During the COVID-19 pandemic (2020) he called for releasing detained refugees and asylum seekers who had cleared security checks, arguing it would protect their health and help slow the spread of the virus.',1);
INSERT INTO "position" VALUES(190,'peter-khalil-wills','foreign_policy','Per his Wikipedia article, Khalil "is a strong supporter of the Western alliance" and a "very strong supporter of the US alliance," and on China co-authored a statement that "Bowing to Beijing would be the modern equivalent of the Munich Agreement," advocating "containment of Chinese totalitarian threats to democratic nations." He serves as Assistant Minister for Defence.',1);
INSERT INTO "position" VALUES(191,'richard-marles-corio','immigration','Marles supports turning back asylum-seeker boats and a Pacific Solution-style offshore resettlement of refugees, and as Shadow Minister for Immigration and Border Protection (2013-2016) backed maintaining offshore processing to deter people smuggling. He also supported the Australian War Memorial commemorating Operation Sovereign Borders navy personnel.',1);
INSERT INTO "position" VALUES(192,'richard-marles-corio','foreign_policy','As Defence Minister, Marles is a strong supporter of AUKUS, saying it "is going to really drive the biggest uplift in the Australian defense industry that we''ve seen" and that the partnership requires contributing to the US submarine industrial base. On China he describes recent incidents as "unsafe and unprofessional" but seeks stabilisation, saying the nations should "cooperate where we can, disagree where we must" and advocates resuming defence dialogue to reduce miscalculation.',1);
INSERT INTO "position" VALUES(193,'richard-marles-corio','economic_nationalism','Outlining ALP defence policy as Shadow Defence Minister, Marles said "The ability to sustain and maintain the equipment the ADF uses is fundamental to our national security and it is essential that we always retain the industrial capability to meet this objective," that "At its best, Australian industry is as capable as any in the world," and advocated that "an Australian shipbuilder be mandated for all future shipbuilding programs."',1);
INSERT INTO "position" VALUES(194,'sam-birrell-nicholls','immigration','Birrell has advocated for regional skilled migration, supporting a Designated Area Migration Agreement (DAMA) for the Goulburn Valley and, in 2021, pushing before a parliamentary inquiry for ''an immediate global recruitment campaign to attract migrants with in-demand skills'' to address regional job shortages.',1);
INSERT INTO "position" VALUES(195,'tim-watts-gellibrand','immigration','In his first speech (December 2013), Watts argued immigration and multiculturalism are ''foundation stones'' of Australia''s open society and that ''an open economy cannot reach its full potential without an equally open society.'' While saying asylum seekers should arrive ''in a fair and orderly way,'' he called the Coalition''s ''dramatic cuts to Australia''s annual refugee intake and aid budget'' ''an abject moral failure,'' and criticised renaming the immigration department to add ''Border Protection.''',1);
INSERT INTO "position" VALUES(196,'tim-watts-gellibrand','foreign_policy','Watts is described as an outspoken advocate of Australian aid in Parliament and a proponent of greater Australian engagement in Asia. He has stated that there is no other nation in Asia more important to Australia''s future than Indonesia.',1);
INSERT INTO "position" VALUES(197,'tim-wilson-goldstein','faith','Tim Wilson describes himself as agnostic, having said ''I''m more of an agnostic, but I prefer to say that I haven''t found God, but I''m on a journey and I may one day find God.''',1);
INSERT INTO "position" VALUES(198,'tim-wilson-goldstein','foreign_policy','Wilson is a member of the ''Wolverines'', a parliamentary group critical of the Chinese government, and has accused Huawei of creating surveillance systems for the Chinese government, urging the UK to ban the company. In an October 2024 advertisement in the Australian Jewish News he described himself as ''proudly Zionist''.',1);
INSERT INTO "position" VALUES(199,'tim-wilson-goldstein','economic_nationalism','In his 2016 maiden speech, Tim Wilson championed open markets and free trade, saying his predecessor''s legacy was "to open markets" and that "the benefits of trade agreements begin with the signing of a pen but finish with new opportunity." He framed Australia as a net capital importer needing a competitive tax system to attract foreign investment, and advocated restructuring domestic sectors into "outward-looking export industries" rather than protecting local industry through tariffs.',1);
INSERT INTO "position" VALUES(200,'andrew-hastie-canning','faith','Hastie is a Christian; after rejecting religion in adolescence he later became part of several reformed and evangelical churches (including Capitol Hill Baptist Church, St Matthew''s Anglican Church Shenton Park, Crossroads Church Canberra, and Mandurah Presbyterian Church), and has cited his Christian faith as informing his policy views such as on individual freedoms.',1);
INSERT INTO "position" VALUES(201,'andrew-hastie-canning','immigration','Andrew Hastie has stated that Australia''s immigration numbers are ''too high, while the standards are too low,'' arguing population growth has outpaced infrastructure and pressured housing and services and that ''the system needs a massive overhaul'' (March 2026). In October 2025 he resigned from the Liberal shadow frontbench, saying he could not remain Shadow Home Affairs Minister ''and remain silent on immigration policy.''',1);
INSERT INTO "position" VALUES(202,'andrew-hastie-canning','foreign_policy','Hastie is a prominent critic of Chinese government influence in Australia, having written that ''Communist China'' rather than Islamic terrorism would be the central security concern of the 21st century, and supported banning Huawei from Australia''s 5G network. In May 2020 he signed a letter condemning what it called an assault on Hong Kong''s autonomy, rule of law and fundamental freedoms.',1);
INSERT INTO "position" VALUES(203,'andrew-hastie-canning','economic_nationalism','Andrew Hastie, Shadow Minister for Industry and Sovereign Capability, has argued for rebuilding Australian manufacturing as a matter of sovereignty, stating "Our need for a reborn Australian manufacturing sector is now vital. Our sovereignty depends upon it, our allies and partners depend upon it." He defined self-reliance as "the ability of Australia to domestically manufacture the goods and services we need," said "if globalisation led to the offshoring of Australian manufacturing, then the new geopolitical disorder can bring it back home," and called for governments to support and "pick winners" in industry.',1);
INSERT INTO "position" VALUES(204,'anne-aly-cowan','faith','Aly is Muslim; Wikipedia describes her as the first female federal parliamentarian of Islamic faith and one of Australia''s first two Muslim government ministers.',1);
INSERT INTO "position" VALUES(205,'anne-aly-cowan','immigration','As Minister for Multicultural Affairs, Aly stated in June 2025 that ''multiculturalism isn''t solely about social cohesion and multicultural communities aren''t solely responsible for social cohesion,'' arguing that making such communities ''solely and wholly responsible for social cohesion'' had added to a perception of them being ''over-securitised.'' In 2016 she spoke against then-Immigration Minister Peter Dutton''s comments regarding Lebanese Muslim immigration.',1);
INSERT INTO "position" VALUES(206,'anne-aly-cowan','foreign_policy','On recognition of Palestinian statehood, Aly stated that ''just saying to recognize Palestinian state without any context is in some ways tokenistic'', supporting the government position that recognition should be part of a just peace process. She is also noted as a researcher on countering violent extremism, having founded People Against Violent Extremism (PaVE).',1);
INSERT INTO "position" VALUES(207,'anne-aly-cowan','citizenship_eligibility','Born in Egypt, Aly renounced her Egyptian citizenship on 6 May 2016, before the close of nominations for the 2016 federal election, so she did not breach section 44(i); the Egyptian embassy later provided written confirmation that as of that date she had completely renounced her Egyptian citizenship.',1);
INSERT INTO "position" VALUES(208,'ben-small-forrest','citizenship_eligibility','Small discovered he held Australian-New Zealand dual citizenship and resigned from the Senate on 15 April 2022 under section 44(i); New Zealand approved his renunciation on 14 April 2022, after which he was reappointed to fill the vacancy, and he was later elected MP for Forrest in 2025.',1);
INSERT INTO "position" VALUES(209,'josh-wilson-fremantle','immigration','In his September 2016 first speech, Josh Wilson said ''indefinite detention is wrong'' and that ''the operation of the centres at Nauru and Manus Island has been unacceptable,'' arguing that ''creating a properly constituted regional settlement framework is possible.''',1);
INSERT INTO "position" VALUES(210,'josh-wilson-fremantle','foreign_policy','In a statement dated 8 February 2024, Wilson said of Israel''s military campaign in Gaza that ''not every military action constitutes self defence. The wholesale destruction of Gaza is not self defence'', and called for the violence to end, describing the killing of civilians as wrong.',1);
INSERT INTO "position" VALUES(211,'josh-wilson-fremantle','economic_nationalism','Josh Wilson has advocated for Australian shipbuilding and sovereign industrial capacity, saying that "as an island continent nation, we need to have that sovereign capacity, both in terms of the industrial side of it and the workforce and skills side of it." He said he is glad to be part of a government delivering an Australian strategic fleet because the nation "can''t go without that capacity," referencing the shipbuilding hub at Henderson in his electorate.',1);
INSERT INTO "position" VALUES(212,'josh-wilson-fremantle','citizenship_eligibility','Born in London, Wilson held British citizenship and applied to renounce it shortly after his 2016 endorsement, with the renunciation registered effective 29 June 2016 (after the close of nominations). Referred to the High Court, he resigned in May 2018 following the Gallagher ruling and won the resulting Fremantle by-election.',1);
INSERT INTO "position" VALUES(213,'kate-chaney-curtin','immigration','Speaking on 26 March 2024 as the Migration Amendment (Removal and Other Measures) Bill 2024 was forced through the House, Kate Chaney said it was ''very very disappointing,'' stating her community ''wants to see compassion when we are approaching asylum seekers.'' She has also criticised the former ''fast track'' processing system as flawed.',1);
INSERT INTO "position" VALUES(214,'kate-chaney-curtin','foreign_policy','Chaney has called for greater scrutiny and transparency of the AUKUS agreement, joining other crossbench MPs in pressing for more parliamentary accountability over the deal.',1);
INSERT INTO "position" VALUES(215,'madeleine-king-brand','economic_nationalism','As Minister for Resources, Madeleine King announced a Critical Minerals Strategic Reserve, stating "while we will continue to supply the world with critical minerals, it is also important that Australia has access to the critical minerals and rare earths we need for a Future Made in Australia," and noting the initiative would generate additional investment and employment, particularly in Western Australia.',1);
INSERT INTO "position" VALUES(216,'patrick-gorman-perth','immigration','In his first speech to Parliament, Patrick Gorman said ''Perth welcomes new Australians and has a proud migrant history,'' highlighting his electorate''s multicultural and migrant heritage.',1);
INSERT INTO "position" VALUES(217,'rick-wilson-o-connor','economic_nationalism','In his 2013 first speech, Rick Wilson said he stands "proudly for the Liberal philosophy of free markets, vigorous competition, small government and individual responsibility." He cited foreign investment positively, noting that "it was syndicated American money that was behind the development of the sand plain into an extraordinarily productive farming region" around Esperance, and welcomed the rebuilding of the live animal export trade.',1);
INSERT INTO "position" VALUES(218,'sam-lim-tangney','faith','Sam Lim is a practising Buddhist; he became the first person to be sworn into the Australian federal parliament on Buddhist scripture (the Dhammapada), and has said Buddhism has ''always been a positive force'' in his life giving him ''great inner strength''. The Federation of Australian Buddhist Councils describes him as ''perhaps the first Buddhist Federal Member of Parliament''.',1);
INSERT INTO "position" VALUES(219,'sam-lim-tangney','immigration','In his maiden speech (6 September 2022), Malaysian-born Sam Lim credited former Labor PM Gough Whitlam with ending the White Australia policy and introducing multiculturalism, saying ''because of him we can call Australia home.''',1);
INSERT INTO "position" VALUES(220,'sam-lim-tangney','economic_nationalism','Sam Lim has backed local manufacturing and local jobs in connection with defence industry grants, stating "by backing local manufacturing, the Albanese Labor Government is investing in high-skilled, local jobs right here in Tangney," and framing the support as building Australia''s local capability and employment.',1);
INSERT INTO "position" VALUES(221,'sam-lim-tangney','citizenship_eligibility','Born in Malaysia, Lim became an Australian citizen in 2008; his Wikipedia citizenship record lists his Malaysian citizenship as held until 2021, before his 2022 election to the House of Representatives.',1);
INSERT INTO "position" VALUES(222,'zaneta-mascarenhas-swan','immigration','In her first speech, Mascarenhas recounted that her Goan Indian father was told at the Australian embassy in Kenya ''You have the right skills, but you''re the wrong colour'' under the White Australia policy, and said her family''s migration was only possible after the Whitlam government dismantled the last parts of that policy; she praised ''the most multicultural parliament we''ve had in history.''',1);
INSERT INTO "position" VALUES(223,'zaneta-mascarenhas-swan','economic_nationalism','In her first speech, Zaneta Mascarenhas argued "in WA we need to build beyond the resources boom and make our economy more resilient," and that "Australia needs to increase diversification, commercialisation and sophistication of our industry capability." She said Australia is rich in critical minerals to "build batteries, wind turbines and solar panels" and could become a "renewable energy superpower," advocating use of the National Reconstruction Fund to build advanced manufacturing capability, including the cell-manufacturing "value-add step."',1);
INSERT INTO "position" VALUES(224,'david-pocock-act','faith','David Pocock has publicly spoken about the role of his Christian faith in inspiring him to get involved in politics, citing theologians such as Dietrich Bonhoeffer, Oscar Romero and Walter Wink as influences. He has described exploring his Christian faith, including reading theology and studying writers such as N.T. Wright and John Howard Yoder.',1);
INSERT INTO "position" VALUES(225,'david-pocock-act','immigration','Pocock opposes offshore processing, calling for an end to it and a more human-rights-compliant refugee approach. After the government reauthorised Nauru offshore detention in February 2023 he called it a ''massive failure'' and argued it ''makes no sense to be paying $420m of taxpayer money over three years to detain a small group of people.''',1);
INSERT INTO "position" VALUES(226,'david-pocock-act','foreign_policy','In remarks reported on 3 June 2024, Pocock called on Australia to cut all military ties with Israel and end arms deals, citing Australian-made parts used in F-35 aircraft and an Elbit Systems vehicle contract, and called for targeted sanctions against members of the Israeli government and Israel Defense Forces over the situation in Gaza.',1);
INSERT INTO "position" VALUES(227,'david-pocock-act','economic_nationalism','Independent Senator David Pocock has advocated reforming government procurement to favour Australian companies and small businesses, saying Australia should be "investing in Australian companies - sovereign Australian companies - that are building up their capability in a whole range of industries from defence to quantum computing... and not just going with multinationals." He criticised multinationals "skimming the cream off the top and subcontracting that to smaller Australian companies" as "a ridiculous use of taxpayer money," and called for a system where smaller Australian companies can win contracts.',1);
INSERT INTO "position" VALUES(228,'david-pocock-act','citizenship_eligibility','Pocock, who held Zimbabwean and South African citizenship by birth/descent, provided documentary evidence renouncing both before the nomination deadline of 22 April 2022, leaving him solely an Australian citizen as required by section 44 ahead of his 2022 Senate election.',1);
INSERT INTO "position" VALUES(229,'katy-gallagher-act','immigration','At a 2015 Palm Sunday refugee rally Gallagher expressed discomfort with offshore detention, telling Fairfax Media ''I am uncomfortable with what is going on now'' and that few Australians, ''if they fully understood what was going on in detention centres and offshore processing, would be that comfortable with how it is being conducted.''',1);
INSERT INTO "position" VALUES(230,'katy-gallagher-act','citizenship_eligibility','Gallagher held British citizenship by descent through her father; her renunciation was lodged in April 2016 but not registered by the UK Home Office until 16 August 2016, after she nominated for the 2016 election. On 9 May 2018 the High Court unanimously ruled her ineligible under section 44(i); she returned to the Senate at the 2019 election.',1);
INSERT INTO "position" VALUES(231,'andrew-bragg-nsw','immigration','In a December 2025 address to the Centre for Independent Studies on housing, Bragg said ''cutting migration will not singularly fix the housing crisis, but reducing it will help demand,'' and argued migration policy should prioritise bringing in people ''who can actually build homes,'' noting Australia is short 80,000 tradies while receiving only 4,000 on visas in the prior year.',1);
INSERT INTO "position" VALUES(232,'andrew-bragg-nsw','economic_nationalism','In his 2019 maiden speech, Andrew Bragg argued against protectionism, saying "this nation will never have enough domestic capital to meet our high ambitions" and that "the argument that we should close down foreign investment is akin to raising the tariff walls." He said "almost one-quarter of our economy is exports... we simply cannot afford to take protectionist risks," while adding Australia "must maintain a liberal approach to trade and foreign investment whilst ensuring we do all the appropriate due diligence, and reserve the right to legislate to protect Australia''s security, economic and social interests."',1);
INSERT INTO "position" VALUES(233,'andrew-bragg-nsw','citizenship_eligibility','Bragg was a British citizen by descent (his father and three grandparents were born in the United Kingdom) until renouncing it in December 2017, before his 2019 election to the Senate.',1);
INSERT INTO "position" VALUES(234,'dave-sharma-nsw','immigration','In his March 2024 Senate first speech, Sharma linked high immigration to housing pressure, saying ''the shortage of housing is being exacerbated by high immigration'' and that ''until we are able to accelerate the pace of our home building, we need to reduce our immigration intake.''',1);
INSERT INTO "position" VALUES(235,'dave-sharma-nsw','foreign_policy','Sharma, a former Australian ambassador to Israel, has advocated that Australia spend more than 2% of GDP on defence. On Israel-Gaza he has supported demilitarisation of the Gaza Strip and stated that the conflict will not end until Hamas stops firing rockets.',1);
INSERT INTO "position" VALUES(236,'david-shoebridge-nsw','immigration','As the Greens spokesperson on immigration, Shoebridge opposes the Labor government''s resettlement deal with Nauru, calling for it to be ''ripped up'' and for ''an immediate pause on sending any further people to Nauru,'' and has called for a royal commission into offshore processing.',1);
INSERT INTO "position" VALUES(237,'david-shoebridge-nsw','foreign_policy','Shoebridge has been a vocal supporter of Palestinian causes. In August 2025 he said that if the Albanese government stopped the export of F-35 fighter jet parts to Israel, Israel''s F-35 fleet would be grounded, and in September 2025 he called for Australia to apply sanctions against Israel comparable to those against Russia.',1);
INSERT INTO "position" VALUES(238,'deborah-o-neill-nsw','faith','Deborah O''Neill is known as a devout/practising Catholic; born to Irish Catholic immigrants, she has described politics as her way of giving action to her faith.',1);
INSERT INTO "position" VALUES(239,'deborah-o-neill-nsw','immigration','O''Neill says the best way to retain the cohesiveness of Australia''s multicultural society is to support an increased humanitarian intake and ensure adequate funding for resettlement of refugees and migrants, while protecting borders from ''chaos.'' She has said Australians ''really rejected the sense of chaos, of processes being overwhelmed.''',1);
INSERT INTO "position" VALUES(240,'deborah-o-neill-nsw','foreign_policy','O''Neill is described as an ''AUKUS champion'' and chairs the Parliamentary Joint Committee on Defence overseeing the AUKUS nuclear-powered submarine program. She is characterised as hawkish on China, is a member of the Inter-Parliamentary Alliance on China, and has stated that Xi Jinping is ''forever tied'' to the persecution of Uighurs.',1);
INSERT INTO "position" VALUES(241,'deborah-o-neill-nsw','citizenship_eligibility','O''Neill, who held Irish citizenship through her Irish parents, renounced her Irish citizenship in order to run for federal parliament as required by section 44.',1);
INSERT INTO "position" VALUES(242,'jenny-mcallister-nsw','immigration','Responding in the Senate to anti-immigration marches, McAllister said the government has ''zero tolerance for hate and discrimination in all its forms'' and described anti-Indian sentiment seen at the protests as racist, emphasising a commitment to ''building a safer and more inclusive Australia for everyone.''',1);
INSERT INTO "position" VALUES(243,'jessica-collins-nsw','immigration','In her first Senate speech (30 July 2025), Collins drew on her doctoral research with the Karen refugee community resettled from Burma to Brisbane and time spent in refugee camps on the Thai-Burma border, stating that ''as a middle power, Australians have a moral obligation to help where we can, understanding the limitations we have.'' She called for expanded economic sanctions on Burma''s military regime.',1);
INSERT INTO "position" VALUES(244,'jessica-collins-nsw','foreign_policy','In her first Senate speech, Collins advocated shifting Australia''s Pacific relationship "from aid and dependency to trade and prosperity", noting Pacific countries "want to move beyond the aid relationship with Australia". She highlighted that remittances from Pacific workers exceed Australian government aid, criticised high transfer fees, and called for stronger economic sanctions on Burma''s central bank.',1);
INSERT INTO "position" VALUES(245,'maria-kovacic-nsw','immigration','In her first speech, Kovacic (daughter of Croatian migrants who fled communism) described Australia welcoming her parents and ''hundreds of thousands like them'' as an act of a country with ''extraordinary courage and confidence,'' framing her migrant story as part of Australia''s multicultural history alongside its Indigenous First Peoples.',1);
INSERT INTO "position" VALUES(246,'mehreen-faruqi-nsw','faith','Mehreen Faruqi is Muslim; she was the first Muslim woman to be a member of an Australian parliament and the first female Muslim senator.',1);
INSERT INTO "position" VALUES(247,'mehreen-faruqi-nsw','immigration','As the Australian Greens'' immigration and citizenship spokesperson, Faruqi advocates for refugees and asylum seekers and seeks an end to mandatory detention. In September 2025 she moved in the Senate to condemn anti-immigration marches as ''racist, white supremacist rallies'' and accused politicians and media of normalising hate.',1);
INSERT INTO "position" VALUES(248,'mehreen-faruqi-nsw','foreign_policy','Faruqi has been a prominent parliamentary critic of Israel over the Gaza war. In November 2023 she led Greens colleagues in a Senate walkout protesting the government''s refusal to call for a ceasefire, and in 2025 she held signs in the Senate reading "Gaza is starving... Sanction Israel" and directly asked PM Albanese, "will you sanction Israel?" She has called for an end to Australian military exports to Israel.',1);
INSERT INTO "position" VALUES(249,'mehreen-faruqi-nsw','citizenship_eligibility','Migrated from Pakistan in 1992 and became an Australian citizen in 1994; she retained Pakistani citizenship until renouncing it in 2017 to meet section 44 eligibility requirements before entering federal Parliament.',1);
INSERT INTO "position" VALUES(250,'sean-bell-nsw','immigration','Bell named ''ending mass immigration'' among his top Senate priorities, arguing that high immigration levels are driving housing unaffordability, overloading infrastructure and pushing up energy prices in NSW, and calling for a government that puts ''Australian families, industries, and values first.''',1);
INSERT INTO "position" VALUES(251,'sean-bell-nsw','economic_nationalism','In his 26 November 2025 maiden speech, Bell said Australian manufacturing ''is being shut down'' and that industry such as Tomago Aluminium is ''on the brink'', that coalmining jobs sustaining regions like the Hunter ''are being sacrificed'', and criticised reliance on ''Chinese-made solar panels and foreign supply chains'' as ''national self-harm'', adding that a young family ''should not have to compete with every millionaire from China, India or the United States'' to buy a home.',1);
INSERT INTO "position" VALUES(252,'tim-ayres-nsw','economic_nationalism','Ayres states in his first speech that he advocates for strong manufacturing industries and good blue-collar jobs, especially in Australia''s regions, noting Australia lost 25 per cent of its manufacturing workforce between 2012 and 2016, and he criticises the offshoring of jobs and concentration of economic activity in big cities.',1);
INSERT INTO "position" VALUES(253,'tim-ayres-nsw','citizenship_eligibility','A change to Canadian citizenship law (Bill C-3, passed 15 December 2025) automatically conferred Canadian citizenship on him via a Canadian-born grandfather while he was already a sitting senator; he renounced the Canadian citizenship on 29 December 2025, which did not affect his eligibility under section 44(i).',1);
INSERT INTO "position" VALUES(254,'jacinta-nampijinpa-price-nt','immigration','On 3 September 2025 Price claimed the Labor government was giving preference to immigrants from particular countries, specifically India, citing concern over ''large numbers'' arriving. She later retracted the claim that immigration law permits ethnic preference but said ''I don''t believe I have anything to apologise about''; on 10 September 2025 Liberal leader Sussan Ley removed her from the shadow ministry after she refused to apologise.',1);
INSERT INTO "position" VALUES(255,'jacinta-nampijinpa-price-nt','foreign_policy','Price has publicly criticised the Albanese Government''s foreign policy on the Middle East. In an October 2024 opinion piece she defended Israel as "our ally" and accused critics of being silent on Hamas atrocities while accusing Israel of "genocide" for responding. She characterised the government''s September 2025 decision to recognise a Palestinian state as "ill-timed, impulsive, irrational, immoral and ideologically-driven".',1);
INSERT INTO "position" VALUES(256,'malarndirri-mccarthy-nt','faith','Malarndirri McCarthy was baptised in the Catholic church and grew up with a deep respect for both traditional Indigenous and Catholic values; Catholic media describe her as a woman of faith who draws on a lifetime of Catholic faith.',1);
INSERT INTO "position" VALUES(257,'larissa-waters-qld','immigration','In a public statement on her official Facebook page (31 May 2024), Waters said ''we should be proud of multicultural and migrant communities, but the Labor and Liberal parties want to demonise migrants to distract from their own failings.'' As Greens leader she has rejected cuts to overall migration numbers and the framing of migrants/international students as a cause of the housing crisis.',1);
INSERT INTO "position" VALUES(258,'larissa-waters-qld','foreign_policy','Waters has criticised AUKUS as wasteful, saying "We are wasting A$370 billion on nuclear submarines that actually may never even eventuate" and that the expenditure "makes us less safe". On the Middle East she has said Australia should play a stronger role in sanctioning Benjamin Netanyahu''s war cabinet.',1);
INSERT INTO "position" VALUES(259,'larissa-waters-qld','citizenship_eligibility','Held Canadian citizenship from birth; she resigned from the Senate on 18 July 2017 over section 44(i), renounced her Canadian citizenship on 8 August 2017, and the High Court ruled on 27 October 2017 that she had been invalidly elected. She returned to the Senate on 6 September 2018 to fill a casual vacancy.',1);
INSERT INTO "position" VALUES(260,'malcolm-roberts-qld','immigration','Roberts advocates cutting Australia''s annual skilled and family migration intake to around 70,000 (a reduction of more than 60% from the 190,000 cap), describing this as ''zero net'' migration, and has called for a parliamentary inquiry into the impacts of mass immigration on housing, wages, infrastructure and social cohesion.',1);
INSERT INTO "position" VALUES(261,'malcolm-roberts-qld','foreign_policy','Roberts argues Australia should stay out of overseas conflicts, writing on Ukraine that "we have no dog in this fight and we should stay out of it" and questioning the mainstream media narrative on the war. He has called for Australia to avoid being drawn into foreign wars on false premises, citing the Iraq WMD claims.',1);
INSERT INTO "position" VALUES(262,'malcolm-roberts-qld','economic_nationalism','In his 2016 maiden speech, Roberts stated that ''90 per cent of Australia''s large companies are foreign owned'', that ''the people of Australia are desperate to regain our sovereignty'' and ''Australians have had enough of foreign control'', and criticised de-industrialisation policies as ''costing jobs, destroying families, bankrupting businesses''.',1);
INSERT INTO "position" VALUES(263,'malcolm-roberts-qld','citizenship_eligibility','Born in India in 1955 and a British citizen by descent through his father; his attempts to renounce before nominating were ineffectual and renunciation was only registered on 5 December 2016. The High Court ruled on 27 October 2017 that he had been ineligible under section 44(i) and disqualified him; with his citizenship resolved he was re-elected to the Senate in 2019.',1);
INSERT INTO "position" VALUES(264,'matthew-canavan-qld','faith','Canavan is a Roman Catholic; he was raised Catholic and has said he "rediscovered" his Roman Catholic faith while preparing for his marriage. Wikipedia categorises him as an Australian Roman Catholic.',1);
INSERT INTO "position" VALUES(265,'matthew-canavan-qld','immigration','On a speech page about migration/protection legislation, Canavan supports strict border control and deterrence of unauthorised boat arrivals, taking pride that the government ''put a stop to'' people smuggling, and supports requiring asylum seekers to take reasonable steps to establish their identity and make protection visa applications in good faith. He argues these measures are consistent with international obligations and cites the reduction of children in detention.',1);
INSERT INTO "position" VALUES(266,'matthew-canavan-qld','foreign_policy','Canavan argues Australia''s defence strategy has put too much stake on nuclear submarines that would not be delivered until the 2040s, and that the AUKUS agreement has been put under review by the Trump administration. He calls for higher defence spending, warns that "economic dependence on China only deepens their malign influence", and stresses retaining sovereignty by working with close allies like the US.',1);
INSERT INTO "position" VALUES(267,'matthew-canavan-qld','economic_nationalism','In a January 2021 policy paper, Canavan called to reverse the decline in Australian manufacturing by reinvesting in coal and gas, ''protecting Australian jobs from unfair overseas competition'', introducing a ''Buy Australian Act'' to give preference to Australian-made goods in government contracts, and protecting key manufacturing industries including by tariffs; he wrote that this challenges ''longstanding commitments to free trade and the removal of industry protection'' but that security challenges require backing Australian industrial development.',1);
INSERT INTO "position" VALUES(268,'matthew-canavan-qld','citizenship_eligibility','Referred to the High Court in the 2017-18 citizenship crisis over possible Italian citizenship by descent; on 27 October 2017 the Court (Re Canavan) held he had never been an Italian citizen and was validly elected, so he was not disqualified under section 44(i).',1);
INSERT INTO "position" VALUES(269,'murray-watt-qld','immigration','In relation to the August 2025 memorandum of understanding allowing Australia to send members of the NZYQ cohort to Nauru, Watt said the arrangement would involve ''hundreds'' from that cohort, the group of detainees whose visas were cancelled but who could not be deported.',1);
INSERT INTO "position" VALUES(270,'paul-scarr-qld','immigration','In an address to the Migration Institute of Australia, Scarr (Shadow Minister for Immigration) argues net overseas migration is ''materially higher than a range of measures of long-term sustainable levels'' and points to research suggesting around 160,000-220,000 annually as optimal for GDP per capita. He frames concern about immigration numbers as driven by housing and economic pressures rather than opposition to multiculturalism, calls for evidence-based debate that does not ''inflame emotion,'' and celebrates Australia''s refugee resettlement legacy.',1);
INSERT INTO "position" VALUES(271,'paul-scarr-qld','foreign_policy','Scarr has stated he supports "a two-state solution that is negotiated between the parties and would provide both Israelis and Palestinians with peace and security within internationally recognized borders", arguing the issue can only be resolved by negotiation between the parties.',1);
INSERT INTO "position" VALUES(272,'pauline-hanson-qld','immigration','Hanson advocates drastically reduced immigration, having called for capping immigration (75,000 in 2018; 130,000 in 2025). In a June 2026 speech she declared Australia "cannot be a multicultural society" and must become monocultural. She has called for a ban on Muslim immigration and has stated Australia is "in danger of being swamped" by groups she says do not assimilate. Per reporting on a September 2025 Senate immigration inquiry she backed, her broader advocacy includes deeper migration cuts, an eight-year wait for citizenship and welfare, and withdrawal from the UN Refugee Convention.',1);
INSERT INTO "position" VALUES(273,'pauline-hanson-qld','foreign_policy','Hanson has said foreign aid should be judged by whether "it''s spent well" and that Australia should "clean up our own backyard first"; One Nation''s platform calls for a large cut to the aid budget. She has raised concern about aid-recipient nations also accepting Chinese aid. On the Middle East she has called for Palestinians on temporary visas to be repatriated now the Gaza conflict has ended, saying "charity begins at home".',1);
INSERT INTO "position" VALUES(274,'pauline-hanson-qld','economic_nationalism','In a May 2026 interview, Hanson said ''I don''t believe foreigners should own any housing in Australia or our farming land'', and proposed giving foreign owners two years to sell or have property repossessed by the government (later clarifying this would apply to temporary visa holders and foreigners living overseas, not permanent residents). In a December 2020 media release she also opposed ''predatory foreign investment'' and foreign takeovers of Australian businesses across sectors including manufacturing and mining.',1);
INSERT INTO "position" VALUES(275,'alex-antic-sa','faith','Antic is publicly described as a Christian senator and frames his politics around Christian faith and values; his 2019 maiden speech cited "family, faith, freedom and the flag" as his core values, and The Spectator Australia refers to him directly as a "Christian Senator." Sources do not pin down a specific denomination.',1);
INSERT INTO "position" VALUES(276,'alex-antic-sa','immigration','Antic was one of several Coalition senators who crossed party lines on 1 September 2025 to support a One Nation motion establishing a Senate inquiry into the effects of high immigration on the economy, housing affordability, wages, infrastructure and social cohesion.',1);
INSERT INTO "position" VALUES(277,'barbara-pocock-sa','foreign_policy','Pocock has criticised the conduct of the Israeli state and military in Gaza, saying "We have certainly been critical of the behaviour of the Israeli state, their military, and the way they continue to conduct a war against the civilians in Gaza." She has also voiced South Australian concerns about AUKUS and called for Australia to forge a more independent foreign policy.',1);
INSERT INTO "position" VALUES(278,'charlotte-walker-sa','faith','Walker has stated she is not religious, considering herself an agnostic and a humanist (per an April 2026 Sydney Morning Herald interview, as reported in her Wikipedia article).',1);
INSERT INTO "position" VALUES(279,'don-farrell-sa','foreign_policy','As Trade Minister, Farrell pressed China to lift trade sanctions on Australian exports, stating "Things aren''t going to get back to normal until they lift those bans"; this pressure preceded China lifting tariffs on Australian wine in April 2024. He has pursued trade diversification away from China through agreements with the UK and India.',1);
INSERT INTO "position" VALUES(280,'karen-grogan-sa','faith','Grogan''s Wikipedia article states she was born in London "into a large Irish Catholic family," describing her family/upbringing background; it does not state her current personal religious practice.',1);
INSERT INTO "position" VALUES(281,'marielle-smith-sa','faith','In her first (maiden) speech to the Senate, Smith referred to "my Christian values of social justice and fairness," saying she found a political home in the Labor Party because of those values. This is a self-identification of Christian values rather than a stated denomination or practising status.',1);
INSERT INTO "position" VALUES(282,'marielle-smith-sa','citizenship_eligibility','Smith held British citizenship by descent through her UK-born mother and renounced it in 2018 prior to nominating for parliament, resolving her eligibility under section 44(i).',1);
INSERT INTO "position" VALUES(283,'penny-wong-sa','faith','Wong is described as a practising Christian and a member of the Uniting Church in Australia; she is quoted saying "I do not ever remember having the sense that I denied the existence of God."',1);
INSERT INTO "position" VALUES(284,'penny-wong-sa','immigration','As Foreign Minister, Wong said her government would "consider New Zealand''s concerns about Australia''s Section 501 deportation policy," under which non-citizens with criminal records are deported, an issue that had strained relations between the two countries.',1);
INSERT INTO "position" VALUES(285,'penny-wong-sa','foreign_policy','As Foreign Minister, Wong said in April 2024 that Australia would consider recognising Palestinian statehood as a means of facilitating a two-state solution, but clarified the May 2024 UN vote on Palestinian participation did not constitute recognition, which would come only "when we think the time is right." She described Israel''s planned Rafah offensive as "unjustifiable" (February 2024), paused UNRWA funding in February 2024 pending Israeli evidence, and in June 2025 announced Australia would sanction Israeli ministers Ben-Gvir and Smotrich. She sought to stabilise relations with China, becoming the first Australian cabinet minister to visit China since 2019 (December 2022).',1);
INSERT INTO "position" VALUES(286,'penny-wong-sa','citizenship_eligibility','Wong was born in Kota Kinabalu, Malaysia, and held Malaysian citizenship, which she renounced in 2001 before being elected to the Senate in 2002, resolving her eligibility under section 44(i).',1);
INSERT INTO "position" VALUES(287,'sarah-hanson-young-sa','immigration','A former refugee-justice and Amnesty International campaigner and former Greens immigration spokesperson, Hanson-Young has been a prominent advocate against offshore detention. On leaving the immigration portfolio she said she would "never stop fighting for people seeking asylum" and that her team''s work "has exposed the systematic abuse of women and children on Nauru and has been central to changing public perception about offshore detention."',1);
INSERT INTO "position" VALUES(288,'helen-polley-tas','faith','Polley identifies as Catholic, which she has cited in informing her positions on issues such as same-sex marriage.',1);
INSERT INTO "position" VALUES(289,'jacqui-lambie-tas','faith','In 2014 Lambie described herself as ''Catholic; I''m religious'', citing it as a reason for declining an invitation to visit a Sydney mosque.',1);
INSERT INTO "position" VALUES(290,'jacqui-lambie-tas','immigration','Lambie''s stated immigration positions have shifted over time. In 2014-2017 she proposed banning the burqa, introduced a bill to prohibit full face coverings during terrorism threat declarations, called for Australia to adopt travel restrictions on Muslim-majority countries similar to Donald Trump''s, and advocated deporting Muslims who supported Sharia law. After participating in the 2018 program ''Go Back to Where You Came From,'' she shifted toward a more pro-refugee stance, saying the discussion about accepting more refugees "needs to be on the political table," and distanced herself from earlier anti-Islam rhetoric.',1);
INSERT INTO "position" VALUES(291,'jacqui-lambie-tas','foreign_policy','Lambie has been a vocal critic of the Chinese government, warning in 2014 of the "unprecedented" threat from "Communist Chinese military capacity" and opposing the China-Australia Free Trade Agreement in 2015, calling the Chinese government "anti-democratic" and "a bully, thief, liar and international human rights abuser." On AUKUS, she criticised the revised submarine arrangement, telling defence officials in Senate estimates "What we should be getting is three new submarines and now we''re getting trash instead."',1);
INSERT INTO "position" VALUES(292,'jacqui-lambie-tas','economic_nationalism','Through her "Make Australia Make Again" (MAMA) campaign, Lambie calls for reviving domestic manufacturing, arguing "What we make, we control" and that government "has an obligation to identify the core industrial capabilities Australia needs." She cites the Whyalla steelworks as a "critical" sovereign capability, advocates putting "the brakes on foreign purchases of our critical assets," and promotes a "Back local. Back Australia" approach of investing in Australian industry rather than competitors.',1);
INSERT INTO "position" VALUES(293,'jacqui-lambie-tas','citizenship_eligibility','Lambie held British citizenship by descent from her Scottish-born father and resigned from the Senate on 14 November 2017 under section 44 over this dual citizenship; following a recount her seat went to Steve Martin, and she was re-elected to the Senate in 2019.',1);
INSERT INTO "position" VALUES(294,'jonathon-duniam-tas','faith','Duniam is a Christian and attends the Mount Stuart Presbyterian Church in Hobart; he was not raised in a Christian household but attended Catholic schools.',1);
INSERT INTO "position" VALUES(295,'nick-mckim-tas','immigration','As Greens immigration spokesperson, McKim is a strong opponent of offshore detention, describing it as designed "to make people''s lives so miserable... that they decide to turn back to face the persecution they fled." He has called Australia a "human rights pariah," said there is "never an excuse for torture," criticised Labor''s policy as "the same rubbish in a different bin," and called for detainees to be evacuated and a "genuine regional approach" to be adopted.',1);
INSERT INTO "position" VALUES(296,'nick-mckim-tas','foreign_policy','In a Senate speech on 26 March 2025, McKim described Israel''s actions in Gaza as "a genocide" and "a barbaric murder spree," said it was "utterly disgraceful how complicit Labor has allowed us to become," referencing weapons components and the Pine Gap facility, and moved a motion calling for the government to impose sanctions on "the extremist Netanyahu government," end the arms trade, and call for an end to the conflict in Gaza.',1);
INSERT INTO "position" VALUES(297,'nick-mckim-tas','citizenship_eligibility','McKim was born in London and held British citizenship, which he formally renounced (registered 1 February 2016); he sat in breach of section 44 from 20 August 2015 until that date, but his renunciation was complete before the 2016 election nominations, so he was not in breach when nominating.',1);
INSERT INTO "position" VALUES(298,'peter-whish-wilson-tas','foreign_policy','In September 2023 Whish-Wilson joined a cross-party delegation of Australian MPs to Washington, D.C. to lobby the U.S. Department of Justice to abandon its attempts to extradite Australian publisher Julian Assange.',1);
INSERT INTO "position" VALUES(299,'peter-whish-wilson-tas','economic_nationalism','Whish-Wilson established a Senate inquiry into foreign investment, stating that "the government''s failure to ensure the integrity of the foreign investment approval process is undermining what faith the public has that these takeovers are being approved in the national interest." He raised concerns about foreign takeovers (citing Bellamy''s and VDL Dairy) and potential weaknesses, including money-laundering vulnerabilities, in Australia''s foreign investment and property-purchase framework.',1);
INSERT INTO "position" VALUES(300,'richard-colbeck-tas','economic_nationalism','Colbeck called for a Senate inquiry into the Australian metals manufacturing industry, stating "these assets need to be supported and protected, because... if we lose these assets, it will be nearly impossible to recover them," and that "a ''Future Made in Australia'' needs to be more than just a catchphrase" with government supporting existing facilities. He has also advocated for protecting jobs in Tasmanian salmon, forestry and other regional industries.',1);
INSERT INTO "position" VALUES(301,'bridget-mckenzie-vic','faith','In her first speech to the Senate, McKenzie stated ''I am confident in two things—my faith and science'', explicitly affirming that she holds a religious faith, though she did not name a denomination.',1);
INSERT INTO "position" VALUES(302,'bridget-mckenzie-vic','immigration','In her 2025 CPAC speech, McKenzie said she is "pro-migrant and against aggressive immigration," warning against an immigration program that strains housing, infrastructure, services and social cohesion. She said Australia should welcome migrants who share its values and respect the rule of law, stated "We do not need Islamists in this country," and noted Australia has avoided the illegal-immigration problems seen elsewhere partly due to tough decisions by previous Coalition governments.',1);
INSERT INTO "position" VALUES(303,'bridget-mckenzie-vic','foreign_policy','In May 2024 McKenzie criticised Senator Fatima Payman''s comments on Gaza as "Absolutely appalling" after Payman accused Israel of genocide and used the phrase "From the river to the sea, Palestine will be free," and questioned what the Prime Minister would do in response.',1);
INSERT INTO "position" VALUES(304,'bridget-mckenzie-vic','economic_nationalism','McKenzie supported reducing the foreign investment screening threshold to zero dollars so that all proposed foreign investments would be scrutinised, citing concern about "opportunistic foreign raiders getting control of Australia''s food supply assets" and stating "it is not in our national interest to leave the door open wide for foreign opportunists to take advantage of our clean, green reputation and assets." She framed the measures as protecting Australian agricultural land.',1);
INSERT INTO "position" VALUES(305,'james-paterson-vic','faith','Paterson is an agnostic and has described himself as ''not religious at all'', although his wife is Catholic and his children were baptised Catholic.',1);
INSERT INTO "position" VALUES(306,'james-paterson-vic','immigration','Paterson defended the Coalition''s plan to reduce migration, arguing it would bring in 140,000 permanent residents in a way that is "much more sustainable than what Labor has been doing" and would "ease pressure on the housing market, health sector and congestion."',1);
INSERT INTO "position" VALUES(307,'james-paterson-vic','foreign_policy','Paterson is a strong critic of China; he and Andrew Hastie were denied entry to China in 2019 over their criticism of Beijing''s treatment of Uyghurs, and in 2022 he became Australian Co-Chair of the Inter-Parliamentary Alliance on China. He has stated that China''s "foreign interference and espionage are the greatest threat to Australia''s way of life, surpassing terrorism" (October 2021). He has advocated a CANZUK freedom-of-movement arrangement between Canada, Australia, New Zealand and the UK.',1);
INSERT INTO "position" VALUES(308,'lidia-thorpe-vic','immigration','Thorpe is a vocal opponent of immigration and offshore detention. Attending protests at the Melbourne Immigration Transit Accommodation in 2022 over the transfer of detainees to Christmas Island, she demanded to know "how many people seeking asylum are actually in there, and what are the plans for them?" and criticised the treatment of detainees. She has continued to advocate for asylum seekers and refugees in the Senate.',1);
INSERT INTO "position" VALUES(309,'lidia-thorpe-vic','foreign_policy','Thorpe is an outspoken advocate for Palestine. At an October 2025 pro-Palestine rally she said she would "burn down Parliament House to make a point" over conditions in Gaza (which she described as hyperbolic), and in November 2024 raised a fist and called "Free Palestine" in the Senate.',1);
INSERT INTO "position" VALUES(310,'michelle-ananda-rajah-vic','foreign_policy','Ananda-Rajah describes herself as a supporter of Israel and the Jewish community while stating she backs Labor''s position of a negotiated two-state solution. In May 2024 she said she felt "very conflicted" about the Australian government''s UN vote supporting Palestinian statehood, and in July 2024 she criticised Senator Fatima Payman for crossing the floor to immediately recognise Palestine, arguing it contradicted Labor''s two-state approach. She visited Israel as part of parliamentary delegations in July and December 2023.',1);
INSERT INTO "position" VALUES(311,'michelle-ananda-rajah-vic','economic_nationalism','In her first speech and related remarks, Ananda-Rajah argues Australia should build sovereign capability in biotechnology, bridging the "missing middle" so domestic biotech firms can achieve scale onshore rather than commercialising overseas, and positions Australia as a global clinical trials destination. She frames science as a pillar of national economic strategy with sovereign capability "now a national priority."',1);
INSERT INTO "position" VALUES(312,'michelle-ananda-rajah-vic','citizenship_eligibility','Born in London, Michelle Ananda-Rajah became an Australian citizen in 1996 and renounced her British citizenship in 2021, resolving her foreign-citizenship status for the purposes of section 44(i) eligibility.',1);
INSERT INTO "position" VALUES(313,'raff-ciccone-vic','foreign_policy','Ciccone is a strong supporter of AUKUS and the Australia-US alliance, stating in an August 2025 piece that "AUKUS represents just one component of our broader defence partnership" resting on shared values and the rules-based order, and projecting it will create around 20,000 jobs. In a March 2026 Senate speech on Iran-Israel escalation he argued "Peace is not maintained by slogans or wishful thinking; it is maintained by strength, alliances and, importantly, deterrence," noted Australia''s military support to the UAE, and accused the Greens of "selective outrage" and an "anti-West and anti-Australia" stance on AUKUS.',1);
INSERT INTO "position" VALUES(314,'raff-ciccone-vic','economic_nationalism','On his official website, Ciccone advocates for Australia building domestic industrial and manufacturing capacity, stating: "Australia must be a country that makes things, to have our own industrial and manufacturing capabilities," and arguing that COVID showed "the need for Australia to be a place which makes things... our own sovereign capabilities." He supports the National Reconstruction Fund to diversify Australia''s industrial base and develop national sovereign capability.',1);
INSERT INTO "position" VALUES(315,'ralph-babet-vic','faith','Wikipedia states plainly that "Babet is Catholic" in the personal life section of his article.',1);
INSERT INTO "position" VALUES(316,'ralph-babet-vic','economic_nationalism','Per a profile of Babet drawing on his August 2022 first speech, he emphasises the importance of Australian superannuation funds being invested locally to boost the domestic economy.',1);
INSERT INTO "position" VALUES(317,'ralph-babet-vic','citizenship_eligibility','Born on Rodrigues in the Republic of Mauritius and an Australian citizen since 1993, Ralph Babet renounced his Mauritian citizenship in March 2022, before taking his Senate seat, to satisfy section 44(i) eligibility.',1);
INSERT INTO "position" VALUES(318,'sarah-henderson-vic','immigration','Henderson opposed the medevac legislation allowing medical transfers of asylum seekers to Australia, saying "there is no need for this bill ... this is all about politics" and that medical treatment was already available on Manus Island and Nauru. She has generally supported the party line on boat turnbacks and offshore processing.',1);
INSERT INTO "position" VALUES(319,'sarah-henderson-vic','economic_nationalism','In her maiden Senate speech (16 October 2019), Henderson stated that Australia''s critical infrastructure assets "such as airports, power stations, data networks, communications infrastructure and ports - including the Port of Darwin - should simply not be falling into foreign hands," and called for foreign investment laws to be re-examined to limit foreign acquisition of prime agricultural land.',1);
INSERT INTO "position" VALUES(320,'steph-hodgins-may-vic','immigration','In her first Senate speech, Hodgins-May criticised "this country''s abhorrent approach to refugees and asylum seekers seeking our protection," cited a record 120 million people forcibly displaced worldwide, and called for "more humility and compassion in our treatment of refugees and asylum seekers" rather than "cruel campaign slogans designed only to scare people and win votes."',1);
INSERT INTO "position" VALUES(321,'steph-hodgins-may-vic','foreign_policy','Hodgins-May is an advocate for Australia increasing its foreign aid budget and placing greater focus on international development. She previously worked in the Australian mission to the United Nations and as Greenpeace''s Head of Pacific, pushing for Australia to do more to help Pacific Island nations facing climate change.',1);
INSERT INTO "position" VALUES(322,'dean-smith-wa','faith','Wikipedia states "He is an Anglican" in the personal life section of Dean Smith''s article.',1);
INSERT INTO "position" VALUES(323,'dean-smith-wa','immigration','In July 2018, Smith called for a national debate on Australia''s population as it reached 25 million, saying issues were broader than immigration alone and included regional growth, congestion and infrastructure. He advocated "moderation" of intake and better forecasting so Australia could "prepare and plan better," suggesting an audit-commission approach or parliamentary inquiry to lead the debate.',1);
INSERT INTO "position" VALUES(324,'ellie-whiteaker-wa','economic_nationalism','According to her Wikipedia article, Whiteaker''s inaugural Senate speech (23 July 2025) highlighted support for policies promoting public sector investment in health care and manufacturing, alongside workers'' rights and gender equality. She is affiliated with the Australian Manufacturing Workers'' Union.',1);
INSERT INTO "position" VALUES(325,'fatima-payman-wa','faith','Wikipedia states "Payman is a Muslim" in the personal life section of her article.',1);
INSERT INTO "position" VALUES(326,'fatima-payman-wa','foreign_policy','In a May 2024 Senate speech Payman accused Israel of committing genocide against Palestinians in Gaza, criticised the Australian government''s response and called for sanctions and divestment against Israel. On 25 June 2024 she crossed the floor to vote for a Greens resolution supporting Australian recognition of Palestinian statehood, after writing on 17 June 2024 that "Australia must recognise Palestine to support peace efforts"; she subsequently left the Labor Party.',1);
INSERT INTO "position" VALUES(327,'fatima-payman-wa','citizenship_eligibility','Born in Kabul, Afghanistan, and naturalised as an Australian citizen in 2005, Fatima Payman was advised she had taken "all reasonable steps" (per Sykes v Cleary) to renounce her Afghan citizenship after a 2021 renunciation request could not be finalised; a November 2024 Senate motion to investigate her section 44 eligibility was defeated 35-3.',1);
INSERT INTO "position" VALUES(328,'glenn-sterle-wa','foreign_policy','In October 2014 Sterle used a Senate speech to condemn fellow Labor MP Melissa Parke''s support for the Boycott, Divestment and Sanctions (BDS) movement, calling on her to "cease her support for divisive campaigns like the BDS movement and support a more constructive dialogue," characterising her stance as "simplistic" and "inflammatory," and reaffirming Labor policy supporting a two-state solution and lasting peace for Israel and Palestine.',1);
INSERT INTO "position" VALUES(329,'jordon-steele-john-wa','immigration','In his maiden Senate speech, Steele-John called for a more humanitarian approach to refugees and asylum seekers, describing the situation on Manus Island as an "ongoing humanitarian crisis" and arguing Australia is "a nation built by those who come across the sea seeking a better life."',1);
INSERT INTO "position" VALUES(330,'jordon-steele-john-wa','foreign_policy','Steele-John, the Greens'' spokesperson for Foreign Affairs and Peace & Nuclear Disarmament, has campaigned to have the government revoke the AUKUS pact and redirect funds to community services. In a November 2021 piece he called to "tear up the AUKUS deal," ratify the nuclear weapons ban treaty, ban the development and sale of weapons including autonomous weapons, close joint military facilities including Pine Gap, oppose framing China as an inevitable enemy, and pursue cooperation and diplomacy. He is co-chair of the Parliamentary Friends of the Treaty on the Prohibition of Nuclear Weapons.',1);
INSERT INTO "position" VALUES(331,'jordon-steele-john-wa','citizenship_eligibility','Born in Northampton, England, Jordon Steele-John held British citizenship from 1994 to 2013 and renounced it at age eighteen in preparation for the 2013 federal election, leaving him solely an Australian citizen for section 44(i) purposes.',1);
INSERT INTO "position" VALUES(332,'matt-o-sullivan-wa','faith','In his 2019 Senate maiden speech, O''Sullivan declared: "My faith is an integral part of my life. I am a Christian, and I believe and affirm the Apostles'' Creed."',1);
INSERT INTO "position" VALUES(333,'michaelia-cash-wa','foreign_policy','As Shadow Minister for Foreign Affairs, Cash affirms ANZUS and the AUKUS submarine pact as enduring alliances and describes the Five Eyes partnership and the Quad as of vital importance (May 2025). On the Middle East she takes a strongly pro-Israel position, in August 2025 calling the Albanese government''s decision to "unilaterally recognise a Palestinian state ahead of a proper peace process" reckless and accusing the government of mismanaging the Australia-Israel relationship.',1);
INSERT INTO "position" VALUES(334,'sue-lines-wa','faith','Senate President Sue Lines has publicly identified as an atheist, stating in 2022 regarding the Lord''s Prayer: "Personally, I would like to see the prayers gone. I''m an atheist. I don''t want to say the prayers."',1);
INSERT INTO "position" VALUES(335,'sue-lines-wa','foreign_policy','Per her Wikipedia article, Lines stated in 2019 at a WA Labor Friends of Palestine launch event that the Israel lobby is "powerful within the party and outside of the party" and influences ALP policy on the Israeli-Palestinian conflict.',1);
INSERT INTO "position" VALUES(336,'varun-ghosh-wa','foreign_policy','In his first Senate speech (25 March 2024) Ghosh stated that "our defence forces, our alliance structures and our diplomatic initiatives all play vital roles in ensuring and maintaining a rules based order in our region and around the world," and highlighted Western Australia''s role as Australia''s Indian Ocean capital, noting Perth is closer to Jakarta than to Canberra.',1);
INSERT INTO "position" VALUES(337,'act-andrew-barr-kurrajong','abortion','Barr voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which allowed nurse practitioners and authorised midwives to prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(338,'act-andrew-barr-kurrajong','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(339,'act-andrew-barr-kurrajong','gender_lgbtq','Stated position and record: Barr is Australia''s first openly gay head of a state or territory government, was a prominent advocate for the ''Yes'' campaign in the 2017 same-sex marriage postal survey, and his government passed the 2020 legislation banning LGBTI conversion practices.',1);
INSERT INTO "position" VALUES(340,'act-andrew-barr-kurrajong','religious_freedom','In the ACT Legislative Assembly debate on the Discrimination Amendment Bill 2022 (23 March 2023), Barr spoke in support of the bill, which narrowed exceptions for religious bodies so that, when providing public goods, services or employment, they may discriminate only on the ground of a person''s religious conviction and not on other protected attributes such as sexuality, gender identity or marital status, while leaving greater freedom for religious observances such as the training and ordination of clergy. This is a stated position and a recorded contribution to debate.',1);
INSERT INTO "position" VALUES(341,'act-andrew-barr-kurrajong','drugs_law_order','Barr supports drug law liberalisation as harm reduction: as Chief Minister he introduced a 2018 bill to legalise personal cannabis cultivation and possession, and in 2021 introduced amendments to decriminalise possession of small quantities of illicit drugs, stating the ''just say no'' approach has not stopped drug use and that the solution lies in health-based harm reduction. (Stated position.)',1);
INSERT INTO "position" VALUES(342,'act-yvette-berry-ginninderra','abortion','Berry voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(343,'act-yvette-berry-ginninderra','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(344,'act-yvette-berry-ginninderra','gender_lgbtq','Recorded vote: as a Labor member present in the Assembly in August 2020, Berry was among the Labor and Greens members who voted to pass the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11), which the Liberals opposed.',1);
INSERT INTO "position" VALUES(345,'act-yvette-berry-ginninderra','education','ACT Deputy Chief Minister and Minister for Education and Early Childhood (education portfolio since 2016). In 2025 she established an independent Expert Panel to review ACT public school system resourcing amid budget pressures, stating ''The review will help us understand how we can achieve equitable resourcing across the ACT public school system to make sure all students are well supported.'' She emphasises the ACT is the only jurisdiction to fund public schools above the national School Resourcing Standard.',1);
INSERT INTO "position" VALUES(346,'act-tara-cheyne-ginninderra','abortion','Cheyne voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(347,'act-tara-cheyne-ginninderra','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes). Cheyne was the minister who introduced the bill.',1);
INSERT INTO "position" VALUES(348,'act-tara-cheyne-ginninderra','gender_lgbtq','Stated position and record: as Human Rights Minister, Cheyne championed the 2024 ACT reforms giving greater choice of gender descriptors on birth certificates, removing the clinical-treatment requirement and lowering the application age, saying the amendments were ''about a person''s fundamental human rights, their identity and being able to express who they are''; she also voted with Labor to pass the 2020 conversion practices ban.',1);
INSERT INTO "position" VALUES(349,'act-tara-cheyne-ginninderra','religious_freedom','As Minister for Human Rights, Cheyne introduced and championed the Discrimination Amendment Bill 2022; in the debate (23 March 2023) she stated the bill amended the exceptions for religious bodies to ''strike a better balance between the right to equality and the right to freedom of thought, conscience, religion and belief,'' citing examples such as prayer groups still being able to exclude people who do not share the relevant religious conviction. This is a stated position and a recorded contribution to debate.',1);
INSERT INTO "position" VALUES(350,'act-tara-cheyne-ginninderra','drugs_law_order','As City and Government Services Minister, Cheyne told the Assembly in December that the territory government was not considering laws to stop medicinal cannabis users from being automatically disqualified from driving, while noting the ACT government ''is closely monitoring the evolving evidence base for driver impairment following tetrahydrocannabinol (THC) intake to inform future considerations.'' (Stated position.)',1);
INSERT INTO "position" VALUES(351,'act-suzanne-orr-yerrabi','abortion','Orr voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(352,'act-suzanne-orr-yerrabi','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(353,'act-suzanne-orr-yerrabi','gender_lgbtq','Recorded vote: as a Labor member present in the Assembly in August 2020, Orr was among the Labor and Greens members who voted to pass the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11), which the Liberals opposed.',1);
INSERT INTO "position" VALUES(354,'act-marisa-paterson-murrumbidgee','abortion','Paterson voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(355,'act-marisa-paterson-murrumbidgee','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(356,'act-marisa-paterson-murrumbidgee','gender_lgbtq','Recorded vote: as a Labor member of the 10th Assembly, Paterson was among the Labor and Greens members who passed the 2024 reforms to the Births, Deaths and Marriages Registration Act (12 to 5), giving greater choice of gender descriptors on birth certificates, removing the clinical-treatment requirement and lowering the application age, which the Liberals opposed.',1);
INSERT INTO "position" VALUES(357,'act-michael-pettersson-yerrabi','abortion','Pettersson voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(358,'act-michael-pettersson-yerrabi','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(359,'act-michael-pettersson-yerrabi','gender_lgbtq','Recorded vote: as a Labor member present in the Assembly in August 2020, Pettersson was among the Labor and Greens members who voted to pass the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11), which the Liberals opposed.',1);
INSERT INTO "position" VALUES(360,'act-michael-pettersson-yerrabi','drugs_law_order','Pettersson authored the private member''s Drugs of Dependence (Personal Use) Amendment Bill 2021 to decriminalise possession of small amounts of illicit drugs, saying ''drug use is a public health issue and I''m glad we are finally treating it like one'' and that ''no-one fixes a drug addiction by going to jail or being put in handcuffs.'' The bill retained criminal penalties for supply, trafficking and manufacture. (Stated position; author of the bill.)',1);
INSERT INTO "position" VALUES(361,'act-chris-steel-murrumbidgee','abortion','Steel voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(362,'act-chris-steel-murrumbidgee','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(363,'act-chris-steel-murrumbidgee','gender_lgbtq','Recorded vote: as a Labor member present in the Assembly in August 2020, Steel was among the Labor and Greens members who voted to pass the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11), which the Liberals opposed. Steel also spoke in support of the bill during the debate.',1);
INSERT INTO "position" VALUES(364,'act-rachel-stephen-smith-kurrajong','abortion','As Health Minister, Stephen-Smith introduced and moved the Health (Improved Abortion Access) Amendment Bill 2024 and voted Aye for it on 25 June 2024, stating in the chamber that ''abortion is an essential feature of an equitable healthcare system'' and that the ACT Labor government ''has been at the forefront of abortion rights and reproductive justice in Australia''; she also confirmed there was no intention to remove the right to conscientious objection.',1);
INSERT INTO "position" VALUES(365,'act-rachel-stephen-smith-kurrajong','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(366,'act-rachel-stephen-smith-kurrajong','gender_lgbtq','Recorded vote: as a Labor member present in the Assembly in August 2020, Stephen-Smith was among the Labor and Greens members who voted to pass the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11), which the Liberals opposed.',1);
INSERT INTO "position" VALUES(367,'act-rachel-stephen-smith-kurrajong','drugs_law_order','As Health Minister, Stephen-Smith backed the 2022 decriminalisation of personal possession of small amounts of illicit drugs, saying the changes ensure people with small amounts for personal use ''are treated with a health response not a criminal one'' and that ''treating drug addiction as a health issue improves outcomes for everyone in the community.'' (Stated position.)',1);
INSERT INTO "position" VALUES(368,'act-rachel-stephen-smith-kurrajong','health','ACT Minister for Health (Barr Labor government). In 2025 released the 2025-2030 ACT Mental Health and Suicide Prevention Regional Plan, signed a new agreement to strengthen primary care, expanded nurse practitioners'' scope of practice via the Nurse Practitioners Legislation Amendment Bill 2025, and established an independent inquiry into health-system data, demand and workforce recruitment/retention.',1);
INSERT INTO "position" VALUES(369,'act-caitlin-tough-brindabella','voluntary_assisted_dying','As ACT Labor candidate for Brindabella in the 2024 election, Tough provided a candidate statement to Canberrans for a Good Death adopting the ACT Labor statement, which expressed support for the ACT''s voluntary assisted dying legislation and noted all ACT Labor MLAs voted in favour of it. (Stated position; she was elected in November 2024 and did not vote on the 2024 Act.)',1);
INSERT INTO "position" VALUES(370,'act-peter-cain-ginninderra','faith','Wikipedia states in its Personal life section that Peter Cain "is a practising Catholic and a vegetarian."',1);
INSERT INTO "position" VALUES(371,'act-peter-cain-ginninderra','abortion','Cain voted No in the ACT Legislative Assembly division of 25 June 2024 against agreeing to the Health (Improved Abortion Access) Amendment Bill 2024, which allowed nurse practitioners and authorised midwives to prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(372,'act-peter-cain-ginninderra','voluntary_assisted_dying','Voted against the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Noes).',1);
INSERT INTO "position" VALUES(373,'act-peter-cain-ginninderra','gender_lgbtq','Recorded vote: as a Liberal member of the 10th Assembly, Cain was part of the Canberra Liberals who opposed the 2024 reforms to the Births, Deaths and Marriages Registration Act (which passed 12 to 5), the party objecting in particular to lowering the age at which a person can apply to change their registered sex.',1);
INSERT INTO "position" VALUES(374,'act-peter-cain-ginninderra','drugs_law_order','As Liberal committee chair, Cain wrote a dissenting report opposing the Drugs of Dependence (Personal Use) Amendment Bill, arguing it would enable ''drug tourism'', conflict with Commonwealth law and burden AFP officers, and that ''drug policy requires a whole-of-government evaluation and response'' rather than a backbencher''s bill. (Stated position; opposed the bill.)',1);
INSERT INTO "position" VALUES(375,'act-leanne-castley-yerrabi','abortion','Castley voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024 (a Canberra Liberals conscience vote), which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(376,'act-leanne-castley-yerrabi','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(377,'act-leanne-castley-yerrabi','gender_lgbtq','Recorded vote: as a Liberal member of the 10th Assembly, Castley was part of the Canberra Liberals who opposed the 2024 reforms to the Births, Deaths and Marriages Registration Act (which passed 12 to 5), the party objecting in particular to lowering the age at which a person can apply to change their registered sex.',1);
INSERT INTO "position" VALUES(378,'act-ed-cocks-murrumbidgee','abortion','Cocks voted No in the ACT Legislative Assembly division of 25 June 2024 against agreeing to the Health (Improved Abortion Access) Amendment Bill 2024, which allowed nurse practitioners and authorised midwives to prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(379,'act-ed-cocks-murrumbidgee','voluntary_assisted_dying','Voted against the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Noes).',1);
INSERT INTO "position" VALUES(380,'act-ed-cocks-murrumbidgee','gender_lgbtq','Recorded vote: as a Liberal member of the 10th Assembly (elected at a 2022 countback), Cocks was part of the Canberra Liberals who opposed the 2024 reforms to the Births, Deaths and Marriages Registration Act (which passed 12 to 5), the party objecting in particular to lowering the age at which a person can apply to change their registered sex.',1);
INSERT INTO "position" VALUES(381,'act-ed-cocks-murrumbidgee','religious_freedom','In a Canberra Daily profile, Cocks listed ''freedom of worship'' among the Liberal values he personally identifies with, naming it alongside freedom of speech, freedom of thought, freedom to own property and freedom to make choices in the market. This is a stated position.',1);
INSERT INTO "position" VALUES(382,'act-jeremy-hanson-murrumbidgee','voluntary_assisted_dying','Voted against the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Noes).',1);
INSERT INTO "position" VALUES(383,'act-jeremy-hanson-murrumbidgee','gender_lgbtq','Stated position and recorded vote: Hanson has publicly stated his support for same-sex marriage (Canberra Times, 4 June 2015); as a Liberal member present in August 2020 he was among the Liberals who opposed the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11).',1);
INSERT INTO "position" VALUES(384,'act-jeremy-hanson-murrumbidgee','religious_freedom','In the Discrimination Amendment Bill 2022 debate (23 March 2023), Hanson said the Canberra Liberals would support the bill, stated that people should be protected from discrimination on the basis of their faith as well as other attributes, noted faith groups remained ''nervous'' about possible unintended consequences, and moved amendments (including on behalf of Elizabeth Lee) seeking a longer commencement period and an objects clause asserting that all human rights are held with equal importance. This reflects stated positions and recorded contributions to debate.',1);
INSERT INTO "position" VALUES(385,'act-jeremy-hanson-murrumbidgee','drugs_law_order','Hanson, as Deputy Liberal Leader, opposed drug decriminalisation, saying ''it''s going to lead to more crime. It''s going to lead to more carnage on our roads.'' He later moved a 2025 Assembly motion to repeal the decriminalisation laws, calling them ''a failed experiment'' that is ''not evidence-based'' and arguing ''the only people that are winning are the drug dealers.'' (Stated position; moved repeal motion.)',1);
INSERT INTO "position" VALUES(386,'act-elizabeth-lee-kurrajong','abortion','Speaking as the Liberal member for Kurrajong on a conscience vote, Lee said ''I support this bill'' and voted Aye on 25 June 2024 for the Health (Improved Abortion Access) Amendment Bill 2024, describing its conscientious-objection referral requirement as a ''sensible amendment''; she is also described as a moderate who supports abortion.',1);
INSERT INTO "position" VALUES(387,'act-elizabeth-lee-kurrajong','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(388,'act-elizabeth-lee-kurrajong','gender_lgbtq','Stated position and recorded vote: Lee is described as a moderate who supports gay marriage (Canberra Times); as a Liberal member present in August 2020 she was among the Liberals who opposed the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11).',1);
INSERT INTO "position" VALUES(389,'act-elizabeth-lee-kurrajong','religious_freedom','In the Discrimination Amendment Bill 2022 debate (23 March 2023), amendments circulated in Elizabeth Lee''s name (moved on her behalf as she was absent) proposed inserting an objects clause stating the indivisibility and universality of human rights and that every person is free and equal in dignity, an extended commencement period, and a club/voluntary-body exception; the objects-clause amendment was put to a division and negatived 7-14. These are recorded proposed amendments attributed to her.',1);
INSERT INTO "position" VALUES(390,'act-elizabeth-lee-kurrajong','drugs_law_order','As Opposition Leader, Lee stated the Canberra Liberals ''remain strongly opposed'' to the drug decriminalisation laws, called them ''bad laws'', and committed that if elected in October 2024 the party would repeal them. She separately said she supported territory rights and did not back the federal Coalition''s attempt to overturn the ACT laws. (Stated position.)',1);
INSERT INTO "position" VALUES(391,'act-james-milligan-yerrabi','abortion','Milligan voted No in the ACT Legislative Assembly division of 25 June 2024 against agreeing to the Health (Improved Abortion Access) Amendment Bill 2024, which allowed nurse practitioners and authorised midwives to prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(392,'act-james-milligan-yerrabi','voluntary_assisted_dying','Voted against the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Noes).',1);
INSERT INTO "position" VALUES(393,'act-james-milligan-yerrabi','gender_lgbtq','Recorded vote: Milligan served in the Assembly from 2016 to October 2020 and was among the Liberals who opposed the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11 in August 2020); he was re-elected in 2024.',1);
INSERT INTO "position" VALUES(394,'act-james-milligan-yerrabi','drugs_law_order','As Shadow Minister for Police and Emergency Services, Milligan opposes drug decriminalisation and supports recriminalisation, citing Oregon: ''in the space of four years, their soft on drugs policy has been a complete and utter disaster.'' He said ''the Canberra Liberals called for the recriminalisation of drugs of dependence, and I stand by that.'' (Stated position.)',1);
INSERT INTO "position" VALUES(395,'act-deborah-morris-brindabella','drugs_law_order','Morris, Deputy Opposition Leader, supports ''tougher sentencing, more police funding, anti-consorting laws and the criminalisation of drug use'', saying ''if you weaken laws that are designed to keep the community safe, a lot of people are going to get hurt, and governments have a responsibility to ensure that that doesn''t happen.'' She has campaigned strongly on crime and law and order. (Stated position.)',1);
INSERT INTO "position" VALUES(396,'act-mark-parton-brindabella','abortion','Parton voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024 (a Canberra Liberals conscience vote), which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(397,'act-mark-parton-brindabella','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(398,'act-mark-parton-brindabella','gender_lgbtq','Recorded vote: as a Liberal member present in August 2020, Parton was among the Liberals who opposed the Sexuality and Gender Identity Conversion Practices Act 2020 (passed 14 to 11).',1);
INSERT INTO "position" VALUES(399,'act-mark-parton-brindabella','drugs_law_order','As Liberal leader, Parton announced in his 2026 budget reply that a Liberal government would recriminalise methamphetamine, describing the existing decriminalisation approach as having ''failed'' and saying ''we will recriminalise meth because we refuse to pretend that a drug causing such serious harm in our community should be treated as just another minor infringement.'' (Stated position.)',1);
INSERT INTO "position" VALUES(400,'act-andrew-braddock-yerrabi','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(401,'act-andrew-braddock-yerrabi','gender_lgbtq','Recorded vote: as an ACT Greens member of the 10th Assembly, Braddock was among the Labor and Greens members who passed the 2024 reforms to the Births, Deaths and Marriages Registration Act (12 to 5), giving greater choice of gender descriptors on birth certificates, removing the clinical-treatment requirement and lowering the application age, which the Liberals opposed.',1);
INSERT INTO "position" VALUES(402,'act-andrew-braddock-yerrabi','religious_freedom','In the Discrimination Amendment Bill 2022 debate (23 March 2023), Braddock (Greens) spoke in support of the bill, applauding the refinement of the Act''s exceptions (including those affecting religious bodies) so that discrimination must be reasonable, proportionate and justifiable, and stated the Greens would oppose the Opposition''s amendment that he said would effectively restore a blanket exemption for clubs to discriminate. This is a stated position and a recorded contribution to debate.',1);
INSERT INTO "position" VALUES(403,'act-andrew-braddock-yerrabi','drugs_law_order','Braddock introduced a private member''s Road Transport (Alcohol and Drugs) Amendment Bill 2026 to remove what he calls ''discriminatory treatment'' of medicinal cannabis users under drug-driving laws, arguing prescribed cannabis users who are not impaired should not be treated differently from prescribed opioid users: ''if you are not impaired, have a valid prescription, and are taking your medication as directed, you should not be treated as a criminal.'' (Stated position; author of the bill.)',1);
INSERT INTO "position" VALUES(404,'act-jo-clay-ginninderra','abortion','Clay voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(405,'act-jo-clay-ginninderra','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes).',1);
INSERT INTO "position" VALUES(406,'act-jo-clay-ginninderra','gender_lgbtq','Recorded vote: as an ACT Greens member of the 10th Assembly, Clay was among the Labor and Greens members who passed the 2024 reforms to the Births, Deaths and Marriages Registration Act (12 to 5), giving greater choice of gender descriptors on birth certificates, removing the clinical-treatment requirement and lowering the application age, which the Liberals opposed.',1);
INSERT INTO "position" VALUES(407,'act-laura-nuttall-brindabella','abortion','Nuttall voted Aye in the ACT Legislative Assembly division of 25 June 2024 to agree to the Health (Improved Abortion Access) Amendment Bill 2024, which expanded who may prescribe abortion medication and required conscientious objectors to provide referral information.',1);
INSERT INTO "position" VALUES(408,'act-laura-nuttall-brindabella','voluntary_assisted_dying','Voted in favour of the Voluntary Assisted Dying Bill 2023, which passed the ACT Legislative Assembly 20 votes to 5 on 5 June 2024 (recorded in the Ayes). Nuttall was an ACT Greens MLA in the Tenth Assembly at the time of the vote.',1);
INSERT INTO "position" VALUES(409,'act-laura-nuttall-brindabella','gender_lgbtq','Recorded vote and action: as an ACT Greens member, Nuttall moved amendments to the 2024 gender-recognition reforms (greater choice of gender descriptors on birth certificates, removing the clinical-treatment requirement and lowering the application age) which were accepted by the ACT Labor Government, and the reforms passed 12 to 5 with the Liberals opposed.',1);
INSERT INTO "position" VALUES(410,'act-fiona-carrick-murrumbidgee','voluntary_assisted_dying','In a candidate statement to Canberrans for a Good Death ahead of the 2024 election, Carrick wrote ''I support Voluntary Assisted Dying, including the current legislation,'' adding any change to the Act''s review timeframe should involve stakeholder and community consultation. (Stated position; she was elected in November 2024 and did not vote on the 2024 Act.)',1);
INSERT INTO "position" VALUES(411,'act-fiona-carrick-murrumbidgee','drugs_law_order','Independent MLA Carrick voted against the Canberra Liberals'' October 2025 motion to repeal the ACT''s drug decriminalisation laws, alongside Labor, the Greens and fellow independent Thomas Emerson; the motion failed. (Recorded vote against repeal.)',1);
INSERT INTO "position" VALUES(412,'act-thomas-emerson-kurrajong','voluntary_assisted_dying','In response to the Canberrans for a Good Death 2024 election candidate survey, Emerson (Independents for Canberra, Kurrajong) answered ''Yes'' to the question ''Do you support VAD'', and supported widening eligibility and a binding advance directive in the next Assembly term. (Stated position; he was elected in November 2024 and did not vote on the 2024 Act.)',1);
INSERT INTO "position" VALUES(413,'act-thomas-emerson-kurrajong','drugs_law_order','Independent MLA Emerson voted against the Canberra Liberals'' October 2025 motion to repeal the ACT''s drug decriminalisation laws, alongside Labor, the Greens and fellow independent Fiona Carrick; the motion failed. (Recorded vote against repeal.)',1);
INSERT INTO "position" VALUES(414,'new-south-wales-jenny-aitchison-maitland','abortion','As a member of the NSW Legislative Assembly, voted in favour of the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(415,'new-south-wales-jenny-aitchison-maitland','voluntary_assisted_dying','Jenny Aitchison voted in favour of (Ayes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(416,'new-south-wales-kevin-anderson-tamworth','abortion','As a member of the NSW Legislative Assembly, voted in favour of the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(417,'new-south-wales-kevin-anderson-tamworth','voluntary_assisted_dying','Kevin Anderson voted in favour of (Ayes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(418,'new-south-wales-edmond-atalla-mount-druitt','faith','Edmond Atalla is of Coptic Orthodox Christian background; he attended the Coptic Orthodox Church in Redfern as a child and is known for advocacy on behalf of Australia''s Coptic community.',1);
INSERT INTO "position" VALUES(419,'new-south-wales-edmond-atalla-mount-druitt','abortion','As a member of the NSW Legislative Assembly, voted against the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(420,'new-south-wales-edmond-atalla-mount-druitt','voluntary_assisted_dying','Edmond Atalla voted against (Noes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(421,'new-south-wales-tina-ayyad-holsworthy','faith','Tina Ayyad is Muslim.',1);
INSERT INTO "position" VALUES(422,'new-south-wales-stephen-bali-blacktown','abortion','As a member of the NSW Legislative Assembly, voted against the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(423,'new-south-wales-stephen-bali-blacktown','voluntary_assisted_dying','Stephen Bali voted against (Noes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(424,'new-south-wales-roy-butler-barwon','voluntary_assisted_dying','Roy Butler voted in favour of (Ayes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(425,'new-south-wales-prue-car-londonderry','abortion','As a member of the NSW Legislative Assembly, voted in favour of the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(426,'new-south-wales-prue-car-londonderry','voluntary_assisted_dying','Prue Car voted in favour of (Ayes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(427,'new-south-wales-prue-car-londonderry','education','NSW Deputy Premier and Minister for Education and Early Learning (since March 2023). Her signature education policy has been addressing the teacher shortage via the largest teacher pay rise in a generation, lifting starting salaries from $75,791 to $85,000 and top-of-scale from $113,042 to $122,100 (October 2023). She framed it as rebuilding public education after the previous Coalition government ''watched on as student outcomes declined and the state was in the grip of a teacher shortage crisis.''',1);
INSERT INTO "position" VALUES(428,'new-south-wales-yasmin-catley-swansea','abortion','As a member of the NSW Legislative Assembly, voted in favour of the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(429,'new-south-wales-yasmin-catley-swansea','voluntary_assisted_dying','Yasmin Catley voted in favour of (Ayes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(430,'new-south-wales-yasmin-catley-swansea','drugs_law_order','Labor Minister for Police and Counter-terrorism. She defended the Government''s 2024 youth bail laws on radio, saying "repeated bail without backup, with no intervention whatsoever, is just a road to ruin." She backed permanent police "wanding" powers to detect knives (commenced December 2024), saying "knife crime devastates families and communities." In the Government''s October 2025 response to the 2024 Drug Summit she said police would "remain focused on disrupting the supply of illicit drugs" while ensuring "diversion opportunities are available."',1);
INSERT INTO "position" VALUES(431,'new-south-wales-anoulack-chanthivong-macquarie-fields','abortion','As a member of the NSW Legislative Assembly, voted in favour of the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(432,'new-south-wales-anoulack-chanthivong-macquarie-fields','voluntary_assisted_dying','Anoulack Chanthivong voted against (Noes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(433,'new-south-wales-anoulack-chanthivong-macquarie-fields','housing_planning','As Minister for Better Regulation and Fair Trading, Chanthivong championed the NSW rental reforms ending no-grounds evictions, saying ''Around a third of the people in NSW rent and they deserve secure and fair housing.'' The reforms require landlords to give a reason to end both periodic and fixed-term tenancies.',1);
INSERT INTO "position" VALUES(434,'new-south-wales-justin-clancy-albury','abortion','As a member of the NSW Legislative Assembly, voted against the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at the second reading (8 Aug 2019) but in favour of the amended bill at the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
INSERT INTO "position" VALUES(435,'new-south-wales-justin-clancy-albury','voluntary_assisted_dying','Justin Clancy voted against (Noes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
