INSERT INTO "position" VALUES(440,'new-south-wales-mark-coure-oatley','abortion','As a member of the NSW Legislative Assembly, voted against the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at the second reading (8 Aug 2019); not recorded in the third reading division.',1);
INSERT INTO "position" VALUES(441,'new-south-wales-mark-coure-oatley','voluntary_assisted_dying','Mark Coure voted in favour of (Ayes) the Voluntary Assisted Dying Bill 2021 at its third reading in the Legislative Assembly on 26 November 2021 (Assembly third reading, which passed 52 votes to 32). The Act was a conscience vote and became the Voluntary Assisted Dying Act 2022 (NSW).',1);
INSERT INTO "position" VALUES(442,'new-south-wales-tim-crakanthorp-newcastle','abortion','As a member of the NSW Legislative Assembly, voted in favour of the Reproductive Health Care Reform Bill 2019 (which became the Abortion Law Reform Act 2019, decriminalising abortion in NSW) at both the second reading (8 Aug 2019) and the third reading (final passage, 8 Aug 2019), on a conscience vote.',1);
