INSERT INTO "position" VALUES(526,'new-south-wales-dugald-saunders-dubbo','drugs_law_order','Nationals MP for Dubbo who has pressed for a tougher law-and-order response to regional youth crime. In February 2025 he said "youth crime isn''t just a Moree problem, it''s a regional NSW problem ... getting worse and worse by the day," and criticised the Government''s youth bail laws as insufficient, noting the Coalition warned the temporary bail laws (extended to 2028) "aren''t enough to solve the regional crime crisis and have proved unsuccessful for the past 12 months."',1);
