INSERT INTO "position" VALUES(784,'queensland-dale-last-burdekin','nuclear','As Mines Minister (LNP), countered Robbie Katter''s 24 June 2026 motion to lift Queensland''s uranium mining ban by moving an amendment that praised the government''s existing energy policies rather than endorsing uranium mining; the amendment passed, keeping the ban in place.',1);
