INSERT INTO "position" VALUES(815,'queensland-tim-nicholls-clayfield','gender_lgbtq','As Health Minister, in January 2025 announced an immediate pause on prescribing puberty blockers (Stage 1) and cross-sex hormones (Stage 2) to new under-18 patients in Queensland public health, citing ''contested evidence''; after a court quashed the directive in October 2025 he reissued it the same day (stated position / ministerial action).',1);
