INSERT INTO "position" VALUES(893,'queensland-shane-knuth-hill','voluntary_assisted_dying','Recorded vote: voted AGAINST the Voluntary Assisted Dying Bill 2021 (all three Katter''s Australian Party members opposed), which nonetheless passed the Queensland Legislative Assembly 61-30 on 16 September 2021 in a conscience vote.',1);
INSERT INTO "position" VALUES(894,'queensland-shane-knuth-hill','religious_freedom','Said in the second reading debate (10 September 2024) that the Bill was "a disgraceful attack on religious-based schools" and a "threat to the fundamental rights of religious institutions", citing ICCPR article 18; voted against the Bill on its third reading.',1);
INSERT INTO "position" VALUES(895,'queensland-shane-knuth-hill','drugs_law_order','As a sitting Katter''s Australian Party member, recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when all LNP, Labor and KAP MPs voted for and only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
