INSERT INTO "position" VALUES(898,'queensland-wayde-chiesa-hinchinbrook','drugs_law_order','LNP member who won the Hinchinbrook by-election on 29 November 2025 (after the December 2024 vote); he campaigned strongly on law and order, stating the LNP''s Adult Crime, Adult Time laws are ''starting to hold youth criminals accountable'' and calling for more police, CCTV and ''tougher bail laws for youth criminals''.',1);
INSERT INTO "position" VALUES(899,'queensland-margie-nightingale-inala','religious_freedom','Voted in favour of the Respect at Work and Other Matters Amendment Bill 2024 on its third reading (10 September 2024). The Bill retained, rather than removed, exemptions allowing faith-based schools and religious bodies to discriminate in employment, after the Labor government withdrew its earlier proposal to narrow them.',1);
