INSERT INTO "position" VALUES(961,'queensland-michael-berkman-maiwar','gender_lgbtq','Greens MP who publicly opposes the 2025 Queensland ban/pause on puberty blockers and hormone therapy for trans minors, stating ''Hormone therapy and puberty blockers save lives'' and that the treatment is lifesaving for young people with gender dysphoria (stated position).',1);
INSERT INTO "position" VALUES(962,'queensland-michael-berkman-maiwar','religious_freedom','Greens MP who criticised the Bill in the second reading debate (10 September 2024) as "watered down" after "Labor caved to pressure from the conservative Christian lobby", objecting that religious institutions including schools remained exempt from anti-discrimination protections; voted in favour of the Bill on its third reading.',1);
