INSERT INTO "position" VALUES(971,'queensland-corrine-mcmillan-mansfield','first_nations','Voted NOE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), opposing the omnibus bill that repealed the Path to Treaty Act 2023 (which ended Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry). The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(972,'queensland-fiona-simpson-maroochydore','abortion','Recorded vote: voted No (against) on the third reading of the Termination of Pregnancy Bill 2018, which decriminalised abortion in Queensland (passed 50-41 on 17 October 2018).',1);
