INSERT INTO "position" VALUES(974,'queensland-fiona-simpson-maroochydore','religious_freedom','Said in the second reading debate (10 September 2024) that Labor "has treated people of faith with contempt" and that she supports faith-based schools'' "right to recruit in alignment with their faith and values"; voted against the Bill on its third reading.',1);
