INSERT INTO "position" VALUES(1012,'queensland-mark-ryan-morayfield','integrity','As shadow minister (former Labor police minister), Ryan spoke on the Crime and Corruption (Restoring Reporting Powers) Amendment Bill 2025 and stated: ''I reiterate the opposition''s support for these public reporting amendments'' restoring the CCC''s power to publicly report on corruption, and ''I encourage all members to do so.'' He raised Labor concerns about unrelated last-minute government amendments (delaying respect-at-work protections) but backed the CCC public-reporting provisions. Bill passed 30 April 2025.',1);
