INSERT INTO "position" VALUES(1057,'queensland-leanne-linard-nudgee','religious_freedom','Voted in favour of the Respect at Work and Other Matters Amendment Bill 2024 on its third reading (10 September 2024). The Bill retained, rather than removed, exemptions allowing faith-based schools and religious bodies to discriminate in employment, after the Labor government withdrew its earlier proposal to narrow them.',1);
INSERT INTO "position" VALUES(1058,'queensland-leanne-linard-nudgee','drugs_law_order','As a sitting Labor member, recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
INSERT INTO "position" VALUES(1059,'queensland-leanne-linard-nudgee','sex_work','Voted YES (Ayes) on the second reading of the Criminal Code (Decriminalising Sex Work) and Other Legislation Amendment Bill 2024, which decriminalised sex work in Queensland. The named division was carried 49–35 on 2 May 2024; Leanne Linard is recorded in the Ayes.',1);
INSERT INTO "position" VALUES(1060,'queensland-leanne-linard-nudgee','first_nations','Voted NOE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), opposing the omnibus bill that repealed the Path to Treaty Act 2023 (which ended Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry). The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(1061,'queensland-amanda-stoker-oodgeroo','faith','Wikipedia states "She is a Christian and attends an Anglican church in inner-city Brisbane," and describes her as a self-described conservative Christian.',1);
INSERT INTO "position" VALUES(1062,'queensland-amanda-stoker-oodgeroo','voluntary_assisted_dying','Stated position: opposes voluntary assisted dying / euthanasia. Stoker (a social conservative) was not in the Queensland Parliament for the 2021 vote, having been a federal Senator at the time, and was elected to the Legislative Assembly in 2024.',1);
INSERT INTO "position" VALUES(1063,'queensland-amanda-stoker-oodgeroo','gender_lgbtq','Has publicly opposed aspects of transgender rights, advocating restricting transgender participation in women''s sport and limiting access to gender-affirming care for children; in 2018 opposed removing religious-school exemptions relating to sexual orientation and gender identity, and has described sexuality as a ''choice'' (stated positions).',1);
INSERT INTO "position" VALUES(1064,'queensland-amanda-stoker-oodgeroo','drugs_law_order','As a sitting LNP member of the Crisafulli Government, recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
