INSERT INTO "position" VALUES(1117,'queensland-john-paul-langbroek-surfers-paradise','education','Queensland Minister for Education and the Arts (LNP) since November 2024. Notable education actions during his tenure: he oversaw Queensland''s first teachers'' strike in 16 years (August 2025), in which more than 50,000 QTU members rejected the government''s proposed 8% pay rise over three years; and (in his Arts capacity) he directed the State Library of Queensland to withdraw a writing fellowship from a First Nations author over a 2024 social-media post, prompting several literary-award judges to resign in protest.',1);
INSERT INTO "position" VALUES(1118,'queensland-mark-boothman-theodore','abortion','Recorded vote: voted No (against) on the third reading of the Termination of Pregnancy Bill 2018, which decriminalised abortion in Queensland (passed 50-41 on 17 October 2018).',1);
