INSERT INTO "position" VALUES(1120,'queensland-mark-boothman-theodore','religious_freedom','As an LNP committee member, said in the second reading debate (10 September 2024) that LNP committee members shared submitters'' concerns, particularly about the undefined term "equitable outcomes" causing uncertainty; voted against the Bill on its third reading.',1);
