INSERT INTO "position" VALUES(1124,'queensland-mark-boothman-theodore','integrity','Boothman (LNP) spoke in support of the Crime and Corruption (Restoring Reporting Powers) Amendment Bill 2025, calling it disappointing that such legislation was needed but condemning the previous Labor government for spending over $300,000 of taxpayers'' money to keep CCC reports about Jackie Trad and Peter Carne secret. He thanked the Attorney-General ''for finally shining a light into a very dodgy era of Queensland politics.''',1);
