INSERT INTO "position" VALUES(1142,'queensland-david-janetzki-toowoomba-south','drugs_law_order','As a senior LNP member of the Crisafulli Government (Treasurer), recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
INSERT INTO "position" VALUES(1143,'queensland-david-janetzki-toowoomba-south','sex_work','Voted NO (Noes) on the second reading of the Criminal Code (Decriminalising Sex Work) and Other Legislation Amendment Bill 2024, opposing decriminalisation of sex work in Queensland. The named division was carried 49–35 on 2 May 2024; David Janetzki is recorded in the Noes.',1);
INSERT INTO "position" VALUES(1144,'queensland-adam-baillie-townsville','drugs_law_order','As a sitting LNP member of the Crisafulli Government, recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
INSERT INTO "position" VALUES(1145,'queensland-adam-baillie-townsville','first_nations','Voted AYE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), the omnibus bill that repealed the Path to Treaty Act 2023, ending Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry. The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(1146,'queensland-robbie-katter-traeger','abortion','Recorded vote: voted No (against) on the third reading of the Termination of Pregnancy Bill 2018, which decriminalised abortion in Queensland (passed 50-41 on 17 October 2018). His party, Katter''s Australian Party, has since promised to bring bills to first amend and then seek to repeal the 2018 decriminalisation.',1);
INSERT INTO "position" VALUES(1147,'queensland-robbie-katter-traeger','voluntary_assisted_dying','Recorded vote: voted AGAINST the Voluntary Assisted Dying Bill 2021 (all three Katter''s Australian Party members opposed), which nonetheless passed the Queensland Legislative Assembly 61-30 on 16 September 2021 in a conscience vote.',1);
INSERT INTO "position" VALUES(1148,'queensland-robbie-katter-traeger','gender_lgbtq','In 2022 moved to legislate banning transgender athletes from women''s sport; his motion on the issue was defeated 49-33, with the LNP opposition voting in favour (stated position / recorded vote on his motion).',1);
INSERT INTO "position" VALUES(1149,'queensland-robbie-katter-traeger','religious_freedom','Voted against the Respect at Work and Other Matters Amendment Bill 2024 on its third reading (10 September 2024). Opposition MPs argued the Bill threatened religious freedom and free speech and did not adequately protect faith-based organisations.',1);
INSERT INTO "position" VALUES(1150,'queensland-robbie-katter-traeger','drugs_law_order','Leader of Katter''s Australian Party; KAP supported and voted for the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on 12 December 2024, and Katter has pushed for tougher youth justice including a ''relocation/bush sentencing'' model sending repeat young offenders to remote rehabilitative facilities.',1);
INSERT INTO "position" VALUES(1151,'queensland-robbie-katter-traeger','sex_work','Voted NO (Noes) on the second reading of the Criminal Code (Decriminalising Sex Work) and Other Legislation Amendment Bill 2024, opposing decriminalisation of sex work in Queensland. The named division was carried 49–35 on 2 May 2024; Robbie Katter is recorded in the Noes.',1);
INSERT INTO "position" VALUES(1152,'queensland-robbie-katter-traeger','first_nations','Voted AYE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), the omnibus bill that repealed the Path to Treaty Act 2023, ending Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry. The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(1153,'queensland-robbie-katter-traeger','nuclear','As KAP leader and Member for Traeger, moved a motion in the Queensland Parliament on 24 June 2026 to end Queensland''s policy of no uranium mining or export, arguing the state''s uranium is a $15–19 billion untapped industry and dismissing opposition as the "antiquated ''No Nukes'' campaign of 30 years ago." The motion was defeated by a government amendment.',1);
INSERT INTO "position" VALUES(1154,'queensland-ann-leahy-warrego','abortion','Recorded vote: voted No (against) on the third reading of the Termination of Pregnancy Bill 2018, which decriminalised abortion in Queensland (passed 50-41 on 17 October 2018).',1);
INSERT INTO "position" VALUES(1155,'queensland-ann-leahy-warrego','voluntary_assisted_dying','Recorded vote: voted AGAINST the Voluntary Assisted Dying Bill 2021, which nonetheless passed the Queensland Legislative Assembly 61-30 on 16 September 2021 in a conscience vote.',1);
INSERT INTO "position" VALUES(1156,'queensland-ann-leahy-warrego','religious_freedom','Voted against the Respect at Work and Other Matters Amendment Bill 2024 on its third reading (10 September 2024). Opposition MPs argued the Bill threatened religious freedom and free speech and did not adequately protect faith-based organisations.',1);
INSERT INTO "position" VALUES(1157,'queensland-ann-leahy-warrego','drugs_law_order','As a sitting LNP member of the Crisafulli Government, recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
INSERT INTO "position" VALUES(1158,'queensland-ann-leahy-warrego','sex_work','Voted NO (Noes) on the second reading of the Criminal Code (Decriminalising Sex Work) and Other Legislation Amendment Bill 2024, opposing decriminalisation of sex work in Queensland. The named division was carried 49–35 on 2 May 2024; Ann Leahy is recorded in the Noes.',1);
INSERT INTO "position" VALUES(1159,'queensland-ann-leahy-warrego','first_nations','Voted AYE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), the omnibus bill that repealed the Path to Treaty Act 2023, ending Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry. The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(1160,'queensland-shannon-fentiman-waterford','abortion','Recorded vote: voted Aye (in favour) on the third reading of the Termination of Pregnancy Bill 2018, which decriminalised abortion in Queensland (passed 50-41 on 17 October 2018).',1);
INSERT INTO "position" VALUES(1161,'queensland-shannon-fentiman-waterford','voluntary_assisted_dying','Recorded vote: voted FOR the Voluntary Assisted Dying Bill 2021, which passed the Queensland Legislative Assembly 61-30 on 16 September 2021 in a conscience vote.',1);
INSERT INTO "position" VALUES(1162,'queensland-shannon-fentiman-waterford','gender_lgbtq','Recorded as supporting transgender rights and opposed to the gender-critical movement; as Child Safety Minister championed 2016 legislation allowing same-sex couples to adopt (stated position). (As Attorney-General she also introduced the Births, Deaths and Marriages Registration Bill in late 2022, though this specific detail was not on the fetched source.)',1);
INSERT INTO "position" VALUES(1163,'queensland-shannon-fentiman-waterford','religious_freedom','Voted in favour of the Respect at Work and Other Matters Amendment Bill 2024 on its third reading (10 September 2024). The Bill retained, rather than removed, exemptions allowing faith-based schools and religious bodies to discriminate in employment, after the Labor government withdrew its earlier proposal to narrow them.',1);
INSERT INTO "position" VALUES(1164,'queensland-shannon-fentiman-waterford','drugs_law_order','As a sitting Labor member (former Attorney-General and Health Minister), recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
INSERT INTO "position" VALUES(1165,'queensland-shannon-fentiman-waterford','sex_work','Voted YES (Ayes) on the second reading of the Criminal Code (Decriminalising Sex Work) and Other Legislation Amendment Bill 2024, which decriminalised sex work in Queensland. The named division was carried 49–35 on 2 May 2024; Shannon Fentiman is recorded in the Ayes.',1);
INSERT INTO "position" VALUES(1166,'queensland-shannon-fentiman-waterford','first_nations','Voted NOE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), opposing the omnibus bill that repealed the Path to Treaty Act 2023 (which ended Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry). The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(1167,'queensland-amanda-camm-whitsunday','voluntary_assisted_dying','Recorded vote: voted AGAINST the Voluntary Assisted Dying Bill 2021, which nonetheless passed the Queensland Legislative Assembly 61-30 on 16 September 2021 in a conscience vote.',1);
INSERT INTO "position" VALUES(1168,'queensland-amanda-camm-whitsunday','religious_freedom','Voted against the Respect at Work and Other Matters Amendment Bill 2024 on its third reading (10 September 2024). Opposition MPs argued the Bill threatened religious freedom and free speech and did not adequately protect faith-based organisations.',1);
INSERT INTO "position" VALUES(1169,'queensland-amanda-camm-whitsunday','drugs_law_order','LNP minister in the Crisafulli Government; recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
INSERT INTO "position" VALUES(1170,'queensland-amanda-camm-whitsunday','sex_work','Voted NO (Noes) on the second reading of the Criminal Code (Decriminalising Sex Work) and Other Legislation Amendment Bill 2024, opposing decriminalisation of sex work in Queensland. The named division was carried 49–35 on 2 May 2024; Amanda Camm is recorded in the Noes.',1);
INSERT INTO "position" VALUES(1171,'queensland-amanda-camm-whitsunday','first_nations','Voted AYE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), the omnibus bill that repealed the Path to Treaty Act 2023, ending Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry. The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(1172,'queensland-cameron-dick-woodridge','abortion','Recorded vote: voted Aye (in favour) on the third reading of the Termination of Pregnancy Bill 2018, which decriminalised abortion in Queensland (passed 50-41 on 17 October 2018).',1);
INSERT INTO "position" VALUES(1173,'queensland-cameron-dick-woodridge','voluntary_assisted_dying','Recorded vote: voted FOR the Voluntary Assisted Dying Bill 2021, which passed the Queensland Legislative Assembly 61-30 on 16 September 2021 in a conscience vote.',1);
INSERT INTO "position" VALUES(1174,'queensland-cameron-dick-woodridge','religious_freedom','Voted in favour of the Respect at Work and Other Matters Amendment Bill 2024 on its third reading (10 September 2024). The Bill retained, rather than removed, exemptions allowing faith-based schools and religious bodies to discriminate in employment, after the Labor government withdrew its earlier proposal to narrow them.',1);
INSERT INTO "position" VALUES(1175,'queensland-cameron-dick-woodridge','drugs_law_order','As a sitting Labor member (former Treasurer), recorded as voting in favour of the Making Queensland Safer Bill 2024 (Adult Crime, Adult Time) on its passage on 12 December 2024, when only Greens MP Michael Berkman and independent Sandy Bolton voted against.',1);
INSERT INTO "position" VALUES(1176,'queensland-cameron-dick-woodridge','sex_work','Voted YES (Ayes) on the second reading of the Criminal Code (Decriminalising Sex Work) and Other Legislation Amendment Bill 2024, which decriminalised sex work in Queensland. The named division was carried 49–35 on 2 May 2024; Cameron Dick is recorded in the Ayes.',1);
INSERT INTO "position" VALUES(1177,'queensland-cameron-dick-woodridge','first_nations','Voted NOE on the second reading of the Brisbane Olympic and Paralympic Games Arrangements and Other Legislation Amendment Bill 2024 (28 November 2024), opposing the omnibus bill that repealed the Path to Treaty Act 2023 (which ended Queensland''s First Nations Treaty Institute and Truth-telling and Healing Inquiry). The bill passed 53 to 35.',1);
INSERT INTO "position" VALUES(1178,'south-australia-cory-bernardi-statewide','faith','Bernardi is described as a conservative Catholic; in his 2006 Senate maiden speech he pledged to be guided by Judeo-Christian principles.',1);
INSERT INTO "position" VALUES(1179,'south-australia-cory-bernardi-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly.',1);
INSERT INTO "position" VALUES(1180,'south-australia-cory-bernardi-statewide','gender_lgbtq','One Nation MLC and party state leader; former Liberal senator. A long-standing opponent of same-sex marriage: in a federal speech he linked redefining marriage to bestiality, and in 2026 said he stands by those comments ''100 per cent.'' In his SA maiden speech to the Legislative Council on 20 May 2026 he criticised gender-affirming healthcare, stating ''the government allows doctors to mutilate children in the name of gender-affirming care,'' prompting Greens MLCs to walk out.',1);
INSERT INTO "position" VALUES(1181,'south-australia-cory-bernardi-statewide','religious_freedom','Bernardi has a long record advocating freedom of conscience and warning of risks to religious freedom. In July 2019, as a federal Senator for SA, he tabled an ''Australian Freedoms Bill'' intended to ''ring-fence Australia''s key freedoms'', and warned that a religious freedom act, ''unless handled carefully, gravely risks a slippery slope towards blasphemy laws.''',1);
INSERT INTO "position" VALUES(1182,'south-australia-emily-bourke-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly. Also voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1183,'south-australia-emily-bourke-statewide','voluntary_assisted_dying','Voted in favour (Aye) of the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021, which passed 14 votes to 7.',1);
INSERT INTO "position" VALUES(1184,'south-australia-nicola-centofanti-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly. Also voted in favour of Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1185,'south-australia-nicola-centofanti-statewide','voluntary_assisted_dying','Voted against (Noe) the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021 (the bill passed 14 votes to 7).',1);
INSERT INTO "position" VALUES(1186,'south-australia-nicola-centofanti-statewide','religious_freedom','Centofanti, Liberal Leader in the Legislative Council, states on her official website: ''I believe in the fundamental rights and freedoms of every person, including the freedom of thought, speech, worship and association.'' She opposed the Conversion Practices Prohibition Bill 2024, questioning its necessity (a Liberal conscience vote).',1);
INSERT INTO "position" VALUES(1187,'south-australia-nicola-centofanti-statewide','hunting','Liberal MLC (Opposition Leader in the Council) and member of the SA Select Committee on Hunting of Native Birds, which recommended duck hunting continue. She was among committee members who attended a pro-hunting event organised by hunters'' lobby group CHASA and expressed support for hunting.',1);
INSERT INTO "position" VALUES(1188,'south-australia-mira-el-dannawi-statewide','faith','Wikipedia records El Dannawi as the first Muslim member of the South Australian Parliament.',1);
INSERT INTO "position" VALUES(1189,'south-australia-mira-el-dannawi-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly. Also voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1190,'south-australia-sarah-game-statewide','faith','Sarah Game has Jewish heritage and was confirmed Catholic, but has stated ''my values are Christian, [but] I don''t align myself now with any particular religion''; she chose to make an affirmation rather than a religious oath when sworn into the Legislative Council.',1);
INSERT INTO "position" VALUES(1191,'south-australia-sarah-game-statewide','abortion','Introduced (as Family First MLC) the 2026 bill to restrict access to late-term abortions and voted for it in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly. Also voted in favour of Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024; she had earlier introduced her own 2025 restriction bill.',1);
INSERT INTO "position" VALUES(1192,'south-australia-sarah-game-statewide','gender_lgbtq','Legislative Council member (elected for One Nation in 2022; in 2026 announced she would join the Family First Party). Per her Wikipedia profile she has stated she ''does not hold to strict interpretations of complex personal issues relating to abortion and transgender issues,'' indicating a non-dogmatic stance; no detailed voting record on LGBTQ/gender bills is documented in the sourced material reviewed.',1);
INSERT INTO "position" VALUES(1193,'south-australia-sarah-game-statewide','hunting','Family First (elected One Nation) MLC and member of the SA Select Committee on Hunting of Native Birds, which recommended duck hunting continue. She was among committee members who attended a pro-hunting event organised by hunters'' lobby group CHASA and expressed support for hunting.',1);
INSERT INTO "position" VALUES(1194,'south-australia-heidi-girolamo-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly. Also voted in favour of Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1195,'south-australia-hilton-gumbys-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly.',1);
INSERT INTO "position" VALUES(1196,'south-australia-justin-hanson-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly. Also voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1197,'south-australia-justin-hanson-statewide','voluntary_assisted_dying','Voted in favour (Aye) of the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021, which passed 14 votes to 7.',1);
INSERT INTO "position" VALUES(1198,'south-australia-laura-henderson-statewide','abortion','On 17 June 2026 was paired in favour of Sarah Game''s late-term abortion restriction bill in the Legislative Council, her vote paired against Michelle Lensink''s vote opposing it. Also voted in favour of Liberal MLC Ben Hood''s 2024 amendment bill, defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1199,'south-australia-laura-henderson-statewide','gender_lgbtq','Liberal MLC. In the Legislative Council on 24 September 2024 she spoke against the Conversion Practices Prohibition Bill 2024 (a conscience vote for the Liberal Party), calling it ''incredible overreach into the personal lives of people in this state'' and arguing ''it is not for us as a parliament to tell parents what conversations they can and cannot have.'' She raised concerns about the bill''s definitions and parental rights.',1);
INSERT INTO "position" VALUES(1200,'south-australia-laura-henderson-statewide','religious_freedom','In the Legislative Council on the Conversion Practices Prohibition Bill 2024 (a Liberal conscience vote) Henderson spoke against the bill, raising religious-freedom concerns including that religious schools might lack protection for expressing biblical viewpoints on sexuality.',1);
INSERT INTO "position" VALUES(1201,'south-australia-rebecca-hewett-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly.',1);
INSERT INTO "position" VALUES(1202,'south-australia-ben-hood-statewide','abortion','Introduced the 2024 Termination of Pregnancy (Terminations and Live Births) Amendment Bill (defeated in the Legislative Council 10 votes to 9 in October 2024) and voted for it. Also voted in favour of Sarah Game''s 2026 late-term abortion restriction bill in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly.',1);
INSERT INTO "position" VALUES(1203,'south-australia-ben-hood-statewide','hunting','Liberal MLC and member of the SA Select Committee on Hunting of Native Birds, which recommended duck hunting continue. He was among committee members who attended a pro-hunting event organised by hunters'' lobby group CHASA and expressed support for hunting.',1);
INSERT INTO "position" VALUES(1204,'south-australia-dennis-hood-statewide','faith','Hood converted to Christianity at age 19 and continues to attend church regularly; he is identified as a Baptist and has referred to his Christian convictions in relation to his political positions.',1);
INSERT INTO "position" VALUES(1205,'south-australia-dennis-hood-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly.',1);
INSERT INTO "position" VALUES(1206,'south-australia-dennis-hood-statewide','voluntary_assisted_dying','Voted against (Noe) the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021 (the bill passed 14 votes to 7).',1);
INSERT INTO "position" VALUES(1207,'south-australia-dennis-hood-statewide','religious_freedom','Hood has a record of supporting faith-based exemptions and religious observance. In 2007 he defended prayer in parliament; in 2009 he rejected the Greens'' call to name religious schools that discriminate on sexual orientation; and in 2016 he proposed an amendment allowing medical professionals to refuse reproductive assistance on conscientious-objection grounds.',1);
INSERT INTO "position" VALUES(1208,'south-australia-dennis-hood-statewide','drugs_law_order','Hood has a long, publicly documented record opposing drug liberalisation and favouring enforcement. He has praised abstinence-based drug policy, pushed for tougher cannabis penalties (proposing in 2013 raising maximum fines for small grows), opposed medicinal cannabis arguing ''the harm outweighs the therapeutic benefits,'' and advocated minimum sentences for repeat offenders.',1);
INSERT INTO "position" VALUES(1209,'south-australia-ian-hunter-statewide','faith','Hunter is an atheist; he contributed a chapter titled ''Parliament and Prayer'' to the 2010 Australian Book of Atheism and has publicly described opening parliament with prayer as archaic.',1);
INSERT INTO "position" VALUES(1210,'south-australia-ian-hunter-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly. Also voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1211,'south-australia-ian-hunter-statewide','voluntary_assisted_dying','Voted in favour (Aye) of the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021, which passed 14 votes to 7.',1);
INSERT INTO "position" VALUES(1212,'south-australia-ian-hunter-statewide','gender_lgbtq','Long-serving Labor MLC and the first openly gay/LGBTI member of the SA Parliament and Cabinet. A prominent same-sex marriage advocate: delivered a 2009 parliamentary speech calling for marriage equality and co-sponsored a 2011 Marriage Equality Bill with Greens MLC Tammy Franks, at one point calling Labor''s then-policy on marriage ''morally bankrupt''. He married his partner overseas before Australian law recognised same-sex marriage. In Nov 2023 he spoke in the Legislative Council relaying a survivor''s account in support of banning conversion practices.',1);
INSERT INTO "position" VALUES(1213,'south-australia-ian-hunter-statewide','religious_freedom','Hunter, an atheist, has advocated secular reform, repeatedly calling for the removal of prayers from the opening of parliament, and in late 2023 called for South Australia to ban conversion practices in step with other states.',1);
INSERT INTO "position" VALUES(1214,'south-australia-ian-hunter-statewide','hunting','Labor MLC and former minister who signed off on hunting seasons 2013-2018. As a member of the SA Select Committee on Hunting of Native Birds he dissented from the majority recommendation, attaching a statement that duck hunting ''necessarily means supporting deliberate cruelty to animals'' and declaring that ''Duck and quail hunting in South Australia should be made illegal.''',1);
INSERT INTO "position" VALUES(1215,'south-australia-michelle-lensink-statewide','abortion','On 17 June 2026 was paired against Sarah Game''s late-term abortion restriction bill in the Legislative Council (absent due to illness), with her vote paired against Laura Henderson''s vote in favour. In October 2024 she was recorded as opposing Liberal MLC Ben Hood''s amendment bill (absent on medical leave during the 10-9 division but counted as against it).',1);
INSERT INTO "position" VALUES(1216,'south-australia-michelle-lensink-statewide','voluntary_assisted_dying','Voted in favour (Aye) of the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021, which passed 14 votes to 7.',1);
INSERT INTO "position" VALUES(1217,'south-australia-michelle-lensink-statewide','religious_freedom','Lensink, a Liberal MLC, spoke in the Legislative Council on 24 September 2024 to support the Conversion Practices Prohibition Bill 2024, saying ''I rise to indicate that I will be supporting this legislation'' and that she would not support amendments to it.',1);
INSERT INTO "position" VALUES(1218,'south-australia-kyam-maher-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly. Also voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1219,'south-australia-kyam-maher-statewide','voluntary_assisted_dying','As Shadow Attorney-General and Labor Leader in the Legislative Council, Kyam Maher introduced the Voluntary Assisted Dying Bill in December 2020 and voted in favour of it at the final reading in the SA Legislative Council on 5 May 2021 (which passed 14 votes to 7).',1);
INSERT INTO "position" VALUES(1220,'south-australia-kyam-maher-statewide','gender_lgbtq','Labor MLC and Attorney-General. Drafted the Conversion Practices Prohibition Bill 2024, the Malinauskas Government''s legislation banning LGBTIQ conversion practices (passed October 2024, effective 1 April 2025). Publicly described conversion practices as ''a damaging practice that seeks to force members of the LGBTIQ community to abandon who they are under the guise of "saving" or "helping" them.''',1);
INSERT INTO "position" VALUES(1221,'south-australia-kyam-maher-statewide','first_nations','As South Australian Attorney-General and Minister for Aboriginal Affairs (and the first Indigenous person to hold the AG role in Australia), championed the First Nations Voice Act 2023, which created Australia''s first legislated Indigenous Voice to Parliament. Remained strongly committed to it after the 2023 federal referendum defeat: "It''s almost taken on a greater importance, because this is what we''ve got to hold onto," and pledged to restart SA''s treaty process.',1);
INSERT INTO "position" VALUES(1222,'south-australia-reggie-martin-statewide','abortion','Voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1223,'south-australia-reggie-martin-statewide','hunting','Labor MLC who moved for and chaired the SA Legislative Council Select Committee on the Hunting of Native Birds (report tabled Dec 2023). As presiding member he delivered the committee''s majority report recommending that duck/native bird hunting be allowed to continue in South Australia (with tightened regulations).',1);
INSERT INTO "position" VALUES(1224,'south-australia-tung-ngo-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly. Also voted in favour of Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1225,'south-australia-tung-ngo-statewide','voluntary_assisted_dying','Voted against (Noe) the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021 (the bill passed 14 votes to 7).',1);
INSERT INTO "position" VALUES(1226,'south-australia-carlos-quaremba-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly.',1);
INSERT INTO "position" VALUES(1227,'south-australia-clare-scriven-statewide','abortion','Voted in favour of Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026, where it passed 10 votes to 9 before being defeated in the House of Assembly. Also voted in favour of Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1228,'south-australia-clare-scriven-statewide','voluntary_assisted_dying','Voted against (Noe) the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021 (the bill passed 14 votes to 7). Ahead of the vote she told InDaily, ''there is clear evidence that safeguards are ignored or diluted in practice once voluntary euthanasia becomes legal... I will not be supporting the bill.''',1);
INSERT INTO "position" VALUES(1229,'south-australia-melanie-selwood-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly.',1);
INSERT INTO "position" VALUES(1230,'south-australia-melanie-selwood-statewide','gender_lgbtq','Greens MLC elected at the March 2026 state election. On 20 May 2026 she walked out of the Legislative Council, alongside fellow Greens MLC Robert Simms, during One Nation MLC Cory Bernardi''s maiden speech in protest at his comments about transgender people and gender-affirming healthcare. She has aligned with the Greens'' platform of advancing LGBTIQ+ rights and accessible gender-affirming healthcare.',1);
INSERT INTO "position" VALUES(1231,'south-australia-robert-simms-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly. Also voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1232,'south-australia-robert-simms-statewide','voluntary_assisted_dying','Voted in favour (Aye) of the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021, which passed 14 votes to 7.',1);
INSERT INTO "position" VALUES(1233,'south-australia-robert-simms-statewide','gender_lgbtq','Greens MLC and SA Greens leader; openly gay and the first out gay man to represent SA in federal parliament. Long-standing LGBTIQ advocate: as a federal senator was Greens spokesperson on marriage equality; in SA has introduced birth-certificate reform for rainbow families and a bill to remove religious exemptions from anti-discrimination laws, and supported the 2024 conversion practices ban (moving amendments with Tammy Franks). On 20 May 2026 he walked out of the Legislative Council during One Nation MLC Cory Bernardi''s maiden speech over Bernardi''s remarks on transgender people and gender-affirming care.',1);
INSERT INTO "position" VALUES(1234,'south-australia-robert-simms-statewide','religious_freedom','On 28 August 2024 Greens MLC Simms introduced the Equal Opportunity (Religious Bodies) Amendment Bill into the Legislative Council, seeking to remove exemptions in the Equal Opportunity Act that allow religious bodies such as schools and welfare providers to discriminate on grounds including sexual orientation and gender identity.',1);
INSERT INTO "position" VALUES(1235,'south-australia-russell-wortley-statewide','abortion','Voted against Sarah Game''s bill to restrict access to late-term abortions in the Legislative Council on 17 June 2026; the bill passed the upper house 10 votes to 9 but was later defeated in the House of Assembly. Also voted against Liberal MLC Ben Hood''s 2024 Termination of Pregnancy amendment bill, which was defeated in the Legislative Council 10 votes to 9 in October 2024.',1);
INSERT INTO "position" VALUES(1236,'south-australia-russell-wortley-statewide','voluntary_assisted_dying','Voted in favour (Aye) of the Voluntary Assisted Dying Bill at its final reading in the SA Legislative Council on 5 May 2021, which passed 14 votes to 7.',1);
INSERT INTO "position" VALUES(1237,'south-australia-james-agness-light','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1238,'south-australia-sarah-andrews-gibson','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1239,'south-australia-jack-batty-bragg','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1240,'south-australia-jack-batty-bragg','drugs_law_order','Batty, Shadow Minister for Community Safety, Police and Corrections, has campaigned on tough bail and sentencing. In February 2025 he announced Liberal legislation for a mandatory minimum six-month sentence for assaulting police (''If you assault a police officer, you will go to jail''), and in January 2026 backed a ''Break bail, face jail'' presumption against bail for serious repeat offenders.',1);
INSERT INTO "position" VALUES(1241,'south-australia-lawrence-ben-enfield','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1242,'south-australia-zoe-bettison-ramsay','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1243,'south-australia-aria-bolkus-colton','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1244,'south-australia-blair-boyer-wright','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1245,'south-australia-blair-boyer-wright','gender_lgbtq','In March 2026 Boyer publicly criticised the SA Liberal Party over a preselected candidate who had made anti-LGBTIQ statements, calling the preselection ''shambolic'' and the candidate''s views ''shocking'' and ''extreme''.',1);
INSERT INTO "position" VALUES(1246,'south-australia-blair-boyer-wright','health','SA Minister for Health and Wellbeing (Malinauskas Labor government), appointed after the March 2026 state election, taking the portfolio from Chris Picton. On ambulance ramping he said ''we always want to see ramping hours decrease, and we are investing in every way possible to help drive that number down'' and acknowledged Labor ''didn''t achieve what we said we wanted to'' on its 2022 pledge to end ramping, while committing to reduce it ''as far as we can.'' The government accepted 17 of 18 recommendations from a coronial inquest into ramping and cites a health budget grown from $7.3bn (2021) to over $11bn (2026).',1);
INSERT INTO "position" VALUES(1247,'south-australia-blair-boyer-wright','education','SA Minister for Education, Training and Skills (2022-2026). His signature policy was the ''off and away'' ban on mobile phones in all South Australian public high schools, rolled out through 2023 across all 131 schools with secondary enrolments. He defended it saying ''I knew this was the right policy for our high schools as I had seen up close the damage that distraction and cyber bullying was causing at school'' and that bullying can be ''24/7 for young people today,'' citing preliminary data showing reduced violence and phone-based bullying incidents.',1);
INSERT INTO "position" VALUES(1248,'south-australia-geoff-brock-stuart','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1249,'south-australia-michael-brown-florey','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1250,'south-australia-nick-champion-taylor','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1251,'south-australia-nadia-clancy-elder','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1252,'south-australia-nadia-clancy-elder','gender_lgbtq','In a 20 August 2025 parliamentary speech marking 50 years since SA decriminalised homosexuality, Clancy said the conversion-practices ban ''sends a clear message to all South Australians of diverse genders and sexualities: you are not broken, you do not need fixing, and you are loved and valued for who you are.''',1);
INSERT INTO "position" VALUES(1253,'south-australia-nat-cook-hurtle-vale','abortion','As Speaker of the House of Assembly did not vote on Sarah Game''s June 2026 late-term abortion restriction bill, but publicly welcomed its defeat, posting that ''tonight the South Australian Parliament voted for unchanged access to Abortion''; she had earlier been involved in the campaign to decriminalise abortion in South Australia in 2021.',1);
INSERT INTO "position" VALUES(1254,'south-australia-nat-cook-hurtle-vale','gender_lgbtq','Labor MP for Hurtle Vale (elected Speaker of the House of Assembly in May 2026, sitting as independent in that role). As Shadow Human Services Minister she drafted private legislation to outlaw LGBTIQ conversion therapy in SA (reported July 2020), proposing penalties of up to eight years'' imprisonment, an early step toward what became the Conversion Practices Prohibition Act 2024. As Human Services Minister she engaged extensively with LGBTIQ policy, including implementation of the 2024 conversion practices ban.',1);
INSERT INTO "position" VALUES(1255,'south-australia-nat-cook-hurtle-vale','drugs_law_order','Cook is an anti-violence campaigner who entered public life after her 17-year-old son Sam Davis was killed in a one-punch attack in 2008. She and her partner founded the Sammy D Foundation, which runs anti-violence school programs for young people; she stood down from its board on election to Parliament.',1);
INSERT INTO "position" VALUES(1256,'south-australia-alex-dighton-black','faith','In his February 2025 first speech, Dighton spoke of his Catholic faith, recounting that his family regularly attended Sunday Mass at St Joseph''s Kingswood, that he was educated at Cabra Dominican College, and that he continues to celebrate Mass in the Cabra Chapel community.',1);
INSERT INTO "position" VALUES(1257,'south-australia-alex-dighton-black','abortion','Did not vote on Sarah Game''s June 2026 late-term abortion restriction bill in the House of Assembly as he was on paternity leave.',1);
INSERT INTO "position" VALUES(1258,'south-australia-travis-fatchen-mount-gambier','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1259,'south-australia-katrine-hildyard-reynell','faith','Hildyard is a practising Catholic, per her Wikipedia biography which cites her 2014 first speech in the South Australian Hansard.',1);
INSERT INTO "position" VALUES(1260,'south-australia-katrine-hildyard-reynell','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1261,'south-australia-katrine-hildyard-reynell','gender_lgbtq','As Minister, Hildyard announced an $80,000 South Australian government commitment to the Adelaide Pride March at the 2026 SA Pride Gala on 6 June 2026.',1);
INSERT INTO "position" VALUES(1262,'south-australia-lucy-hood-adelaide','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1263,'south-australia-eddie-hughes-giles','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1264,'south-australia-tom-koutsantonis-west-torrens','faith','Tom Koutsantonis identifies with the Greek Orthodox faith, stating ''The Orthodox Church and the Parish of Saint George is a constant in my family''s life,'' and has publicly described St George Orthodox Church as a spiritual home and beacon of faith.',1);
INSERT INTO "position" VALUES(1265,'south-australia-tom-koutsantonis-west-torrens','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1266,'south-australia-tom-koutsantonis-west-torrens','gender_lgbtq','During 2012 South Australian parliamentary debate, Koutsantonis stated his belief that marriage should be between a man and a woman, opposing same-sex marriage while supporting civil unions and legal rights for same-sex couples.',1);
INSERT INTO "position" VALUES(1267,'south-australia-peter-malinauskas-croydon','faith','Malinauskas identifies as Catholic; he comes from a Catholic family, was educated at the Catholic Mercedes College, and has publicly described his Catholic faith as important to him.',1);
INSERT INTO "position" VALUES(1268,'south-australia-peter-malinauskas-croydon','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1269,'south-australia-peter-malinauskas-croydon','gender_lgbtq','As Premier, Malinauskas leads the Labor government that passed the Conversion Practices Prohibition Act 2024. Reflecting on 50 years since SA decriminalised homosexuality, he said ''we have come a long way, the march of progress is on the side of decency of love,'' and tasked Ian Hunter with chairing the commemorative committee.',1);
INSERT INTO "position" VALUES(1270,'south-australia-peter-malinauskas-croydon','drugs_law_order','As Premier, Malinauskas led the Labor government''s 2025 knife crime package, reported as among the toughest knife laws in the country: expanded police wanding-search powers at shopping centres, public transport and licensed venues, a ban on knife sales to minors, secure-storage requirements for certain knives in stores, and extended public knife-carry bans to childcare centres, universities and TAFE campuses. He said that ''while there are legitimate reasons to own a knife, recent events both locally and interstate have highlighted the need for us to crack down on potential knife crime.''',1);
INSERT INTO "position" VALUES(1271,'south-australia-peter-malinauskas-croydon','first_nations','As Premier, his government legislated and implemented South Australia''s First Nations Voice to Parliament (First Nations Voice Act 2023), the nation''s first, and pledged to restart treaty talks. He also supported the 2023 federal Indigenous Voice referendum during his premiership.',1);
INSERT INTO "position" VALUES(1272,'south-australia-matthew-marozzi-morialta','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1273,'south-australia-jenni-mitton-mawson','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1274,'south-australia-cressida-o-hanlon-dunstan','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1275,'south-australia-john-fulbrook-playford','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1276,'south-australia-ashton-hurn-schubert','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1277,'south-australia-ashton-hurn-schubert','drugs_law_order','As South Australian Liberal leader, Ashton Hurn identified tackling crime as one of her top priorities ahead of the 2026 state election, citing concerns such as home invasions and business vandalism. Her party''s law-and-order platform included proposed "break bail, face jail" laws.',1);
INSERT INTO "position" VALUES(1278,'south-australia-catherine-hutchesson-waite','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1279,'south-australia-lou-nicholson-finniss','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1280,'south-australia-david-paton-ngadjuri','faith','Paton has publicly said his Christian faith was integral to his recovery after two near-fatal cycling accidents.',1);
INSERT INTO "position" VALUES(1281,'south-australia-david-paton-ngadjuri','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1282,'south-australia-rhiannon-pearce-king','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1283,'south-australia-rhiannon-pearce-king','drugs_law_order','As Minister for Correctional Services, Pearce''s office stated in November 2025 that South Australia has the lowest recidivism rate in the nation, attributing this partly to employment programs (Work Ready, Release Ready) and funding for drug and alcohol support for former detainees.',1);
INSERT INTO "position" VALUES(1284,'south-australia-chris-picton-kaurna','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1285,'south-australia-chris-picton-kaurna','gender_lgbtq','As Health Minister, Picton said on gender-affirming healthcare for trans young people that ''medical decisions should be made by doctors, not by politicians,'' pointing to reviews in NSW and Queensland that found such services safe and evidence-based, and committing to consider the national NHMRC review.',1);
INSERT INTO "position" VALUES(1286,'south-australia-toby-priest-morphett','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1287,'south-australia-cheyne-rich-port-adelaide','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1288,'south-australia-jenn-roberts-hartley','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1289,'south-australia-alice-rolls-unley','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1290,'south-australia-robert-roylance-hammond','faith','In his May 2026 maiden speech Roylance spoke of his Christian faith, recounting discovering it through the underground church while teaching in China, saying he was in Parliament ''because of (God''s) will'', and closing with ''Viva Cristo Rey'' (''long live Christ the King'').',1);
INSERT INTO "position" VALUES(1291,'south-australia-robert-roylance-hammond','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1292,'south-australia-olivia-savvas-newland','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1293,'south-australia-matt-schultz-kavel','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1294,'south-australia-ella-shaw-elizabeth','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1295,'south-australia-meagan-spencer-torrens','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1296,'south-australia-jayne-stinson-badcoe','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1297,'south-australia-joe-szakacs-cheltenham','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1298,'south-australia-joe-szakacs-cheltenham','drugs_law_order','Szakacs served as South Australia''s Minister for Police, Emergency Services and Correctional Services from 24 March 2022 to 15 April 2024, the portfolio responsible for policing and law-and-order matters; he is an admitted legal practitioner of the Supreme Court of South Australia.',1);
INSERT INTO "position" VALUES(1299,'south-australia-josh-teague-heysen','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1300,'south-australia-sam-telfer-flinders','faith','In his 17 May 2022 first speech to the South Australian House of Assembly, Sam Telfer spoke of his strong Christian faith and a heritage of faithfulness across generations, saying he is blessed to worship at the same church as his forebears in his home town of Ungarra.',1);
INSERT INTO "position" VALUES(1301,'south-australia-sam-telfer-flinders','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1302,'south-australia-chantelle-thomas-narungga','faith','In her May 2026 maiden speech, Thomas spoke of tackling her first term "with God within me," ended with the line "the Godly are as bold as lions," and thanked her church community, identifying with Christian faith.',1);
INSERT INTO "position" VALUES(1303,'south-australia-chantelle-thomas-narungga','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1304,'south-australia-erin-thompson-davenport','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1305,'south-australia-jason-virgo-mackillop','abortion','Voted in favour of Family First MLC Sarah Game''s bill to restrict access to late-term abortions when it was debated in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1306,'south-australia-jason-virgo-mackillop','gender_lgbtq','One Nation MP for MacKillop, elected April 2026. Earlier in life he was an LGBT and marriage-equality activist: he organised marriage-equality and IDAHO (International Day Against Homophobia) rallies in Adelaide around 2011, was involved with gay and lesbian counselling services, and ran for the Australian Sex Party in 2010. Asked in 2026 about his political evolution he said ''we grow up, we learn new things, we change our views as we age,'' and declined to elaborate on his current positions on LGBT rights.',1);
INSERT INTO "position" VALUES(1307,'south-australia-tim-whetstone-chaffey','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1308,'south-australia-david-wilkins-lee','abortion','Voted against Family First MLC Sarah Game''s bill to restrict access to late-term abortions in the House of Assembly on 18 June 2026; the bill was defeated in the lower house 36 votes to 9.',1);
INSERT INTO "position" VALUES(1309,'tasmania-jo-palmer-rosevears','education','Tasmanian Minister for Education (Liberal MLC, since April 2024). Her central policy is the ''Lifting Literacy'' agenda mandating structured, explicit, evidence-based literacy instruction - requiring one hour of structured literacy daily in primary schools, with all Tasmanian students to be taught reading in a systematic, explicit way by 2026 - and extending the same model to numeracy, requiring a minimum one hour of structured numeracy instruction daily from 2027. She said schools would leverage the literacy hour ''to add critical math skills as well.''',1);
INSERT INTO "position" VALUES(1310,'tasmania-kerry-vincent-prosser','gender_lgbtq','In the 2024 Equality Tasmania Legislative Council election survey Vincent (Liberal) referenced the government''s existing 2023 conversion-practices bill and said work on intersex issues should be done collaboratively "with community and clinical stakeholders"; he answered "No" on a Human Rights Act and gave a neutral response on drag story time. (Stated positions.)',1);
INSERT INTO "position" VALUES(1311,'tasmania-craig-farrell-derwent','abortion','Recorded vote: As the Legislative Council member for Derwent (Labor), Craig Farrell voted in favour of the Reproductive Health (Access to Terminations) Bill 2013 (which decriminalised abortion). He was one of nine members who voted yes when the bill passed the Legislative Council 9 votes to 5 on 21 November 2013.',1);
INSERT INTO "position" VALUES(1312,'tasmania-cassy-o-connor-hobart','abortion','Stated position / recorded action: As Greens leader, Cassy O''Connor supported the 13 June 2018 motion to provide terminations through public hospitals (defeated 12-11). In a 3 February 2023 statement she said a Women''s Health Tasmania report "highlights the need for improved access to safe and affordable termination services in Tasmania" and described "a health system still failing on reproductive health."',1);
INSERT INTO "position" VALUES(1313,'tasmania-cassy-o-connor-hobart','voluntary_assisted_dying','Recorded vote: as the Greens member for Clark in the House of Assembly, Cassy O''Connor (listed as ''Ms O''Connor'') voted Aye in favour of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 at its second reading division on 4 December 2020. The bill passed 17 Ayes to 7 Noes. (She now sits in the Legislative Council for Hobart.)',1);
INSERT INTO "position" VALUES(1314,'tasmania-cassy-o-connor-hobart','gender_lgbtq','As Greens leader O''Connor championed the 2019 gender-optional birth certificate reforms, saying "Just as it was with the vote on marriage equality, the sky is likely to remain in place with the passing of this legislation"; in a February 2023 parliamentary speech she supported a ban on conversion practices, stating "The Greens choose love, acceptance and inclusion" and speaking as the mother of a transgender son. (Stated positions/parliamentary speech.)',1);
INSERT INTO "position" VALUES(1315,'tasmania-cassy-o-connor-hobart','religious_freedom','O''Connor has opposed weakening section 17 of the Anti-Discrimination Act, describing it as ''gold standard'' and raising concern about the Australian Christian Lobby campaign to water it down (Sept 2021), and has supported legislation prohibiting conversion practices while distinguishing such practices from legitimate religious prayer and pastoral care (Feb 2023). Stated positions.',1);
INSERT INTO "position" VALUES(1316,'tasmania-cassy-o-connor-hobart','drugs_law_order','Stated position: O''Connor, Greens justice spokesperson, advocates treating drug use as a health issue rather than a crime and supports decriminalisation, saying in January 2023 that ''Drug use is a health issue, not a crime against another person'' and that criminalisation is ''costly, ineffective, and harmful.'' In October 2024 she called on the Rockliff government to ''look at the evidence from other jurisdictions, including the ACT, and introduce this common-sense reform in Tasmania.''',1);
INSERT INTO "position" VALUES(1317,'tasmania-cassy-o-connor-hobart','native_forest_logging','Greens MLC O''Connor advocates ending native forest logging in Tasmania, framing it as the state''s best climate action: ''The best, fastest way for Tasmania to take real climate action is to end the logging and burning of native forests,'' noting native forest logging ''produces two and a half times the emissions of the State''s entire transport sector.''',1);
INSERT INTO "position" VALUES(1318,'tasmania-rosemary-armitage-launceston','abortion','Recorded vote: As the Legislative Council member for Launceston, Rosemary Armitage voted against the Reproductive Health (Access to Terminations) Bill 2013 (which decriminalised abortion). She was one of five members who voted no when the bill passed the Legislative Council 9 votes to 5 on 21 November 2013.',1);
INSERT INTO "position" VALUES(1319,'tasmania-rosemary-armitage-launceston','gender_lgbtq','During the November 2018 Legislative Council debate on the gender/birth-certificate reform bill, Armitage stated she could not support the bill as presented. (Stated position during debate.)',1);
INSERT INTO "position" VALUES(1320,'tasmania-rosemary-armitage-launceston','drugs_law_order','Stated position: Armitage opposed a 2019 motion for pill testing at Tasmanian festivals, saying ''I do not believe there is any safe way to take drugs'' and ''I feel this could be seen as a way of normalising drug taking,'' concluding ''I cannot support the motion.''',1);
INSERT INTO "position" VALUES(1321,'tasmania-ruth-forrest-murchison','abortion','Recorded vote: As the Legislative Council member for Murchison, Ruth Forrest voted in favour of the Reproductive Health (Access to Terminations) Bill 2013 (which decriminalised abortion). She was one of nine members who voted yes when the bill passed the Legislative Council 9 votes to 5 on 21 November 2013.',1);
INSERT INTO "position" VALUES(1322,'tasmania-ruth-forrest-murchison','voluntary_assisted_dying','Stated position: Ruth Forrest, independent member for Murchison, supported the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 and, with Labor members, moved the bulk of amendments to it during its passage through the Legislative Council in 2020. The bill passed the upper house at its third reading on 10 November 2020.',1);
INSERT INTO "position" VALUES(1323,'tasmania-ruth-forrest-murchison','drugs_law_order','Recorded action / stated position: In August 2019 Forrest moved a motion in the Legislative Council calling for pill testing (drug analysis) services at Tasmanian music festivals and events; the motion was supported by only four members and defeated, with Liberal and Labor members voting against. She indicated she intended to re-table the motion pending coronial recommendations.',1);
INSERT INTO "position" VALUES(1324,'tasmania-ruth-forrest-murchison','gambling','Voted AGAINST the Gaming Control Amendment (Future Gaming Market) Bill 2021 in the Tasmanian Legislative Council (passed 8-5), stating the bill ''fails to deliver effective harm minimisation measures and a fair distribution'' of gaming revenue to the community.',1);
INSERT INTO "position" VALUES(1325,'tasmania-mike-gaffney-mersey','abortion','Recorded vote: As the Legislative Council member for Mersey, Mike Gaffney voted in favour of the Reproductive Health (Access to Terminations) Bill 2013 (which decriminalised abortion). He was one of nine members who voted yes when the bill passed the Legislative Council 9 votes to 5 on 21 November 2013.',1);
INSERT INTO "position" VALUES(1326,'tasmania-mike-gaffney-mersey','voluntary_assisted_dying','Stated position (and recorded role): Mike Gaffney, independent member for Mersey, is the author and mover of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 in the Legislative Council, which he introduced in August 2020 and moved through to its third reading on 10 November 2020. He is a strong supporter of voluntary assisted dying.',1);
INSERT INTO "position" VALUES(1327,'tasmania-mike-gaffney-mersey','gender_lgbtq','During the November 2018 Legislative Council debate on the gender/birth-certificate reform bill, Gaffney said he could not support certain provisions without sufficient information, stating his job was "for good legislation and to review what''s in front of us" and warning that passing flawed legislation would "put your cause back even further." (Stated position during debate.)',1);
INSERT INTO "position" VALUES(1328,'tasmania-mike-gaffney-mersey','gambling','Voted AGAINST the Gaming Control Amendment (Future Gaming Market) Bill 2021 in the Tasmanian Legislative Council (passed 8-5), joining the minority of independent MLCs who opposed the pokies reform framework as inadequate on harm minimisation.',1);
INSERT INTO "position" VALUES(1329,'tasmania-meg-webb-nelson','religious_freedom','Webb authored a ten-point Legislative Council motion (passed 9 to 5 in October 2019) defending Tasmania''s Anti-Discrimination Act against the proposed federal Religious Discrimination Bill, warning the federal bill ''risks making our state law unworkable and will leave a range of vulnerable Tasmanians less protected.'' Stated position and a recorded motion she moved.',1);
INSERT INTO "position" VALUES(1330,'tasmania-meg-webb-nelson','drugs_law_order','Stated position: Webb advocates raising Tasmania''s minimum age of criminal responsibility from 10 to at least 14, telling the Legislative Council (motion debated October 2021) ''Children do not belong in the criminal justice system. To have them there is not smart justice; it is not compassionate justice,'' and calling for a ''contemporary, nation-leading therapeutic approach to youth justice.''',1);
INSERT INTO "position" VALUES(1331,'tasmania-meg-webb-nelson','gambling','Voted AGAINST the Gaming Control Amendment (Future Gaming Market) Bill 2021 in the Tasmanian Legislative Council (passed 8-5). A long-time anti-pokies campaigner, Webb delivered a marathon (~6.5 hour) speech opposing the industry-favoured framework, arguing it ignored consumer protection and harm minimisation, and advocating $1 bet limits, 6-second spin speeds, lower jackpots and higher return-to-player rates. She said: ''We''ve got a lot of doubt as to the ultimate impact of this Bill still remaining for us.''',1);
INSERT INTO "position" VALUES(1332,'tasmania-tania-rattray-mcintyre','abortion','Recorded vote: Tania Rattray (then Legislative Council member for Apsley, now McIntyre) voted in favour of the Reproductive Health (Access to Terminations) Bill 2013 (which decriminalised abortion). She was one of nine members who voted yes when the bill passed the Legislative Council 9 votes to 5 on 21 November 2013.',1);
INSERT INTO "position" VALUES(1333,'tasmania-tania-rattray-mcintyre','gender_lgbtq','During the November 2018 Legislative Council debate on the gender/birth-certificate reform bill, Rattray stated she could not support the bill as presented. (Stated position during debate.)',1);
INSERT INTO "position" VALUES(1334,'tasmania-bridget-archer-bass','voluntary_assisted_dying','Stated position: as Tasmanian Minister for Health, Mental Health and Wellbeing, Bridget Archer said in April 2026 that ''Tasmanians should have the right to make their own choices at the end-of-life, including access to voluntary assisted dying supported by registered health practitioners if they are eligible,'' announcing public consultation on the statutory review of the End-of-Life Choices (Voluntary Assisted Dying) Act 2021. (She was not a member of the Tasmanian Parliament at the time of the 2020-21 vote.)',1);
INSERT INTO "position" VALUES(1335,'tasmania-bridget-archer-bass','gender_lgbtq','In February 2022, as federal MP, Archer crossed the floor over the religious discrimination bill; she said she was "horrified" that proposed protections would not extend "to children who identify as transgender" and "utterly distressed by this exclusion," and said she could not support the bill in that form. (Stated position/floor-crossing.)',1);
INSERT INTO "position" VALUES(1336,'tasmania-bridget-archer-bass','religious_freedom','As federal member for Bass, Archer said in 2022 she could not support the Commonwealth Religious Discrimination Bill, arguing its Statement of Belief provisions would ''allow for discrimination to happen'' and would override Tasmania''s existing ''gold standard'' anti-discrimination laws, while stating there ''absolutely should be freedom from discrimination for all people, including people of faith.'' Stated position.',1);
INSERT INTO "position" VALUES(1337,'tasmania-bridget-archer-bass','drugs_law_order','Stated position: As Health Minister, Archer ruled out drug decriminalisation in June 2026, saying ''We won''t be decriminalising illicit drugs, which cause significant harm in our community,'' adding that Tasmania''s focus remains on harm minimisation through supply, demand and harm-reduction strategies.',1);
INSERT INTO "position" VALUES(1338,'tasmania-bridget-archer-bass','health','Tasmanian Minister for Health, Mental Health and Wellbeing, Ageing and Aboriginal Affairs (Rockliff Liberal government, sworn in August 2025 after the July 2025 state election). Emphasises record elective-surgery delivery - over 22,500 elective surgeries in 2024-25 (a 46.1% increase over pre-elective-surgery-plan levels) - and increased health-system transparency, including daily publication of ambulance response times and elective-surgery wait-list reporting from early 2026, plus a Tasmanian Midwifery Workforce Strategy.',1);
INSERT INTO "position" VALUES(1339,'tasmania-michael-ferguson-bass','faith','Michael Ferguson has publicly identified as a Christian. In a parliamentary speech quoted by the Australian Christian Lobby he said, "I am a Christian. I would not say I am a very good one," and referred to himself as "a person of faith."',1);
INSERT INTO "position" VALUES(1340,'tasmania-michael-ferguson-bass','abortion','Stated position / recorded action: Described as anti-abortion, Michael Ferguson as Tasmanian Health Minister opposed a 13 June 2018 motion (moved by Labor''s Michelle O''Byrne) to provide pregnancy terminations through public hospitals; the motion was defeated 12-11. He instead offered an amendment directing the Department of Health to provide advice after consulting stakeholders.',1);
INSERT INTO "position" VALUES(1341,'tasmania-michael-ferguson-bass','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Michael Ferguson (listed as ''Mr Ferguson'') voted Noe, against. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1342,'tasmania-michael-ferguson-bass','gender_lgbtq','Wikipedia records that Ferguson opposed same-sex marriage and that in 2018 he criticised the Tasmanian Greens and Labor for their reforms making birth certificates gender-optional. (Stated positions.)',1);
INSERT INTO "position" VALUES(1343,'tasmania-michael-ferguson-bass','religious_freedom','Ferguson has been described as a conservative Liberal who opposed same-sex marriage (voting against related legislation in 2010) and abortion, and in 2018 criticised Greens and Labor reforms to make birth certificate gender optional. Stated positions and a recorded vote.',1);
INSERT INTO "position" VALUES(1344,'tasmania-michael-ferguson-bass','drugs_law_order','Stated position: As Police Minister in December 2018, Ferguson flagged a renewed push for mandatory minimum sentences for child sex offenders, saying ''We''ve been prevented once and we don''t want to be prevented twice from having stronger legislation to protect children'' and challenging Labor to state its position.',1);
INSERT INTO "position" VALUES(1345,'tasmania-cecily-rosol-bass','drugs_law_order','Stated position: Rosol opposes ''adult crime, adult time'' laws and supports raising the age of criminal responsibility and evidence-based youth justice. In May 2025 she cited UN Special Rapporteurs that such laws are ''Incompatible with basic child rights'' and asked the Premier to ''ditch the adult crime, adult time plan.''',1);
INSERT INTO "position" VALUES(1346,'tasmania-shane-broad-braddon','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Shane Broad (listed as ''Dr Broad'') voted Aye, in favour. The bill passed 17 Ayes to 7 Noes and later became the End-of-Life Choices (Voluntary Assisted Dying) Act 2021.',1);
INSERT INTO "position" VALUES(1347,'tasmania-anita-dow-braddon','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Anita Dow (listed as ''Ms Dow'', and acting as a teller for the Ayes) voted Aye, in favour. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1348,'tasmania-felix-ellis-braddon','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Felix Ellis (listed as ''Mr Ellis'', and acting as a teller for the Noes) voted Noe, against. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1349,'tasmania-felix-ellis-braddon','gender_lgbtq','At a July 2022 public meeting on the Tasmanian Law Reform Institute''s conversion-practices report, Ellis noted there would be "a formal consultation period that all Tasmanians can take part in before any legislation is tabled," said he wanted to hear from constituents and would "listen with open ears and an open heart." (Stated position.)',1);
INSERT INTO "position" VALUES(1350,'tasmania-felix-ellis-braddon','drugs_law_order','Stated position: As Police Minister, Ellis has pushed tougher bail and youth crime measures. In July 2025 he said police ''are often let down by weak bail laws'' and announced a re-elected Liberal government would ''bring this to an end, introducing new bail laws for serious repeat young offenders,'' making breach of bail an offence for youths and continuing knife-crime restrictions for under-18s, advocating being ''tough on crime, and the causes of crime.''',1);
INSERT INTO "position" VALUES(1351,'tasmania-roger-jaensch-braddon','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Roger Jaensch (listed as ''Mr Jaensch'') voted Aye, in favour. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1352,'tasmania-roger-jaensch-braddon','gender_lgbtq','OUTInPerth describes Jaensch as having "been a supporter of LGBTIQ+ equality for many years and a voice for LGBTIQ+ law reform in the Liberal Party." (Reported characterisation of his record.)',1);
INSERT INTO "position" VALUES(1353,'tasmania-roger-jaensch-braddon','gambling','As Community Services Minister, jointly announced in November 2024 the deferral of Tasmania''s mandatory pre-commitment pokies card, favouring alternative measures instead, including flagging that facial recognition technology may be included in the harm-minimisation package and that the government was reviewing the Tasmanian Gambling Exclusion Scheme.',1);
INSERT INTO "position" VALUES(1354,'tasmania-jeremy-rockliff-braddon','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Jeremy Rockliff (listed as ''Mr Rockliff'') voted Aye, in favour. He told Parliament he would support the bill after having voted against three previous voluntary assisted dying bills. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1355,'tasmania-jeremy-rockliff-braddon','gender_lgbtq','Rockliff voted for the Greens-sponsored 2015 motion supporting same-sex marriage (which passed the House 15-9), stating he was "absolutely unequivocally in favour of same-sex marriage equality"; as Premier in 2022 he committed to banning conversion practices, saying "I will be leading the change" and that change was needed given the harm to wellbeing. (Recorded vote and stated positions.)',1);
INSERT INTO "position" VALUES(1356,'tasmania-jeremy-rockliff-braddon','religious_freedom','As Premier, Rockliff told Parliament on 15 May 2024 ''There will be no weakening of the Anti-Discrimination Act. I will absolutely rule that out,'' responding to calls (including from Archbishop Porteous) to amend the Act; he earlier voted for Tasmania''s 2015 in-principle motion supporting same-sex marriage. Stated position and recorded vote.',1);
INSERT INTO "position" VALUES(1357,'tasmania-jeremy-rockliff-braddon','drugs_law_order','Stated position: Premier Rockliff opposes drug decriminalisation and adopts a ''tough on crime'' stance. He defended the government''s youth crime crackdown in March 2024, saying he made ''no apologies'' and that Tasmanians had ''a gutful'' of youth crime, and in April 2025 said on ''adult crime, adult time'' laws ''Yes, we will, absolutely. All options are on the table.'' In July 2025 he said ''Community safety must come first'' while pledging to also divert young people from the justice system.',1);
INSERT INTO "position" VALUES(1358,'tasmania-vica-bayley-clark','gender_lgbtq','In December 2023 parliamentary estimates Bayley criticised the government''s 2015 LGBTIQA+ framework for "the complete lack of acknowledgement of Tasmanians who are non-binary and don''t identify as male or female," and pressed the government to update the framework with the LGBTIQA+ community. (Stated position/parliamentary statement.)',1);
INSERT INTO "position" VALUES(1359,'tasmania-vica-bayley-clark','gambling','Greens MP who condemned the Liberal government''s watering-down/deferral of the mandatory pokies pre-commitment card, calling it ''a shameful decision that will mean more harm done to more Tasmanians.'' The Greens support strong mandatory harm-minimisation measures including card-based play with binding loss limits.',1);
INSERT INTO "position" VALUES(1360,'tasmania-vica-bayley-clark','native_forest_logging','Greens Deputy Leader and Member for Clark, Bayley (environment/biodiversity portfolio) campaigns to end native forest logging in Tasmania: ''We must protect the environment, and end native forest logging.'' He has accused the Liberal government of secretly planning to log reserved forests despite taxpayer subsidies to protect them.',1);
INSERT INTO "position" VALUES(1361,'tasmania-helen-burnet-clark','drugs_law_order','Stated position: Burnet advocates for a drug-checking (pill testing) service in Tasmania, telling parliament in September 2025 that ''Pill testing reduces harm and saves lives'' and that it was ''an easy win'' for the government that would save lives without new legislation, citing Royal Australian College of General Practitioners support.',1);
INSERT INTO "position" VALUES(1362,'tasmania-ella-haddad-clark','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Ella Haddad (listed as ''Ms Haddad'') voted Aye, in favour. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1363,'tasmania-ella-haddad-clark','gender_lgbtq','As Labor''s then shadow attorney-general, Haddad opposed the federal Religious Freedom draft bills, saying the changes "would unnecessarily risk hard-won anti-discrimination rights and, if passed, would expose vulnerable Australians to increased discrimination with no recourse." (Stated position.)',1);
INSERT INTO "position" VALUES(1364,'tasmania-ella-haddad-clark','religious_freedom','In a 2020 submission on the federal Religious Freedom Bills, Haddad argued Tasmania''s Anti-Discrimination Act ''provides a model for the nation,'' warning the federal draft would ''unnecessarily risk hard-won anti-discrimination rights,'' and noted the Tasmanian Act already allows faith-based organisations including schools, hospitals and charities to select employees on the basis of religion. Stated position.',1);
INSERT INTO "position" VALUES(1365,'tasmania-ella-haddad-clark','drugs_law_order','Stated position: As Labor justice spokeswoman, Haddad indicated in November 2023 that Labor would not oppose the government''s mandatory minimum sentencing bill for child sex offences, saying ''It''s too traumatising to continue to bring this big issue back again and again, every election, with no regard to the effect on victim-survivors,'' citing a wish to stop the issue being used politically. Labor''s general policy has been opposition to mandatory sentencing.',1);
INSERT INTO "position" VALUES(1366,'tasmania-kristie-johnston-clark','gender_lgbtq','In the 2024 Equality Tasmania election survey Johnston said she wants to end conversion practices ("Absolutely"), would enact a prohibition as "Very high priority. It is long overdue," supported prohibiting medically-unnecessary interventions on intersex children, and answered "Yes" to all the survey''s major LGBTIQA+ reform questions. (Stated positions.)',1);
INSERT INTO "position" VALUES(1367,'tasmania-madeleine-ogilvie-clark','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Madeleine Ogilvie (listed as ''Ms Ogilvie'') voted Noe, against. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1368,'tasmania-madeleine-ogilvie-clark','religious_freedom','In December 2015 Ogilvie voted, in a free vote, against a Greens motion supporting marriage equality, on the basis that it was a matter for federal reform, and said she would ''not be bullied over same-sex marriage.'' Recorded vote and stated position.',1);
INSERT INTO "position" VALUES(1369,'tasmania-eric-abetz-franklin','faith','Eric Abetz is a Christian. His Wikipedia article states he is a Protestant Christian and a member of the Christian Reformed Churches of Australia.',1);
INSERT INTO "position" VALUES(1370,'tasmania-eric-abetz-franklin','abortion','Stated position / recorded federal vote: As a Liberal Senator for Tasmania, Eric Abetz was one of ten senators who voted yes in 2017 on Cory Bernardi''s motion to ban abortion on gender grounds (the motion was not carried). His Wikipedia biography also records his association with anti-abortion group Right to Life Australia.',1);
INSERT INTO "position" VALUES(1371,'tasmania-eric-abetz-franklin','gender_lgbtq','In a November 2017 Senate speech Abetz argued that "same-sex marriage is not a human right" in the way religious freedoms and heterosexual marriage are, and opposed the inclusion of trans, intersex and non-binary protections in the marriage legislation. (Stated position.)',1);
INSERT INTO "position" VALUES(1372,'tasmania-eric-abetz-franklin','religious_freedom','Abetz is a public opponent of same-sex marriage and was among 12 senators who voted against the 2017 marriage-equality legislation; he identifies as a Protestant Christian and has been associated with conservative groups including the Australian Christian Lobby and Right to Life Australia. Stated positions and a recorded Senate vote.',1);
INSERT INTO "position" VALUES(1373,'tasmania-jacquie-petrusma-franklin','abortion','Stated position: During the 16 April 2013 Lower House debate on the Reproductive Health (Access to Terminations) Bill, Liberal MP Jacquie Petrusma spoke against the bill in favour of preserving unborn life, stating "An abortion is not the termination of just one life" and drawing on her own experience as a young unmarried pregnant nurse. (Source is the advocacy group Australian Christian Lobby.)',1);
INSERT INTO "position" VALUES(1374,'tasmania-jacquie-petrusma-franklin','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Jacquie Petrusma (listed as ''Mrs Petrusma'') voted Noe, against. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1375,'tasmania-jacquie-petrusma-franklin','religious_freedom','A former Family First Party Senate candidate, Petrusma spoke in the House of Assembly in 2013 in favour of preserving the lives of unborn babies during debate on abortion law reform, according to an Australian Christian Lobby profile. Stated position.',1);
INSERT INTO "position" VALUES(1376,'tasmania-david-o-byrne-franklin','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, David O''Byrne (listed as ''Mr O''Byrne'') voted Aye, in favour. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1377,'tasmania-david-o-byrne-franklin','gender_lgbtq','In Equality Tasmania''s 2025 state election material O''Byrne is recorded as a strong ally supporting marriage equality, conversion-therapy bans, intersex protections, improved access to gender-affirming care, and hate-crime protections. (Stated positions.)',1);
INSERT INTO "position" VALUES(1378,'tasmania-david-o-byrne-franklin','drugs_law_order','Stated position: During November 2023 chamber debate, O''Byrne signalled he would not support the government''s mandatory minimum sentencing bill for child sex offences, arguing mandatory minimums would encourage offenders to plead not guilty rather than guilty, thereby retraumatising victims.',1);
INSERT INTO "position" VALUES(1379,'tasmania-dean-winter-franklin','gender_lgbtq','OUTInPerth describes Winter as "an early advocate for marriage equality." (Reported characterisation.)',1);
INSERT INTO "position" VALUES(1380,'tasmania-rosalie-woodruff-franklin','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Rosalie Woodruff (listed as ''Dr Woodruff'') voted Aye, in favour. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1381,'tasmania-rosalie-woodruff-franklin','gender_lgbtq','As Greens leader Woodruff said the party would "move that Parliament ban conversion practices and fully implement" the Law Reform Institute recommendations, and criticised the Liberal government''s draft bill as one that "would legitimise conversion practices" and increase "trauma, pain and suffering of LGBTIQA+ people"; in the 2024 Equality Tasmania survey the Greens (Woodruff responding) backed a real conversion-practices ban, opposed weakening gender-recognition laws, and supported evidence-based care for trans and gender-diverse youth. (Stated positions.)',1);
INSERT INTO "position" VALUES(1382,'tasmania-rosalie-woodruff-franklin','religious_freedom','On 15 May 2024 Woodruff questioned the Premier in Parliament about Archbishop Porteous urging parents to lobby MPs to weaken the Anti-Discrimination Act and oppose a ban on conversion practices, expressing concern that the Act should not be weakened. Stated position.',1);
INSERT INTO "position" VALUES(1383,'tasmania-rosalie-woodruff-franklin','drugs_law_order','Stated position: Greens leader Woodruff supports legalising and regulating cannabis, telling parliament on 17 March 2021 ''It is well past time to legalise cannabis and regulate it.'' She introduced a bill to decriminalise personal use of small quantities of drugs and directing users to treatment. She opposed the government''s mandatory minimum sentencing bill for child sex offences, saying in November 2023 that ''Every single expert on this matter ... have opposed previous versions of this bill because it will increase harms for victim-survivors.''',1);
INSERT INTO "position" VALUES(1384,'tasmania-rosalie-woodruff-franklin','native_forest_logging','Tasmanian Greens leader Dr Woodruff calls for ending native forest logging, arguing ''In a biodiversity and climate crisis, native forest logging simply shouldn''t continue'' and that it is ''a loss-making industry that survives only on billions in public subsidies... This must end.'' She has criticised the Forest Practices Authority and Liberal plans to continue logging via a bilateral agreement.',1);
INSERT INTO "position" VALUES(1385,'tasmania-tabatha-badger-lyons','drugs_law_order','Stated position: Badger opposed the Police Offences Amendment (Knives and Other Weapons) Bill 2025 as drafted, telling parliament on 1 April 2025 that broadening police wand-search powers ''will result in more people getting caught in the justice system,'' arguing the measure lacks evidence of effectiveness and favouring prevention and diversion over expanded police powers.',1);
INSERT INTO "position" VALUES(1386,'tasmania-guy-barnett-lyons','abortion','Stated position / federal motion: As a Liberal Senator for Tasmania, in June 2008 Guy Barnett moved a motion in the Senate to end Medicare funding for abortions occurring after the second trimester, stating he wanted to show "compassion and care for the unborn... rather than killing them in many cases for psychosocial reasons, which is effectively abortion on request."',1);
INSERT INTO "position" VALUES(1387,'tasmania-guy-barnett-lyons','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Guy Barnett (listed as ''Mr Barnett'') voted Noe, against. He called the bill ''ill-conceived, ambiguous, and fatally flawed'' and argued it undermined dignity. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1388,'tasmania-guy-barnett-lyons','gender_lgbtq','Wikipedia records that Barnett opposed same-sex marriage during the 2017 postal survey campaign, including a September 2017 claim that "''Gay sex'' will be taught in school if SSM vote passes." (Stated position.)',1);
INSERT INTO "position" VALUES(1389,'tasmania-guy-barnett-lyons','religious_freedom','As a senator Barnett pressed for the Commonwealth Marriage Act to be amended to define marriage as between one man and one woman and opposed same-sex marriage in the 2017 postal survey; in 2008 he moved a Senate motion to end Medicare funding for late-term abortions. Stated positions and a recorded motion.',1);
INSERT INTO "position" VALUES(1390,'tasmania-guy-barnett-lyons','drugs_law_order','Stated position: As Attorney-General, Barnett championed bail and sentencing reform. On the 2024 Bail Bill (March 2025) he said reform would ''improve transparency and provide a clear statutory framework for deciding when, or if, bail should be granted'' and ensure ''the safety of victims of crime, individuals and the community is taken into account.'' On ''Post and Boast'' laws (June 2026) he said ''We want to stamp down on a culture where there''s a bragging of the crime'' and ''We want that culture of violence gone.''',1);
INSERT INTO "position" VALUES(1391,'tasmania-guy-barnett-lyons','gambling','As Treasurer, jointly announced in November 2024 that the Tasmanian Government would indefinitely defer its promised mandatory cashless pre-commitment card for poker machines (which would have set default loss limits of ~$100/day, $5,000/year), citing cost, complexity and implementation delays, and would instead pursue alternative harm-minimisation measures. Stated the government needed ''to get the balance right between implementing effective harm minimisation measures and regulatory implications.''',1);
INSERT INTO "position" VALUES(1392,'tasmania-jen-butler-lyons','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Jen Butler (listed as ''Ms Butler'') voted Aye, in favour. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1393,'tasmania-carlo-di-falco-lyons','drugs_law_order','Stated position: As the Shooters, Fishers and Farmers Party member, Di Falco has prioritised firearm-related law and order, proposing in August 2025 a mandatory minimum of at least three months'' imprisonment for anyone caught stealing firearms, and said of his agenda ''We''re not pushing anything that''s going to endanger public safety ... we''re enhancing it.''',1);
INSERT INTO "position" VALUES(1394,'tasmania-jane-howlett-lyons','gambling','As Minister for Hospitality and Small Business, was one of three ministers who jointly announced in November 2024 that the Tasmanian Government would indefinitely defer its promised mandatory cashless pre-commitment card for poker machines in favour of alternative harm-minimisation measures.',1);
INSERT INTO "position" VALUES(1395,'tasmania-mark-shelton-lyons','voluntary_assisted_dying','Recorded vote: in the House of Assembly division on the second reading of the End-of-Life Choices (Voluntary Assisted Dying) Bill 2020 on 4 December 2020, Mark Shelton (listed as ''Mr Shelton'') voted Aye, in favour. The bill passed 17 Ayes to 7 Noes.',1);
INSERT INTO "position" VALUES(1396,'tasmania-mark-shelton-lyons','drugs_law_order','Stated position: As Police Minister in June 2020, Shelton opposed decriminalising illicit drugs, saying ''Illicit drugs are illegal for a reason. They destroy lives and line the pockets of criminals. Let me be clear - there is no safe use of illicit drugs,'' while noting Tasmania Police take a harm-minimisation approach diverting small personal-use possession to health intervention.',1);
INSERT INTO "position" VALUES(1397,'victoria-jacinta-allan-bendigo-east','abortion','Allan, member for Bendigo East since 1999, voted for the Abortion Law Reform Act 2008 that decriminalised abortion in Victoria; her Wikipedia biography notes she received abusive emails and a picket of her electorate office by anti-abortion campaigners over the vote and was targeted by Right to Life groups in the 2010 campaign. As Premier in October 2024 she said there are ''real and genuine threats to the protections women have fought for and won'' and that legislation to protect those rights ''is being looked at being torn down at too many opportunities by conservative politicians.''',1);
INSERT INTO "position" VALUES(1398,'victoria-jacinta-allan-bendigo-east','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Jacinta Allan voted YES (in favour).',1);
INSERT INTO "position" VALUES(1399,'victoria-jacinta-allan-bendigo-east','gender_lgbtq','Labor MP for Bendigo East and Premier of Victoria (since September 2023). She has been a vocal supporter of LGBTIQ+ equality, declaring in a February 2025 statement that ''in Victoria, equality is not negotiable'' and pledging to defend LGBTIQ+ rights against ''hard-right extremists.'' Her government cites achievements including the conversion-practices ban, same-sex adoption, easier birth-certificate sex changes for trans and gender-diverse Victorians, the Pride Centre, and landmark anti-vilification laws.',1);
INSERT INTO "position" VALUES(1400,'victoria-jacinta-allan-bendigo-east','drugs_law_order','As Premier, Allan announced in April 2024 that the government would not proceed with a second medically supervised injecting room in Melbourne''s CBD, saying a site balancing user support and community backing could not be found and committing instead to expanded health and addiction supports. In March 2025 she announced and her government passed the ''toughest bail laws in the country'', stating ''I have listened to victims of crime and Victorians, and I have acted'', removing remand as a last resort and making community safety the overarching principle. She also announced Australia''s first machete ban (effective 1 September 2025), saying ''Machetes are destroying lives so we will destroy machetes.''',1);
INSERT INTO "position" VALUES(1401,'victoria-jacinta-allan-bendigo-east','first_nations','As Premier, introduced the Statewide Treaty Bill 2025 to the Victorian Parliament on 9 September 2025 and championed it. The Bill — Australia''s first legislated treaty framework, establishing an ongoing First Peoples'' representative body (Gellung Warl) — passed both houses (Assembly 16 Oct, Council 30 Oct 2025) and received royal assent on 13 November 2025.',1);
INSERT INTO "position" VALUES(1402,'victoria-jacinta-allan-bendigo-east','nuclear','As Victorian Premier, opposed the federal Coalition''s June 2024 nuclear plan, characterising nuclear as "a more expensive, more risky, more toxic" energy solution and indicating her government would not support it.',1);
INSERT INTO "position" VALUES(1403,'victoria-brad-battin-berwick','abortion','Battin (Liberal), elected Opposition Leader in December 2024, said in a January 2025 interview that he supports Victoria''s existing abortion legislation (and that he would be happy to attend Melbourne''s pride march), per his Wikipedia biography.',1);
INSERT INTO "position" VALUES(1404,'victoria-brad-battin-berwick','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Brad Battin voted NO (against). [Battin (then member for Gembrook)]',1);
INSERT INTO "position" VALUES(1405,'victoria-brad-battin-berwick','gender_lgbtq','Liberal MP for Berwick; elected Victorian Liberal leader in December 2024 after John Pesutto''s defamation loss to Moira Deeming, serving as Opposition Leader until November 2025. He had opposed Deeming''s expulsion and, on becoming leader, promoted Deeming allies and later elevated Deeming to a shadow assistant ministry. In 2015 he voted against legislation allowing same-sex couples to adopt. By 2025 he said he supports Victoria''s abortion laws and would be happy to attend Melbourne''s pride march, and stated ''every person has a choice to identify or be who they want,'' while also announcing a Coalition government would stop biological men convicted of sex offences being housed in women''s prisons.',1);
INSERT INTO "position" VALUES(1406,'victoria-brad-battin-berwick','drugs_law_order','As Liberal leader (Dec 2024-Nov 2025), Battin championed a ''break bail, face jail'' / ''you break bail, you go to jail'' policy as the Liberal-National plan to toughen Victoria''s bail system, framing it as a common-sense response to crime while saying youth crime needs a multi-layered approach: ''It can''t be a one-solution-fits-all approach. We must give young offenders every chance to turn their lives around.'' He earlier served as Shadow Minister for Police (2021-2022).',1);
INSERT INTO "position" VALUES(1407,'victoria-brad-battin-berwick','first_nations','As Leader of the Opposition, opposed the Statewide Treaty and pledged that a Liberal-Nationals government would introduce legislation to repeal the Treaty within its first 100 days, stating the Coalition did not believe Treaty was the best way to close the gap; proposed a standalone First Nations Victoria department instead.',1);
INSERT INTO "position" VALUES(1408,'victoria-roma-britnell-south-west-coast','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Roma Britnell voted YES (in favour).',1);
INSERT INTO "position" VALUES(1409,'victoria-roma-britnell-south-west-coast','sex_work','As Shadow Minister for Consumer Affairs, opposed Victoria''s Sex Work Decriminalisation Bill 2021; moved a reasoned amendment against the bill in the Legislative Assembly (defeated 28 October 2021), arguing sex work is often ''the result of limited choice'' and that the bill lacked support (drug treatment, housing, training) for people exiting the industry.',1);
INSERT INTO "position" VALUES(1410,'victoria-josh-bull-sunbury','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Josh Bull voted YES (in favour).',1);
INSERT INTO "position" VALUES(1411,'victoria-tim-bull-gippsland-east','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Tim Bull voted NO (against).',1);
INSERT INTO "position" VALUES(1412,'victoria-anthony-carbines-ivanhoe','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Anthony Carbines voted NO (against).',1);
INSERT INTO "position" VALUES(1413,'victoria-anthony-carbines-ivanhoe','drugs_law_order','As Minister for Police, Carbines co-announced the March 2025 tough bail laws, saying ''Our tough new bail laws will help police as they crack down on repeat offenders.'' He also co-announced Australia''s first machete ban with an amnesty period (1 September to 30 November 2025), saying ''This is Australia''s first machete ban, and we agree with police that it must be done once and done right.''',1);
INSERT INTO "position" VALUES(1414,'victoria-ben-carroll-niddrie','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Ben Carroll voted YES (in favour).',1);
INSERT INTO "position" VALUES(1415,'victoria-ben-carroll-niddrie','education','Victorian Deputy Premier and Minister for Education. He has championed and extended Victoria''s classroom mobile-phone ban - which began in public schools in 2020 - introducing legislation to extend it (plus wearable devices such as smartwatches and earbuds) to all Victorian schools including non-government schools from January 2027, making Victoria the first state to legislate restrictions on wearable technology. He said: ''The evidence shows it worked and now we''re going further, so every Victorian student, in every Victorian school, can put their phone away and focus on learning.''',1);
INSERT INTO "position" VALUES(1416,'victoria-christine-couzens-geelong','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Christine Couzens voted YES (in favour).',1);
INSERT INTO "position" VALUES(1417,'victoria-lily-d-ambrosio-mill-park','abortion','D''Ambrosio, member for Mill Park since 2002 (and thus in Parliament for the 2008 reform), has publicly supported expanding abortion access. In a 29 November 2023 statement marking the 15th anniversary of Victoria''s 2008 decriminalisation of abortion, she promoted the Allan Labor Government''s expansion of surgical termination services across Melbourne and new sexual and reproductive health hubs, noting safe access zones around abortion providers had been legislated.',1);
INSERT INTO "position" VALUES(1418,'victoria-lily-d-ambrosio-mill-park','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Lily D''Ambrosio voted YES (in favour).',1);
INSERT INTO "position" VALUES(1419,'victoria-lily-d-ambrosio-mill-park','native_forest_logging','As Victorian Minister for Energy, Environment and Climate Change, D''Ambrosio (ALP) drove the government policy to phase out native forest logging, announcing on 7 Nov 2019 the plan to end all native forest logging in Victoria: ''This is the largest environmental protection plan in our state''s history... By ending the destruction of our old growth forests immediately, we''re protecting the habitat of our Greater Gliders, Leadbeater''s Possums, and many other threatened species.'' Logging in state forests ended 1 Jan 2024 and the enabling Act was later repealed.',1);
INSERT INTO "position" VALUES(1420,'victoria-gabrielle-de-vietri-richmond','gender_lgbtq','Greens MP for Richmond (since 2022). She is openly queer and is described as the first openly LGBTQ woman elected to the Victorian Legislative Assembly; she uses she/her and they/them pronouns. She serves as a Victorian Greens spokesperson on LGBTIQA+ rights and has been a public advocate for trans and gender-diverse people and stronger anti-vilification protections. In October 2023, as Greens LGBTIQA+ spokesperson, she opposed Moira Deeming''s motion for an inquiry into gender-affirming care, saying it would ''stoke the flames of transphobia and hate.''',1);
INSERT INTO "position" VALUES(1421,'victoria-gabrielle-de-vietri-richmond','drugs_law_order','Greens MLA for Richmond (which contains the North Richmond injecting room). De Vietri welcomed the 2023 decision to make the North Richmond medically supervised injecting room ongoing, saying ''it saves lives and provides pathways to better health, housing and employment for people who use injecting drugs,'' while pushing for expanded eligibility and additional injecting rooms to relieve pressure on the North Richmond site.',1);
INSERT INTO "position" VALUES(1422,'victoria-steve-dimopoulos-oakleigh','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Steve Dimopoulos voted YES (in favour).',1);
INSERT INTO "position" VALUES(1423,'victoria-steve-dimopoulos-oakleigh','gender_lgbtq','Labor MP for Oakleigh (since 2014) and, alongside Harriet Shing, one of Victoria''s first openly gay cabinet ministers when sworn into the Andrews ministry in June 2022. He is described as the first openly gay Greek-Australian minister in Victoria. He has held portfolios including Tourism, Sport and Major Events, Creative Industries and (until April 2026) Environment and Outdoor Recreation.',1);
INSERT INTO "position" VALUES(1424,'victoria-paul-edbrooke-frankston','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Paul Edbrooke voted YES (in favour).',1);
INSERT INTO "position" VALUES(1425,'victoria-maree-edwards-bendigo-west','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Maree Edwards voted YES (in favour).',1);
INSERT INTO "position" VALUES(1426,'victoria-matthew-guy-bulleen','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Matthew Guy voted NO (against).',1);
INSERT INTO "position" VALUES(1427,'victoria-matthew-guy-bulleen','gender_lgbtq','Liberal MP for Bulleen and a former Victorian Liberal leader (Opposition Leader 2014-2018 and 2021-2022). In October 2021, as Opposition Leader, he confirmed the Liberals would not reverse the conversion-practices ban: ''The Liberals will never bring back conversion therapy. Read that again.'' Before the 2022 election he announced that conservative candidate Renee Heath would not be permitted to sit in the parliamentary Liberal party room if elected, citing her church''s positions on gay, transgender and reproductive rights.',1);
INSERT INTO "position" VALUES(1428,'victoria-bronwyn-halfpenny-thomastown','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Bronwyn Halfpenny voted YES (in favour).',1);
INSERT INTO "position" VALUES(1429,'victoria-paul-hamer-box-hill','faith','Jewish. Wikipedia states "He is Jewish." His father is a survivor of the Holocaust, and in his first speech he said "after the horrors of the Holocaust it was Australia that gave my family a home."',1);
INSERT INTO "position" VALUES(1430,'victoria-david-hodgett-croydon','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). David Hodgett voted NO (against).',1);
INSERT INTO "position" VALUES(1431,'victoria-melissa-horne-williamstown','gambling','As Victorian Minister for Casino, Gaming and Liquor Regulation, announced (with Premier Daniel Andrews, July 2023) and carried the Gambling Legislation Amendment (Pre-commitment and Carded Play) Bill 2024, described as Australia''s most significant gambling-harm reforms - mandatory carded play with binding loss limits, a reduced $100 load-up limit (down from $1,000) and slower spin speeds. Said: ''Everyone loses when it comes to gambling harm... people lose their relationships, their jobs and their wellbeing.'' The bill passed the Legislative Assembly 53-25.',1);
INSERT INTO "position" VALUES(1432,'victoria-natalie-hutchins-sydenham','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Natalie Hutchins voted YES (in favour).',1);
INSERT INTO "position" VALUES(1433,'victoria-emma-kealy-lowan','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Emma Kealy voted YES (in favour).',1);
INSERT INTO "position" VALUES(1434,'victoria-sonya-kilkenny-carrum','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Sonya Kilkenny voted YES (in favour).',1);
INSERT INTO "position" VALUES(1435,'victoria-sonya-kilkenny-carrum','religious_freedom','As Attorney-General, Kilkenny led the Justice Legislation Amendment (Anti-vilification and Social Cohesion) reforms (passed April 2025), which repealed the Racial and Religious Tolerance Act 2001 and expanded anti-vilification protections. She stated that ''genuine and legitimate religious activities, such as worshipping, practising, proselytising and teaching religion - they will always remain someone''s right in Victoria under this Government.''',1);
INSERT INTO "position" VALUES(1436,'victoria-sonya-kilkenny-carrum','drugs_law_order','As Attorney-General, Kilkenny was a lead announcer of the March 2025 ''tough bail laws'', stating the laws were ''targeted squarely at the risks of young people committing serious crimes while out on bail'' and created the toughest bail tests ever for serious offences, including a presumption against bail for knife, weapon and gun offences. The reforms removed remand as a ''last resort'' and added new offences for committing an indictable offence while on bail and breaching bail conditions.',1);
INSERT INTO "position" VALUES(1437,'victoria-sonya-kilkenny-carrum','housing_planning','As Minister for Planning, Kilkenny drove Victoria''s Housing Statement planning reforms to boost housing supply (target of 800,000 new homes over a decade), including allowing small second homes/granny flats without a planning permit and streamlined ''townhouse and low-rise code'' changes: ''These changes will boost housing supply in a way that''s sensitive to every street, whether you''re building a second home for your children or selling off your backyard to help someone else buy theirs.''',1);
INSERT INTO "position" VALUES(1438,'victoria-tim-mccurdy-ovens-valley','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Tim McCurdy voted NO (against).',1);
INSERT INTO "position" VALUES(1439,'victoria-cindy-mcleish-eildon','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Cindy McLeish voted NO (against).',1);
INSERT INTO "position" VALUES(1440,'victoria-james-newbury-brighton','gender_lgbtq','Liberal MP for Brighton (since 2018), a factional moderate who has served as the Coalition''s equality spokesperson. He has been a vocal advocate for LGBTIQ+ rights within the Liberal Party. As equality spokesperson he gave an ''absolutely iron-clad guarantee'' (1 October 2021) that the Liberal Party would not roll back the conversion practices ban: ''there are no ifs, no buts.'' His stance drew opposition from hard-right elements of the party.',1);
INSERT INTO "position" VALUES(1441,'victoria-danny-o-brien-gippsland-south','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Danny O''Brien voted NO (against).',1);
INSERT INTO "position" VALUES(1442,'victoria-danny-o-brien-gippsland-south','drugs_law_order','Nationals MLA for Gippsland South. O''Brien has campaigned on rising regional crime, citing figures of ''62 crimes a day'' across Gippsland local government areas and saying ''These figures show the reality of rising crime across Gippsland.'' He backs a Nationals/Liberal law-and-order platform including hiring an additional 3,000 police officers and reopening closed or reduced-hours police stations.',1);
INSERT INTO "position" VALUES(1443,'victoria-michael-o-brien-malvern','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Michael O''Brien voted NO (against).',1);
INSERT INTO "position" VALUES(1444,'victoria-danny-pearson-essendon','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Danny Pearson voted YES (in favour).',1);
INSERT INTO "position" VALUES(1445,'victoria-john-pesutto-hawthorn','abortion','Pesutto (Liberal), Opposition Leader until December 2024, expressed personal support for abortion and said he would put the issue to a conscience vote, as noted in a 4 February 2025 Victorian Greens statement describing the recent Liberal leadership change.',1);
INSERT INTO "position" VALUES(1446,'victoria-john-pesutto-hawthorn','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). John Pesutto voted NO (against).',1);
INSERT INTO "position" VALUES(1447,'victoria-john-pesutto-hawthorn','gender_lgbtq','Liberal MP for Hawthorn and Leader of the Opposition / Victorian Liberal leader from December 2022 until a leadership spill on 27 December 2024; factionally a moderate. He is central to the Moira Deeming affair: after Deeming spoke at the ''Let Women Speak'' rally (18 March 2023) that was gatecrashed by neo-Nazis, Pesutto moved to discipline her, leading to her nine-month suspension and then expulsion from the party room (19-11) on 12 May 2023. Deeming sued him for defamation over imputations she associated with neo-Nazis; in December 2024 the Federal Court found Pesutto had defamed her, awarding $300,000 in damages plus large legal costs. As leader he stated that ''all people, irrespective of faith, sexual preference, race, ethnicity or gender they identify with, have an equal place in Victoria.''',1);
INSERT INTO "position" VALUES(1448,'victoria-tim-read-brunswick','gender_lgbtq','Greens MP for Brunswick (since 2018) and a medical doctor whose PhD concerned the epidemiology of sexually transmitted infections; he is the Greens spokesperson for Health. He supported the Greens motion and legislation to ban gay conversion practices and campaigned to reduce restrictions on gay and bisexual men donating blood, continuing to advocate for further easing of those restrictions.',1);
INSERT INTO "position" VALUES(1449,'victoria-tim-read-brunswick','drugs_law_order','Greens MLA for Brunswick and the party''s spokesperson on health, drug law reform and justice; a former physician. Read drafted the Drugs, Poisons and Controlled Substances Amendment (Pill Testing Pilot for Drug Harm Reduction) Bill 2019 and has led the Greens'' push for pill testing, framing drug use as a health issue rather than a criminal one. He also called for decriminalising public drunkenness, urging ''appropriate facilities, instead of relying on police cells.''',1);
INSERT INTO "position" VALUES(1450,'victoria-tim-richardson-mordialloc','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Tim Richardson voted NO (against).',1);
INSERT INTO "position" VALUES(1451,'victoria-richard-riordan-polwarth','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Richard Riordan voted NO (against).',1);
INSERT INTO "position" VALUES(1452,'victoria-brad-rowswell-sandringham','faith','Wikipedia reports that he "once studied to be a Catholic priest," indicating a Catholic faith background.',1);
INSERT INTO "position" VALUES(1453,'victoria-ellen-sandell-melbourne','abortion','Sandell, leader of the Victorian Greens, has publicly supported entrenching abortion access in the Victorian Constitution. In a 4 February 2025 Greens statement supporting the Constitution Amendment (Abortion) Bill 2024 she said ''People deserve to know where their leaders sit when it comes to their reproductive rights and access to essential healthcare,'' and warned it was ''frightening that all it takes is for a change of government to threaten our right to safely access abortion in Victoria, especially when the Liberals are lurching further to the right here.''',1);
INSERT INTO "position" VALUES(1454,'victoria-ellen-sandell-melbourne','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Ellen Sandell voted YES (in favour).',1);
INSERT INTO "position" VALUES(1455,'victoria-ellen-sandell-melbourne','religious_freedom','Sandell, Deputy Leader of the Victorian Greens, moved to remove the Lord''s Prayer from the Legislative Assembly, announcing in February 2023 that she would introduce a motion ''for the lower house to ditch it'' when Parliament returned, consistent with the Greens'' position favouring a secular opening to parliamentary proceedings.',1);
INSERT INTO "position" VALUES(1456,'victoria-ellen-sandell-melbourne','drugs_law_order','Leader of the Victorian Greens (MLA for Melbourne). Sandell condemned the government''s decision not to open a Melbourne CBD injecting room as ''cowardly... It leaves people who are struggling with heroin addiction to die on the streets of Melbourne.'' She strongly opposed Labor''s 2025 bail/youth justice laws allowing children to be tried in adult courts, saying ''Labor is ruining the lives of young people just to cling to power'' and that the laws would not increase community safety.',1);
INSERT INTO "position" VALUES(1457,'victoria-ellen-sandell-melbourne','first_nations','As Leader of the Victorian Greens, publicly backed the Statewide Treaty Bill 2025, saying Greens votes would ensure it passed and calling it "a historic moment where every Victorian has been invited to walk with First Nations people on this incredible journey." The Greens voted for the Bill.',1);
INSERT INTO "position" VALUES(1458,'victoria-david-southwick-caulfield','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). David Southwick voted NO (against).',1);
INSERT INTO "position" VALUES(1459,'victoria-david-southwick-caulfield','gender_lgbtq','Liberal MP for Caulfield and Deputy Liberal Leader. On the Change or Suppression (Conversion) Practices Prohibition Bill (10 December 2020) he moved a reasoned amendment seeking to delay the bill for further consultation, while saying he supported its substantive goals (''we can help stem the trauma by supporting this important bill''). In November 2022 he gave Aleph Melbourne (a Jewish LGBTQI organisation) a personal ''iron-clad guarantee'' that any Liberal amendment to the Equal Opportunity Act would ''protect our LGBTQIA+ community from discrimination,'' in the context of the Liberals'' proposal to adjust the Equal Opportunity (Religious Exceptions) provisions on faith-based school hiring.',1);
INSERT INTO "position" VALUES(1460,'victoria-david-southwick-caulfield','drugs_law_order','Liberal MLA for Caulfield and former Shadow Minister for Police and Crime Prevention. Southwick opposed a second injecting centre in the CBD, saying ''A second injecting centre in the wrong place is the last thing our struggling CBD and stretched frontline police need to be dealing with,'' and pointed to ''ongoing drug trafficking, anti-social behaviour and serious crime at the North Richmond Injecting Centre,'' arguing systemic problems at the first site should be fixed before any second site.',1);
INSERT INTO "position" VALUES(1461,'victoria-ros-spence-kalkallo','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Ros Spence voted YES (in favour). [Spence (then member for Yuroke)]',1);
INSERT INTO "position" VALUES(1462,'victoria-nick-staikos-bentleigh','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Nick Staikos voted YES (in favour).',1);
INSERT INTO "position" VALUES(1463,'victoria-nick-staikos-bentleigh','housing_planning','As Minister for Consumer Affairs, Staikos championed the Consumer and Planning Legislation Amendment (Housing Statement Reform) Bill 2024, which banned all forms of rental bidding, banned rental application fees, and lengthened notice periods for rent increases and notices to vacate: ''Victoria has the strongest rental protections in the country and this builds on our significant work to make renting fairer across the state.''',1);
INSERT INTO "position" VALUES(1464,'victoria-natalie-suleyman-st-albans','faith','Reported as the first Muslim woman elected to the Victorian Parliament. Wikipedia states she "is the first person of Turkish origin, as well as the first Muslim woman, to be elected to the Victorian Parliament."',1);
INSERT INTO "position" VALUES(1465,'victoria-natalie-suleyman-st-albans','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Natalie Suleyman voted NO (against).',1);
INSERT INTO "position" VALUES(1466,'victoria-mary-anne-thomas-macedon','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Mary-Anne Thomas voted YES (in favour).',1);
INSERT INTO "position" VALUES(1467,'victoria-mary-anne-thomas-macedon','health','Victorian Minister for Health and Ambulance Services (Andrews/Allan Labor governments) until she stepped down in April 2026. As minister she rolled out Urgent Care Clinics, the Virtual ED and the state''s first Virtual hospital, and introduced Standards for Safe and Timely Ambulance and Emergency Care to speed ambulance-to-ED handover. In her April 2026 statement she said the government ''established Urgent Care Clinics, the Virtual ED and our first Virtual hospital'' and that planned-surgery reform ''has seen Victoria deliver a record number of surgeries.''',1);
INSERT INTO "position" VALUES(1468,'victoria-bill-tilley-benambra','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Bill Tilley voted NO (against).',1);
INSERT INTO "position" VALUES(1469,'victoria-peter-walsh-murray-plains','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Peter Walsh voted NO (against).',1);
INSERT INTO "position" VALUES(1470,'victoria-vicki-ward-eltham','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Vicki Ward voted YES (in favour).',1);
INSERT INTO "position" VALUES(1471,'victoria-vicki-ward-eltham','gender_lgbtq','Labor MP for Eltham (since 2014). In the December 2024 ministerial reshuffle she became Victoria''s Minister for Equality (the portfolio passing to her from Harriet Shing), a role that leads the government''s work to remove discrimination from Victorian laws and services and to promote inclusion of LGBTIQA+ communities, working with the Commissioner for LGBTIQA+ Communities.',1);
INSERT INTO "position" VALUES(1472,'victoria-kim-wells-rowville','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Kim Wells voted NO (against).',1);
INSERT INTO "position" VALUES(1473,'victoria-nicole-werner-warrandyte','faith','A Christian who previously worked as a youth pastor at the Pentecostal megachurch Planetshakers. In her maiden speech she spoke about discrimination she faced as a person of faith.',1);
INSERT INTO "position" VALUES(1474,'victoria-gabrielle-williams-dandenong','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Gabrielle Williams voted YES (in favour).',1);
INSERT INTO "position" VALUES(1475,'victoria-ryan-batchelor-southern-metropolitan','hunting','As chair of the Legislative Council Select Committee on Victoria''s Recreational Native Bird Hunting Arrangements (2023), Batchelor led and endorsed the committee''s majority report recommending an end to the annual native bird (duck and quail) hunting season on all public and private land from 2024. He supported the ban recommendation.',1);
INSERT INTO "position" VALUES(1476,'victoria-melina-bath-eastern-victoria','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Melina Bath voted NO (against).',1);
INSERT INTO "position" VALUES(1477,'victoria-melina-bath-eastern-victoria','gender_lgbtq','Nationals MLC for Eastern Victoria. In October 2023 she voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1478,'victoria-melina-bath-eastern-victoria','hunting','Nationals member of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023). Bath filed a minority report opposing a ban and supporting the continuation of recreational duck/native bird hunting; she has repeatedly defended regulated duck hunting in the Legislative Council.',1);
INSERT INTO "position" VALUES(1479,'victoria-lizzie-blandthorn-western-metropolitan','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Assembly (conscience vote; the bill passed the Assembly 47-37 on 20 October 2017). Lizzie Blandthorn voted NO (against). [Blandthorn (then member for Pascoe Vale in the Assembly; now in the Council)]',1);
INSERT INTO "position" VALUES(1480,'victoria-jeff-bourman-eastern-victoria','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Jeff Bourman voted NO (against). [Division list records: Bourman (listed as Jeffrey Bourman)]',1);
INSERT INTO "position" VALUES(1481,'victoria-jeff-bourman-eastern-victoria','religious_freedom','Bourman (Shooters, Fishers and Farmers) was one of nine Legislative Council members who voted against the Change or Suppression (Conversion) Practices Prohibition Bill in February 2021, joining opponents who cited concerns about freedom of thought, religion and conscience.',1);
INSERT INTO "position" VALUES(1482,'victoria-jeff-bourman-eastern-victoria','hunting','Shooters, Fishers and Farmers Party member of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023). Bourman filed a minority report opposing the ban recommendation and strongly supporting the continuation of recreational duck/native bird hunting.',1);
INSERT INTO "position" VALUES(1483,'victoria-katherine-copsey-southern-metropolitan','gender_lgbtq','Greens MLC for Southern Metropolitan (since 2022). She publicly criticised the anti-trans content of Moira Deeming''s February 2023 inaugural speech, describing Deeming''s language as ''absolutely shocking,'' and the Victorian Greens have campaigned (with Copsey among members) to expand the state''s anti-vilification laws to better protect LGBTIQA+ people.',1);
INSERT INTO "position" VALUES(1484,'victoria-katherine-copsey-southern-metropolitan','hunting','Greens member of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023). She supported the committee''s majority recommendation to end recreational native bird (duck and quail) hunting on all public and private land from 2024.',1);
INSERT INTO "position" VALUES(1485,'victoria-georgie-crozier-southern-metropolitan','abortion','Crozier (Liberal, Shadow Health Minister) said of a 2022 crossbench bill on conscientious objection by religiously affiliated hospitals that she had not yet seen the legislation, stating ''I need to see the details in the bill. I''m very supportive of women''s rights.'' In February 2025 debate she characterised the Greens'' Constitution Amendment (Abortion) Bill 2024 to entrench abortion in the constitution as a political manoeuvre rather than genuinely protecting abortion from politicisation.',1);
INSERT INTO "position" VALUES(1486,'victoria-georgie-crozier-southern-metropolitan','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Georgie Crozier voted NO (against). [Division list records: Crozier (listed as Georgina Crozier)]',1);
INSERT INTO "position" VALUES(1487,'victoria-georgie-crozier-southern-metropolitan','gender_lgbtq','Liberal MLC for Southern Metropolitan (since 2010), a former nurse and midwife. In October 2023 she spoke in support of Moira Deeming''s motion for a parliamentary inquiry into gender-affirming care and questioned whether the Change or Suppression (Conversion) Practices Prohibition Act was ''actually working,'' and voted for the motion, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1488,'victoria-georgie-crozier-southern-metropolitan','drugs_law_order','Liberal MLC and shadow health spokesperson. Crozier has opposed the location of the North Richmond injecting room and a second CBD facility, arguing trials should be in non-residential areas: ''If Daniel Andrews was serious about protecting the community, he would immediately move the trial away from a school, family homes and small businesses.'' She has raised parliamentary questions about resident safety and CCTV coverage around the North Richmond precinct.',1);
INSERT INTO "position" VALUES(1489,'victoria-georgie-crozier-southern-metropolitan','health','Victorian Shadow Minister for Health and Ambulance Services (Liberal, Legislative Council). A former nurse and midwife, she is a persistent critic of Labor''s health record, focusing on ambulance ramping and response times, hospital pressures and elective-surgery wait lists, and has raised failures of code-1 ambulance response benchmarks in regional Victoria in Parliament.',1);
INSERT INTO "position" VALUES(1490,'victoria-david-davis-southern-metropolitan','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). David Davis voted NO (against).',1);
INSERT INTO "position" VALUES(1491,'victoria-david-davis-southern-metropolitan','gender_lgbtq','Liberal MLC for Southern Metropolitan and a long-serving senior Liberal. In October 2023 he voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1492,'victoria-moira-deeming-western-metropolitan','faith','Identifies as Presbyterian. Wikipedia states she "identifies as Maori and a Presbyterian." She is widely reported as a devout Christian and has publicly defended retention of the Lord''s Prayer in Parliament.',1);
INSERT INTO "position" VALUES(1493,'victoria-moira-deeming-western-metropolitan','abortion','Deeming (Liberal) holds anti-abortion views. Her Wikipedia biography states she ''believes that laws legalising abortion need to be repealed'' and ''thinks that rape victims should reject abortions and turn to the church.'' Writing on a Christian news website she described abortion as a ''terrible evil'' and wrote that each abortion ''wounds a mother and father, murders an unborn child, and ends a whole family line.''',1);
INSERT INTO "position" VALUES(1494,'victoria-moira-deeming-western-metropolitan','gender_lgbtq','Liberal MLC for Western Metropolitan and a prominent social conservative on gender issues. She co-organised and spoke at the ''Let Women Speak'' (Kellie-Jay Keen-Minshull / ''Posie Parker'') rally on the steps of Parliament House in Melbourne on 18 March 2023, which was gatecrashed by members of the neo-Nazi National Socialist Network who performed Nazi salutes. After the rally, then-Liberal leader John Pesutto moved to expel her; she accepted a nine-month suspension from the parliamentary Liberal Party on 27 March 2023, then was expelled from the party room by 19 votes to 11 on 12 May 2023. She sued Pesutto for defamation over imputations that she associated with neo-Nazis; in December 2024 the Federal Court found Pesutto had defamed her and awarded $300,000 in damages. She was readmitted to the parliamentary Liberal Party on 27 December 2024. Deeming has campaigned against transgender ''gender ideology'', opposed allowing trans women in female sport, criticised the Safe Schools program, and has been a vocal advocate for what she frames as women''s sex-based rights. In October 2023 she moved a motion in the Legislative Council calling for a parliamentary inquiry into gender-affirming care; it was defeated 21-16, with the Liberals, Nationals and conservative crossbenchers voting in support and Labor and the Greens opposing.',1);
INSERT INTO "position" VALUES(1495,'victoria-moira-deeming-western-metropolitan','religious_freedom','Deeming, a Presbyterian, is a prominent religious-conservative voice in the Legislative Council. Her Wikipedia biography records her conservative-Christian positions, including the view that rape victims should reject abortion and turn to the church, and documents her opposition to a range of progressive social measures. She supported the July 2024 petition to retain the Lord''s Prayer in the Legislative Council, telling Parliament she had been ''overwhelmed by the number of religious communities - not necessarily Christian communities'' who wanted the prayer retained.',1);
INSERT INTO "position" VALUES(1496,'victoria-david-ettershank-western-metropolitan','drugs_law_order','Legalise Cannabis Party MLC. Ettershank introduced the Road Safety Amendment (Medicinal Cannabis) Bill 2023 and successfully amended an omnibus roads bill so that from 1 March 2025 medicinal cannabis patients driving unimpaired no longer automatically lose their licence, with magistrates given discretion on impairment. He also welcomed the government''s Drugs, Poisons and Controlled Substances Amendment (Pill Testing) Bill 2024, saying ''drug checking has been effective in saving lives wherever it has been provided.'' His party also introduced a bill for personal adult use of cannabis.',1);
INSERT INTO "position" VALUES(1497,'victoria-michael-galea-south-eastern-metropolitan','gender_lgbtq','Labor MLC for South-Eastern Metropolitan (since 2022). He is Deputy Chair of the Legislative Council Legal and Social Issues Committee''s inquiry into anti-LGBTQIA+ hate crimes and co-chairs the Victorian government''s LGBTIQA+ Justice Working Group. On the hate-crimes inquiry he said ''this is a global phenomenon and it will require global solutions,'' referencing Victoria''s ''post-and-boast'' laws and support for services such as Switchboard Victoria.',1);
INSERT INTO "position" VALUES(1498,'victoria-michael-galea-south-eastern-metropolitan','hunting','Deputy chair of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023). He supported the committee''s majority recommendation to end the annual native bird (duck and quail) hunting season on all public and private land from 2024.',1);
INSERT INTO "position" VALUES(1499,'victoria-renee-heath-eastern-victoria','faith','Reported as a lifelong member of the City Builders'' church, a Pentecostal church led in Australia by her father, pastor Brian Heath. Described in reporting as a conservative Pentecostal Christian.',1);
INSERT INTO "position" VALUES(1500,'victoria-renee-heath-eastern-victoria','gender_lgbtq','Liberal MLC for Eastern Victoria, elected 2022. A social conservative and lifelong member of the City Builders'' church (led in Australia by her father, pastor Brian Heath), an organisation that has been accused of historic links to gay conversion practices. Before the 2022 election, then-Liberal leader Matthew Guy said Heath would not be permitted to sit in the parliamentary party room if elected, citing the church''s opposition to gay, transgender and reproductive rights; new leader John Pesutto reversed that decision and appointed her Secretary of the Parliamentary Liberal Party. She was a close ally of Moira Deeming and was demoted as party-room Secretary on 12 May 2023 during the caucus vote on Deeming''s expulsion. In October 2025 her sister Clare Heath-McIvor testified to a Victorian parliamentary inquiry about conversion practices allegedly linked to the church. In October 2023 she voted for Moira Deeming''s motion calling for an inquiry into gender-affirming care (defeated 21-16).',1);
INSERT INTO "position" VALUES(1501,'victoria-renee-heath-eastern-victoria','religious_freedom','Heath, a conservative Pentecostal and lifelong member of the City Builders'' church (led by her father), framed religious liberty as a central theme of her inaugural speech (20 December 2022), stating: ''Victorians should not be told what to think, what to say, how to worship, how to raise their children,'' which she characterised as ''a failed socialist experiment which has reinvented itself as a cultural movement.''',1);
INSERT INTO "position" VALUES(1502,'victoria-ann-marie-hermans-south-eastern-metropolitan','gender_lgbtq','Liberal MLC for South-Eastern Metropolitan (since 2022), considered part of the ''religious right'' faction of the Victorian Liberal Party. In 2023 she voted against the successful party-room motion to expel fellow conservative Moira Deeming. She has publicly criticised the Andrews government''s gender and sexuality policies and characterised the Change or Suppression (Conversion) Practices Prohibition Act as an ''overreach'' that, in her view, strips individuals of the right to consent to private practices such as counselling or prayer. In October 2023 she voted for Moira Deeming''s motion calling for an inquiry into gender-affirming care (defeated 21-16).',1);
INSERT INTO "position" VALUES(1503,'victoria-ann-marie-hermans-south-eastern-metropolitan','religious_freedom','Hermans (Liberal), considered part of the ''religious right'' faction of the Victorian Liberal Party and a former Family First candidate, has raised religious-freedom concerns about anti-vilification legislation, characterising it as overreach and warning of ''a potential threat here to the freedom of speech and freedom of religion.''',1);
INSERT INTO "position" VALUES(1504,'victoria-shaun-leane-north-eastern-metropolitan','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Shaun Leane voted YES (in favour).',1);
INSERT INTO "position" VALUES(1505,'victoria-david-limbrick-south-eastern-metropolitan','gender_lgbtq','MLC for South-Eastern Metropolitan, elected 2018 for the Liberal Democrats and now a member of the Libertarian Party. In February 2021 he announced he would vote against (and voted against) the Change or Suppression (Conversion) Practices Prohibition Bill, arguing on libertarian grounds that it ''tramples over several human rights'' in the Victorian Charter including freedom of thought, conscience, religion and expression, and that adults should be free to approach faith leaders about their lives. He framed his opposition as the government not interfering in private choices rather than support for conversion practices. In October 2023 he spoke for, and voted for, Moira Deeming''s motion calling for an inquiry into gender-affirming care (defeated 21-16).',1);
INSERT INTO "position" VALUES(1506,'victoria-david-limbrick-south-eastern-metropolitan','religious_freedom','Limbrick (then Liberal Democrats) was one of nine Legislative Council members who voted against the Change or Suppression (Conversion) Practices Prohibition Bill in February 2021. He and other opponents stated they did not support harmful practices but would not back the bill because it ''oppresses basic human rights, including freedom of thought, religion and conscience.''',1);
INSERT INTO "position" VALUES(1507,'victoria-david-limbrick-south-eastern-metropolitan','drugs_law_order','Libertarian Party MLC who lists drug law reform among his priority areas. Limbrick has advocated drug-checking/pill-testing services and harm reduction, voting in support of the government''s Drugs, Poisons and Controlled Substances Amendment (Pill Testing) Bill 2024 (passed the Legislative Council 29 October 2024, 23 votes to 16). He argues for bodily autonomy and against criminal sanctions for personal drug use.',1);
INSERT INTO "position" VALUES(1508,'victoria-wendy-lovell-northern-victoria','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Wendy Lovell voted NO (against).',1);
INSERT INTO "position" VALUES(1509,'victoria-wendy-lovell-northern-victoria','gender_lgbtq','Liberal MLC for Northern Victoria. In October 2023 she voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1510,'victoria-trung-luu-western-metropolitan','gender_lgbtq','Liberal MLC for Western Metropolitan. In October 2023 he voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1511,'victoria-sarah-mansfield-western-victoria','abortion','Mansfield (Australian Greens, health spokesperson) introduced the Constitution Amendment (Abortion) Bill 2024 into the Legislative Council on 12 November 2024, which sought to entrench the Abortion Law Reform Act 2008 in the Victorian Constitution so it could only be altered by a three-fifths supermajority. Seconding the bill on 4 February 2025 she said ''Abortion is already a postcode lottery in Victoria, we can''t risk a change in government further threatening access to this essential healthcare'' and ''If there was ever a time to do this, it''s now.''',1);
INSERT INTO "position" VALUES(1512,'victoria-sarah-mansfield-western-victoria','gender_lgbtq','Greens MLC for Western Victoria and Deputy Leader of the Victorian Greens; a general practitioner by profession and the party''s health spokesperson. In October 2023, responding to Moira Deeming''s motion for an inquiry into gender-affirming care, she said ''the right to access gender-affirming care is supported by all major medical bodies in Australia and the World Health Organisation,'' and the Greens opposed the motion (defeated 21-16).',1);
INSERT INTO "position" VALUES(1513,'victoria-sarah-mansfield-western-victoria','drugs_law_order','Greens MLC and Co-Deputy Leader; a former GP. Mansfield has called for a medically supervised injecting room in Geelong, citing high regional overdose deaths and the arrival of potent synthetic opioids: ''Medically supervised injecting rooms save lives. They not only prevent overdoses by providing immediate treatment, they also link people with addiction support and other social services.'' She has urged the government to develop a synthetic opioids plan for Victoria.',1);
INSERT INTO "position" VALUES(1514,'victoria-bev-mcarthur-western-victoria','gender_lgbtq','Liberal MLC for Western Victoria. In February 2021 she crossed the floor to vote against the Change or Suppression (Conversion) Practices Prohibition Bill 2020, arguing it interfered with individual autonomy (''This is not about electric shocks. This is about free individuals seeking advice...''). She has argued individuals transitioning should be given ''honest and open advice'' and that parents should be able to counsel their children. She supported (with Moira Deeming) a Liberal State Council motion urging the federal party to ban trans women and girls from women''s sport. In October 2023 she spoke for, and voted for, Moira Deeming''s motion calling for an inquiry into gender-affirming care (defeated 21-16).',1);
INSERT INTO "position" VALUES(1515,'victoria-bev-mcarthur-western-victoria','religious_freedom','McArthur crossed the floor to vote against the Change or Suppression (Conversion) Practices Prohibition Bill 2020/2021. In Parliament (4 February 2021) she framed her opposition around individual liberty, arguing: ''This is not about electric shocks. This is about free individuals seeking advice on deeply personal matters,'' and that ''individuals should be free to seek counselling, advice or care on any matter that they see fit without the interference of government.'' She was one of nine members who voted against the bill in the Legislative Council.',1);
INSERT INTO "position" VALUES(1516,'victoria-bev-mcarthur-western-victoria','hunting','Liberal member of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023). McArthur filed a minority report opposing the committee''s ban recommendation and supporting the continuation of recreational native bird (duck and quail) hunting.',1);
INSERT INTO "position" VALUES(1517,'victoria-joe-mccracken-western-victoria','gender_lgbtq','Liberal MLC for Western Victoria. In October 2023 he voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16. He chairs the Legislative Council Legal and Social Issues Committee''s inquiry into anti-LGBTQIA+ hate crimes (hearings 2026), stating ''violence against any Victorian because of who they are is wrong.''',1);
INSERT INTO "position" VALUES(1518,'victoria-nick-mcgowan-north-eastern-metropolitan','gender_lgbtq','Liberal MLC for North-Eastern Metropolitan. In October 2023 he voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1519,'victoria-evan-mulholland-northern-metropolitan','gender_lgbtq','Liberal MLC for Northern Metropolitan. In October 2023 he voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1520,'victoria-evan-mulholland-northern-metropolitan','religious_freedom','Mulholland (Liberal) sponsored the petition (nearly 11,000 signatures) to retain the Lord''s Prayer in Legislative Council proceedings, debated 31 July 2024. He argued ''This place is deeply rooted in traditions and our Christian foundations that have made our democracy so strong,'' and wrote that ''any attempt to remove faith from Parliament - the public square - must be resisted at all costs,'' adding that representatives ''make decisions informed by our values, and those values at times are inseparable from our faith.'' The Labor government subsequently abandoned plans to replace the prayer.',1);
INSERT INTO "position" VALUES(1521,'victoria-evan-mulholland-northern-metropolitan','drugs_law_order','Liberal MLC. Mulholland introduced the Bail Amendment (Indictable Offences Whilst on Bail) Bill 2024 (first reading 20 February 2024), a private member''s bill to retain the offence of committing an indictable offence while on bail and prevent its repeal under the 2023 bail changes, automatically elevating the bail test for those who reoffend while on bail. The bill''s second reading was defeated on 6 March 2024.',1);
INSERT INTO "position" VALUES(1522,'victoria-evan-mulholland-northern-metropolitan','hunting','Liberal member of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023). Mulholland filed a minority report opposing the committee''s ban recommendation and supporting the continuation of recreational native bird (duck and quail) hunting.',1);
INSERT INTO "position" VALUES(1523,'victoria-rachel-payne-south-eastern-metropolitan','abortion','Payne (Legalise Cannabis Party) describes herself as ''unequivocally pro-choice'' and opposes conscientious objection provisions in Victoria''s abortion laws, arguing ''to work in public health is to serve the needs of all patients.'' In October 2025 she co-authored, with Georgie Purcell, a report calling for medical and surgical abortion to be made free to every Victorian, expanded surgical provision in public hospitals, extending medical abortion access from nine to twelve weeks, and oversight of conscientious objection.',1);
INSERT INTO "position" VALUES(1524,'victoria-rachel-payne-south-eastern-metropolitan','gender_lgbtq','Legalise Cannabis MLC for South-Eastern Metropolitan (since 2022) and an LGBTIQ advocate. On Transgender Day of Remembrance (28 November 2024) she made a Legislative Council statement in solidarity with trans and gender-diverse people, citing high rates of violence and suicidal thoughts and criticising parliamentarians who use ''child safety'' as a pretext for vilification. She has supported gender-affirming care for minors, anti-vilification laws and LGBTIQ+ legal services, and praised Minister Harriet Shing''s ''unwavering allyship.''',1);
INSERT INTO "position" VALUES(1525,'victoria-rachel-payne-south-eastern-metropolitan','drugs_law_order','Legalise Cannabis Party MLC. With David Ettershank, Payne co-introduced the Road Safety Amendment (Medicinal Cannabis) Bill 2023 to end automatic licence loss for unimpaired medicinal cannabis drivers; the resulting reform took effect 1 March 2025. She voted in support of the government''s Pill Testing Bill 2024 (passed 29 October 2024) and introduced the Drugs, Poisons and Controlled Substances Amendment (Regulation of Personal Adult Use of Cannabis) Bill 2023 to allow personal adult cannabis use.',1);
INSERT INTO "position" VALUES(1526,'victoria-aiv-puglielli-north-eastern-metropolitan','gender_lgbtq','Greens MLC for North-Eastern Metropolitan (elected 2022), the youngest member of the Victorian Parliament and openly queer. He serves as the Greens spokesperson for LGBTIQA+ equality and has used his platform to advocate for trans and gender-diverse people and to call for expanded anti-vilification laws covering gender and sexuality. He has spoken about his rights being ''on public trial'' and said the parliament ''needs more queer voices... more trans and gender-diverse voices.'' In October 2023 he spoke against Moira Deeming''s motion for an inquiry into gender-affirming care, calling it a ''waste of our time'' (motion defeated 21-16).',1);
INSERT INTO "position" VALUES(1527,'victoria-aiv-puglielli-north-eastern-metropolitan','drugs_law_order','Greens MLC and the party''s drug harm reduction spokesperson. Puglielli has repeatedly pressed for a pill testing/drug-checking trial (''Setting up a pill testing trial this year will help keep young Victorians safe'') and for more safe injecting rooms, warning the decision not to open a Melbourne CBD injecting room was ''gutless and will leave countless Victorians vulnerable.'' He advocates decriminalisation of personal drug use, ''directing people who use drugs to health services for help, not prison for harm,'' plus banning sniffer dogs at festivals and increased harm-reduction funding.',1);
INSERT INTO "position" VALUES(1528,'victoria-georgie-purcell-northern-victoria','abortion','Purcell (Animal Justice Party) is a vocal advocate for expanded abortion access. In a June 2022 Guardian opinion piece she argued nurses should be permitted to prescribe medical abortions, and in Parliament has spoken in favour of expanding abortion services in rural and regional Victoria, drawing on her own experience of difficulties accessing services and harassment before safe access zones. In October 2025 she co-authored, with Rachel Payne, a report calling for free medical and surgical abortion for all Victorians, expanded public-hospital provision, and extending medical abortion access from nine to twelve weeks.',1);
INSERT INTO "position" VALUES(1529,'victoria-georgie-purcell-northern-victoria','hunting','Animal Justice Party member of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023) and a leading campaigner against duck shooting. She supported the committee''s majority recommendation to end recreational native bird (duck and quail) hunting on all public and private land from 2024.',1);
INSERT INTO "position" VALUES(1530,'victoria-harriet-shing-eastern-victoria','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Harriet Shing voted YES (in favour).',1);
INSERT INTO "position" VALUES(1531,'victoria-harriet-shing-eastern-victoria','gender_lgbtq','Labor MLC for Eastern Victoria (since 2014) and the first openly lesbian member of the Parliament of Victoria. In June 2022 she was appointed Minister for Equality (alongside Steve Dimopoulos, becoming one of Victoria''s first openly gay cabinet ministers). She was a vocal supporter of the Change or Suppression (Conversion) Practices Prohibition Bill, speaking in the February 2021 debate to acknowledge survivors and the harms of conversion practices, and has publicly criticised the Liberal Party''s record on LGBTQI protections. She is a member of the Labor Left. As Minister for Equality she spoke against Moira Deeming''s October 2023 motion for an inquiry into gender-affirming care (defeated 21-16). From April 2026 she became Minister for Health, Ambulance Services and Water.',1);
INSERT INTO "position" VALUES(1532,'victoria-harriet-shing-eastern-victoria','religious_freedom','Shing (Labor) voted in favour of the Change or Suppression (Conversion) Practices Prohibition Bill in the Legislative Council in February 2021, supporting the government''s ban on conversion practices.',1);
INSERT INTO "position" VALUES(1533,'victoria-harriet-shing-eastern-victoria','health','Appointed Victorian Minister for Health (also Ambulance Services and Water) in April 2026 in Premier Jacinta Allan''s cabinet reshuffle, replacing Mary-Anne Thomas. Tasked with steering the health system through workforce pressures, demand challenges and cost-of-living impacts, with the government''s stated aim of making care ''easier and cheaper for busy families to access.''',1);
INSERT INTO "position" VALUES(1534,'victoria-adem-somyurek-northern-metropolitan','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Adem Somyurek voted NO (against).',1);
INSERT INTO "position" VALUES(1535,'victoria-adem-somyurek-northern-metropolitan','gender_lgbtq','MLC for Northern Metropolitan (elected 2022 with the Democratic Labour Party; previously a Labor minister). In October 2023 he voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1536,'victoria-ingrid-stitt-western-metropolitan','religious_freedom','As Minister for Multicultural Affairs, Stitt was a quoted government minister in the April 2025 announcement of the Justice Legislation Amendment (Anti-vilification and Social Cohesion) reforms, which extend vilification protections including for religion while the government maintained that legitimate religious expression remains protected.',1);
INSERT INTO "position" VALUES(1537,'victoria-jaclyn-symes-northern-victoria','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Jaclyn Symes voted YES (in favour).',1);
INSERT INTO "position" VALUES(1538,'victoria-jaclyn-symes-northern-victoria','gender_lgbtq','Labor MLC for Northern Victoria; she was Victoria''s Attorney-General (2018-2023) and the government carried the Change or Suppression (Conversion) Practices Prohibition Bill, which passed in February 2021. She stated that ''bigoted and harmful change or suppression practices are not tolerated in Victoria.''',1);
INSERT INTO "position" VALUES(1539,'victoria-jaclyn-symes-northern-victoria','religious_freedom','As Attorney-General, Symes carried the Change or Suppression (Conversion) Practices Prohibition legislation, stating ''This bill does not outlaw prayer. It does not prevent health professionals from doing their job'' and that the practices ''are deeply harmful and total quackery - they must be stamped out.'' On the July 2024 Lord''s Prayer petition she said: ''There is no proposal to remove the Lord''s Prayer from the Parliament. We have not been considering a proposal,'' describing only ''minor conversations'' about modernising procedures.',1);
INSERT INTO "position" VALUES(1540,'victoria-sonja-terpstra-north-eastern-metropolitan','gender_lgbtq','Labor MLC (North-Eastern Metropolitan since 2018). She spoke in support of the Change or Suppression (Conversion) Practices Prohibition Bill during the February 2021 debate, describing opposition to it as ''ridiculous'' and saying the bill ''is about supporting people, not telling them they are wrong or broken.''',1);
INSERT INTO "position" VALUES(1541,'victoria-gayle-tierney-western-victoria','voluntary_assisted_dying','Voted on the Voluntary Assisted Dying Bill 2017 in the Victorian Legislative Council (conscience vote; the bill passed the Council 22-18 on 22 November 2017). Gayle Tierney voted YES (in favour).',1);
INSERT INTO "position" VALUES(1542,'victoria-rikkie-lee-tyrrell-northern-victoria','gender_lgbtq','Pauline Hanson''s One Nation MLC for Northern Victoria. In October 2023 she voted for Moira Deeming''s motion calling for a parliamentary inquiry into gender-affirming care, which was defeated 21-16.',1);
INSERT INTO "position" VALUES(1543,'victoria-sheena-watt-northern-metropolitan','gender_lgbtq','Labor MLC for Northern Metropolitan (since 2020). She spoke in support of the Change or Suppression (Conversion) Practices Prohibition Bill during the February 2021 debate, describing conversion practices as ''harmful and insidious.''',1);
INSERT INTO "position" VALUES(1544,'victoria-sheena-watt-northern-metropolitan','hunting','Labor member of the Victorian Legislative Council Select Committee on Recreational Native Bird Hunting Arrangements (2023). Unlike the committee''s majority ban recommendation, Watt filed a minority report opposing a ban; it did not support ending hunting and instead set out recommendations providing a path forward for duck hunting centred on First Nations self-determination and cultural practices.',1);
INSERT INTO "position" VALUES(1545,'western-australia-tony-buti-armadale','voluntary_assisted_dying','Tony Buti voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1546,'western-australia-tony-buti-armadale','gender_lgbtq','Labor MLA (Armadale) and Attorney General. Buti is leading the Cook Labor Government''s commitment to ban LGBTIQA+ conversion practices. He stated: "Conversion practices that are used to attempt to suppress or change an individual''s sexual orientation or gender identity are not therapeutic and they cause mental health harm to LGBTIQA+ people" and "The Cook Labor Government is committed to banning LGBTIQA+ conversion practices." He said legislation to criminalise conversion therapy, with a complementary civil response scheme for survivors, would be introduced to parliament in 2026, with continued stakeholder engagement on drafting.',1);
INSERT INTO "position" VALUES(1547,'western-australia-tony-buti-armadale','religious_freedom','As WA Attorney General following the March 2025 election, Buti announced that a ban on conversion practices would be introduced to Parliament by the end of 2025, with a model including ''criminal prohibition and a civil response scheme.'' Critics noted the proposed religious protection covers only ''a mere expression of belief or religious principle which is not intended to change or suppress an individual''s sexual orientation or gender identity.'' The Cook Government, in which Buti serves, has committed to reforming and narrowing the religious exemptions under the Equal Opportunity Act and to strengthening protections for LGBTIQA+ staff and students in religious schools. His office''s response to Groenewald''s June 2026 question on Christian freedom of expression committed to legislation that ''achieves a balance between the rights and interests of the diverse community.''',1);
INSERT INTO "position" VALUES(1548,'western-australia-david-michael-balcatta','voluntary_assisted_dying','David Michael voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1549,'western-australia-reece-whitby-baldivis','voluntary_assisted_dying','Reece Whitby voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1550,'western-australia-reece-whitby-baldivis','drugs_law_order','Whitby is Minister for Police; Road Safety; Tourism; Great Southern in the Cook Labor Government, overseeing the Western Australia Police Force. His portfolio includes enforcement of WA''s knife and edged-weapon laws, which took effect on 20 December 2024 under the Police Legislation Amendment Act 2024. Those laws define ''edged weapons'' to include knives, machetes, sickles, scythes and axes, make carrying an edged weapon without lawful excuse an offence (max 3 years jail and $36,000 fine), bar sale/supply to under-18s, and empower metal-detector (''wanding'') searches, with ''personal defence'' explicitly excluded as a lawful excuse.',1);
INSERT INTO "position" VALUES(1551,'western-australia-reece-whitby-baldivis','native_forest_logging','As WA Minister for Environment and Climate Action, Whitby (ALP) supported the WA Labor government''s decision to end commercial native forest logging (effective 1 Jan 2024), stating: ''This decision is a historic moment for WA. Our State is now one of the first in Australia to end native logging.''',1);
INSERT INTO "position" VALUES(1552,'western-australia-dave-kelly-bassendean','voluntary_assisted_dying','Dave Kelly voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1553,'western-australia-kim-giddens-bateman','drugs_law_order','Giddens announced (9 January 2025) a $14.5 million Cook Labor Government juvenile justice package targeting violent young offenders. Measures included trials for young repeat violent offenders within 28 days, immediate review of bail decisions for violent youth offenders, $1 million for tracking technology for offenders on bail, and penalties for responsible adults who fail to report bail curfew breaches. The package also funded a $13.5 million satellite Children''s Court (former Armadale Court site) with an additional magistrate and a dedicated therapeutic court. Giddens said ''Every Western Australian has a right to feel safe in their own home,'' describing the measures as ''common-sense reforms'' delivering ''swifter outcomes for the victims and families of youth crime.''',1);
INSERT INTO "position" VALUES(1554,'western-australia-cassie-rowe-belmont','voluntary_assisted_dying','Cassie Rowe voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1555,'western-australia-lisa-o-malley-bicton','voluntary_assisted_dying','Lisa O''Malley voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1556,'western-australia-don-punch-bunbury','voluntary_assisted_dying','Don Punch voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1557,'western-australia-stephen-price-forrestfield','voluntary_assisted_dying','Stephen Price voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1558,'western-australia-simone-mcgurk-fremantle','voluntary_assisted_dying','Simone McGurk voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1559,'western-australia-meredith-hammat-girrawheen','gender_lgbtq','Labor MLA (Girrawheen). As Health Minister she handled the final stages of the surrogacy/ART reform legislation, advising in 2025 of an 18-month implementation period following passage of the bill that allows same-sex couples, single people and trans and intersex West Australians to access assisted reproductive technology and surrogacy.',1);
INSERT INTO "position" VALUES(1560,'western-australia-meredith-hammat-girrawheen','health','WA Minister for Health and Mental Health (Cook Labor government, promoted March 2025). Chairs a new Cabinet Sub-Committee for Health Coordination bringing together Health Infrastructure, Preventative Health, Aged Care and Medical Research ministers, saying the committee ''will work hard every single day to deliver for all Western Australians, no matter where they live in our vast State'' and that ''it''s time for a new era when it comes to health.'' Aim is for WA to be ''the healthiest state in the nation'' and to reduce long-term hospital demand.',1);
INSERT INTO "position" VALUES(1561,'western-australia-emily-hamilton-joondalup','voluntary_assisted_dying','Emily Hamilton voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1562,'western-australia-jessica-stojkovski-kingsley','voluntary_assisted_dying','Jessica Stojkovski voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1563,'western-australia-roger-cook-kwinana','voluntary_assisted_dying','Roger Cook voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1564,'western-australia-roger-cook-kwinana','gender_lgbtq','Labor MLA (Kwinana); later WA Premier. As Health Minister, Cook publicly opposed gay conversion practices, stating on 3 July 2018: "I am strongly opposed to and do not support the use of sexual orientation change efforts of any kind," and describing practices that attempt to change sexual orientation as "abhorrent" and damaging to the mental health of LGBTI people. As Premier (Cook Labor Government) his government committed to banning LGBTIQA+ conversion practices and delivered gender recognition reforms abolishing the Gender Reassignment Board.',1);
INSERT INTO "position" VALUES(1565,'western-australia-roger-cook-kwinana','religious_freedom','As Premier leading the Cook Labor Government, Cook''s government committed to reforming and narrowing the religious exemptions under the Equal Opportunity Act 1984 (following the Law Reform Commission''s 2022 review, which recommended limiting faith-based bodies'' exemptions) and to strengthening Equal Opportunity protections for LGBTIQA+ staff and students in religious schools, including limiting when Christian schools can hire or enrol based on their beliefs. His government has also committed to introducing a conversion practices ban. The Index report noted the re-elected Cook Government''s commitment to limiting faith-based schools'' hiring and enrolment on the basis of belief. Before the March 2025 election, Cook declined to commit to specific timelines for these reforms, with responses delegated to the Attorney General.',1);
INSERT INTO "position" VALUES(1566,'western-australia-shane-love-mid-west','voluntary_assisted_dying','Shane Love voted AGAINST the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Noes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1567,'western-australia-mark-folkard-mindarie','voluntary_assisted_dying','Mark Folkard voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1568,'western-australia-amber-jade-sanderson-morley','voluntary_assisted_dying','Amber-Jade Sanderson voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1569,'western-australia-amber-jade-sanderson-morley','gender_lgbtq','Labor MLA (Morley) and, as Health Minister, responsible for several LGBTQ-relevant reforms. In the 9 October 2018 surrogacy/ART debate she spoke in favour, saying the bill was "fundamentally about removing discrimination" and that the ability to be a parent had nothing to do with relationship status or sexuality. As Health Minister she said the government was "absolutely committed to" the 2024 surrogacy/ART legislation allowing same-sex couples, single people and trans and intersex West Australians to access surrogacy. In December 2024, responding to Liberal leader Libby Mettam''s call to ban puberty blockers, Sanderson''s spokesperson said the state had no immediate plans to review gender identity services but would continue monitoring international best practice.',1);
INSERT INTO "position" VALUES(1570,'western-australia-yaz-mubarakai-oakford','voluntary_assisted_dying','Yaz Mubarakai voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1571,'western-australia-john-carey-perth','voluntary_assisted_dying','John Carey voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1572,'western-australia-john-carey-perth','gender_lgbtq','Labor MLA for Perth and cabinet minister, openly gay and a long-standing advocate for LGBTQ+ inclusion. Before state parliament, as a City of Vincent councillor he initiated a same-sex relationship register in lieu of federal same-sex marriage, and was elected mayor in 2013. In the 9 October 2018 debate on the surrogacy/ART reform bill he spoke in favour, saying: "I stand on behalf of the gay and lesbian community to support this important social change." He is listed among current openly LGBTQ WA state politicians.',1);
INSERT INTO "position" VALUES(1573,'western-australia-john-carey-perth','housing_planning','As Minister for Planning, Lands, Housing and Homelessness, Carey led WA''s planning reforms (effective 1 March 2024) cutting ''red tape'' to accelerate housing delivery, including a permanent significant development pathway and expanded Development Assessment Panel system: ''The Cook Labor Government continues to lead the nation in driving planning reforms and cutting unnecessary red tape to accelerate the delivery of housing in Western Australia.''',1);
INSERT INTO "position" VALUES(1574,'western-australia-kevin-michel-pilbara','voluntary_assisted_dying','Kevin Michel voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1575,'western-australia-jags-krishnan-riverton','faith','Hindu. Wikipedia''s biography states explicitly in its Personal life section: "He is a Hindu."',1);
INSERT INTO "position" VALUES(1576,'western-australia-peter-rundle-roe','voluntary_assisted_dying','Peter Rundle voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s third reading on 24 September 2019 (passed 45-11). He was not recorded in the second reading division of 3 September 2019.',1);
INSERT INTO "position" VALUES(1577,'western-australia-stuart-aubrey-scarborough','gender_lgbtq','Labor MLA for Scarborough, openly gay, one of six openly LGBT MPs elected to the WA parliament at the 2021 state election. On 19 April 2022, during debate on the Health and Disability Services (Complaints) Amendment Bill 2021 (which extended a code of conduct to help protect people from sexual orientation and gender conversion practices), Aubrey gave an emotional speech disclosing his experience of coming out, depression and suicidal thoughts, declaring "I am a proud gay man" and supporting the legislation. He came out to close friends in September 2012, which he called "one of the best days of my life." He rejected criticism of LGBTQ+ MPs by Mark Latham.',1);
INSERT INTO "position" VALUES(1578,'western-australia-paul-papalia-secret-harbour','voluntary_assisted_dying','Paul Papalia voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1579,'western-australia-paul-papalia-secret-harbour','drugs_law_order','As WA Police Minister, Papalia championed a prohibitionist, enforcement-led approach to methamphetamine. In March 2023 he announced legislation giving police the power to conduct warrantless random drug searches at locations near the state border, explicitly targeting methamphetamine. He cited COVID-era border controls, stating ''During Covid, there was a massive drop in meth use in Western Australia because of the border search power that was in place at that time,'' and said reinstating the powers would deliver ''a huge return in community safety.'' He has also rejected claims linking liquor restrictions in the Kimberley to rising meth use.',1);
INSERT INTO "position" VALUES(1580,'western-australia-terry-healy-southern-river','faith','Christian. Healy has said he is "proud to call himself a Christian" and argued that marriage equality is in line with Christian teachings.',1);
INSERT INTO "position" VALUES(1581,'western-australia-terry-healy-southern-river','voluntary_assisted_dying','Terry Healy voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1582,'western-australia-libby-mettam-vasse','voluntary_assisted_dying','Libby Mettam voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1583,'western-australia-libby-mettam-vasse','gender_lgbtq','Liberal MLA (Vasse), former WA Liberal leader. Mettam has campaigned to ban puberty blockers and transgender health care for under-18s, making it a central plank of her pitch to be premier at the 2025 election. On 14 December 2024 she said Australia should follow the UK and immediately ban puberty blockers for youth gender dysphoria, urging MPs to "simply put the ideology aside, look at the evidence" and stating "We must ensure that the treatment of children and young people with gender dysphoria is safe in the long term as well as the short term." Reporting noted she declined to meet with parents of transgender youth in her own electorate concerned about her approach.',1);
INSERT INTO "position" VALUES(1584,'western-australia-libby-mettam-vasse','health','WA Shadow Minister for Health and Mental Health (Liberal, has held the Health portfolio in opposition since 2021) and Deputy Leader of the Opposition. Stated priorities are tackling excessive ambulance ramping, reducing long hospital wait lists and safeguarding the future of the Women and Babies Hospital, holding the Cook Labor government to account on health.',1);
INSERT INTO "position" VALUES(1585,'western-australia-sabine-winton-wanneroo','voluntary_assisted_dying','Sabine Winton voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1586,'western-australia-sabine-winton-wanneroo','education','WA Minister for Education, Early Childhood, Preventative Health and Wheatbelt (since March 2025); a former teacher of 27 years. Her portfolio covers the Department of Education, the Teacher Registration Board and the School Curriculum and Standards Authority. In her early-childhood capacity she moved (via the Education and Care Services National Law Application Bill 2025) to ban educators'' personal mobile phone use in early learning centres, saying the reforms aim to ''restore trust'' and keep educators ''fully present and accountable.''',1);
INSERT INTO "position" VALUES(1587,'western-australia-rita-saffioti-west-swan','voluntary_assisted_dying','Rita Saffioti voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Assembly. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 3 September 2019 (passed 44-12) and at the third reading on 24 September 2019 (passed 45-11).',1);
INSERT INTO "position" VALUES(1588,'western-australia-klara-andric-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1589,'western-australia-rod-caddies-statewide','faith','Christian. Wikipedia states "He is a Christian" and notes "Caddies has described himself as socially conservative and a Christian." In his inaugural speech (27 May 2025) he said "Along my journey, I became a Christian. That decision changed my life. My faith gave me purpose, clarity and direction."',1);
INSERT INTO "position" VALUES(1590,'western-australia-rod-caddies-statewide','gender_lgbtq','Pauline Hanson''s One Nation MLC. During the November 2025 Legislative Council debate on Maryka Groenewald''s motion on transparency over gender treatment information, Caddies described the current approach to gender-affirming care as "irreversible medical experiments on children." He abandoned his speech after a point of order in which the acting president directed him to focus on transparency rather than treatment views.',1);
INSERT INTO "position" VALUES(1591,'western-australia-dan-caddy-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1592,'western-australia-dan-caddy-statewide','religious_freedom','Labor MLC who, as Parliamentary Secretary representing Attorney General Tony Buti, responded to Maryka Groenewald''s question without notice on the Australian Christian Freedom Index in the Legislative Council (question put 9 June 2026). Reading from prepared notes, Caddy confirmed the Government was aware of the Index and stated that ''the various Christian communities make valuable contributions to the lives of many Western Australians.'' His response contained no specific pledge on Christian freedom of expression, committing instead to Equal Opportunity legislation that is ''fair and effective'' and ''achieves a balance between the rights and interests of the diverse community living in our State.''',1);
INSERT INTO "position" VALUES(1593,'western-australia-sandra-carr-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1594,'western-australia-tim-clifford-statewide','voluntary_assisted_dying','Tim Clifford voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1595,'western-australia-alanna-clohesy-statewide','voluntary_assisted_dying','Alanna Clohesy voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1596,'western-australia-stephen-dawson-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1597,'western-australia-stephen-dawson-statewide','voluntary_assisted_dying','Stephen Dawson voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1598,'western-australia-stephen-dawson-statewide','gender_lgbtq','Labor MLC since 2013 and cabinet minister; openly gay and a prominent LGBTQ legislator. In December 2013 he and his partner Dennis Liddelow became the first same-sex couple to be legally married in Australia, in an ACT midnight ceremony; the marriage was annulled six days later after the High Court struck down the ACT law under the federal Marriage Act. He is listed among current openly LGBTQ WA state politicians.',1);
INSERT INTO "position" VALUES(1599,'western-australia-kate-doust-statewide','abortion','Voted NO (Noes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, opposing the bill. A Labor member identified as pro-life, she questioned the bill extensively during debate and supported (unsuccessful) amendments including a ban on sex-selection abortion. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1600,'western-australia-simon-ehrenfeld-statewide','faith','Jewish. Wikipedia states plainly "Ehrenfeld is Jewish" and categorises him as a Jewish Australian politician. He is a congregant of the Perth Hebrew Congregation. His Jewish identity was the subject of a 2016 WA Liberal preselection controversy.',1);
INSERT INTO "position" VALUES(1601,'western-australia-simon-ehrenfeld-statewide','gender_lgbtq','Liberal MLC. Acting as President during the November 2025 Legislative Council debate on Maryka Groenewald''s gender-treatment transparency motion, Ehrenfeld called One Nation MLC Rod Caddies to focus his remarks on transparency rather than his views on gender treatment. (Procedural role; no personal position on the substance recorded in the source.)',1);
INSERT INTO "position" VALUES(1602,'western-australia-maryka-groenewald-statewide','faith','Christian. As leader of the Australian Christians and the party''s first member elected to any Australian parliament, Groenewald is openly Christian. In her inaugural speech (19 June 2025) she said "the story of Jesus, his resurrection and the transforming truth of the gospel remains the biggest game changer in my life," while adding "I am not here to push my faith on anyone." She has spoken of her faith-based community work and praying weekly over her political work.',1);
INSERT INTO "position" VALUES(1603,'western-australia-maryka-groenewald-statewide','gender_lgbtq','Leader of the Australian Christians party and, after the 2025 state election, the first member of her party elected to any Australian state parliament (WA Legislative Council; inaugural speech 19 June 2025). The Australian Christians platform opposes same-sex marriage and homosexuality. Groenewald has made transgender health care a primary focus, repeatedly demanding the WA government publicly release the Child and Adolescent Gender Diversity Service''s Standards of Care and accusing the government of "secrecy." Her amended transparency motion was defeated 19-17 in November 2025; she said it "has always been about ensuring that Parliament reaffirms its commitment to genuine transparency." She opposes gender-affirming care for minors. In a March 2026 Facebook post about a menopause health seminar she wrote: "A MAN cannot be a WOMAN."',1);
INSERT INTO "position" VALUES(1604,'western-australia-maryka-groenewald-statewide','religious_freedom','Australian Christians MLC and party leader, elected to the Legislative Council in 2025 as the first member of her party to win a state parliamentary seat. In her inaugural speech (19 June 2025) she championed Australia''s ''Christian heritage'' and argued that separation of church and state ''was always about preventing an exertion of the power of the state over the church, and vice versa'' rather than limiting Christian expression in public. She listed party concerns including opposing ''moves to strip Christian schools of their freedom to employ staff who want to live out their faith,'' preserving parental choice in education, protecting Christian teachers, and ''stopping aggressive activist LGBTQ+ legislation from making prayer a thought crime.'' On 9 June 2026 she put a question without notice to the Legislative Council citing the Australian Christian Freedom Index (which ranked WA the ''least restrictive'' jurisdiction in Australia), asking whether the Government would commit to protecting Christians'' right to express their faith freely under any changes to the Equal Opportunity Act.',1);
INSERT INTO "position" VALUES(1605,'western-australia-nick-goiran-statewide','faith','Christian (conservative/evangelical). Wikipedia describes him as a "conservative Christian" and "vocal conservative Christian." Goiran has stated "I have known no part of my life, otherwise than with faith" and "The most important things to me in life are faith, family and friends." He attended Rehoboth Christian College (of which he is a patron) and is a leading figure of the WA Liberal Party''s Christian right.',1);
INSERT INTO "position" VALUES(1606,'western-australia-nick-goiran-statewide','abortion','Voted NO (Noes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, opposing the bill. A Liberal MLC and prominent pro-life campaigner, he led the opposition''s questioning over about nine sitting days and moved numerous (unsuccessful) amendments. The bill decriminalised abortion, removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1607,'western-australia-nick-goiran-statewide','voluntary_assisted_dying','Nick Goiran voted AGAINST the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Noes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1608,'western-australia-nick-goiran-statewide','gender_lgbtq','Liberal MLC and a leading social conservative in the WA Liberal Party. During the 2019 debate on gender reassignment/recognition legislation, Goiran argued gender dysphoria should be treated as a psychological matter, stating: "In essence there are only two alternatives. One perspective believes the solution is a physical one... Whereas others, including me, believe the solution should be to treat it psychologically." He raised concerns about young people accessing gender services at Perth Children''s Hospital. In August 2013 he opposed same-sex marriage in parliamentary remarks (comments criticised by then-Premier Colin Barnett). In March 2023 he publicly supported Victorian Liberal MP Moira Deeming. In September 2024 he opposed the process used to pass the Births, Deaths and Marriages Registration Amendment (Sex or Gender Changes) Bill, calling the government''s use of urgent legislation a "political battering ram." He is described as one of the staunchest pro-life campaigners in WA parliament.',1);
INSERT INTO "position" VALUES(1609,'western-australia-nick-goiran-statewide','religious_freedom','Long-serving Liberal MLC (since 2009) and Leader of the Opposition in the Legislative Council since May 2025, also Shadow Attorney General. A self-described conservative Christian who attended Christian schools and served on the board of the Association for Christian Education. He sponsors a campaign titled ''Leave Faith-Based Schools Alone,'' reflecting his support for protecting faith-based educational institutions. Historically he opposed same-sex marriage, speaking against it in parliament in August 2013, and is pro-life and opposed to euthanasia and surrogacy.',1);
INSERT INTO "position" VALUES(1610,'western-australia-nick-goiran-statewide','drugs_law_order','A barrister and one of the WA Parliament''s most prominent socially conservative members, Goiran has served as Shadow Attorney General (April 2021-February 2023, and again from December 2024) and is Leader of the Opposition in the Legislative Council. On law and order, in 2025 he vocally opposed Labor proposals to raise the age of criminal responsibility from 10 to 12 or 14, arguing against increased leniency for young offenders. He has a long record of justice-related advocacy, including a 2017 parliamentary motion for an inquiry into elder abuse seeking to make it a specific criminal offence.',1);
INSERT INTO "position" VALUES(1611,'western-australia-jackie-jarvis-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1612,'western-australia-jackie-jarvis-statewide','native_forest_logging','As WA Minister for Forestry, Jarvis (ALP) supported ending commercial native forest logging in WA (effective 1 Jan 2024), stating: ''This historic decision reflects the changing climate and community attitudes, and will safeguard our iconic forests.''',1);
INSERT INTO "position" VALUES(1613,'western-australia-ayor-makur-chuot-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1614,'western-australia-steve-martin-statewide','abortion','Voted NO (Noes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, opposing the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The bill nonetheless passed the Council 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1615,'western-australia-brad-pettitt-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1616,'western-australia-brad-pettitt-statewide','gender_lgbtq','WA Greens parliamentary leader and the party''s LGBTQIA+ spokesperson. Pettitt has been a vocal advocate for banning conversion practices, reforming the Equal Opportunity Act, and gender recognition reform via a self-identification (statutory declaration) model. On the 2024 Births, Deaths and Marriages Registration Amendment (Sex or Gender Changes) Bill (which abolished the Gender Reassignment Board), he supported abolishing the board but opposed the bill as written, saying the government''s handling was "undemocratic" and that the bill "continues to medicalise trans, intersex and gender-diverse identities," while calling the Gender Reassignment Board "a cruel, unnecessary, and humiliating barrier." In the November 2025 debate on Maryka Groenewald''s gender-treatment transparency motion, he said "We want the LGBTQIA+ community to be granted equality and autonomy over medical processes," supporting trans youth access to care.',1);
INSERT INTO "position" VALUES(1617,'western-australia-brad-pettitt-statewide','religious_freedom','Greens MLC who has advocated for banning conversion practices in WA and for reforming the Equal Opportunity Act. Launching the Greens'' LGBTQIA+ election platform priorities (12 February 2025), Pettitt said: ''In the next Parliament...the Greens (WA) will fight to ensure that life-changing reforms to the Equal Opportunity Act and the banning of archaic and harmful conversion practices...are finally realised.'' He has criticised WA Labor''s failure to deliver on promises to reform the Equal Opportunity Act, ban conversion practices and scrap the gender reassignment board, and stated the Greens have long pushed the government to reform the Act.',1);
INSERT INTO "position" VALUES(1618,'western-australia-samantha-rowe-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1619,'western-australia-samantha-rowe-statewide','voluntary_assisted_dying','Samantha Rowe voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1620,'western-australia-phil-scott-statewide','faith','Christian. In his inaugural speech to the Legislative Council (27 May 2025) Scott opened by acknowledging "the Lord Jesus Christ, the King of the Nations" and gave thanks for the grace extended to him.',1);
INSERT INTO "position" VALUES(1621,'western-australia-tjorn-sibma-statewide','abortion','Voted NO (Noes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, opposing the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The bill nonetheless passed the Council 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1622,'western-australia-tjorn-sibma-statewide','voluntary_assisted_dying','Tjorn Sibma voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1623,'western-australia-matthew-swinbourn-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1624,'western-australia-matthew-swinbourn-statewide','voluntary_assisted_dying','Matthew Swinbourn voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1625,'western-australia-matthew-swinbourn-statewide','native_forest_logging','As the WA minister handling the Conservation and Land Management Amendment Bill 2025 (which enshrined the ban on commercial native forest logging in law, June 2025), Swinbourn (ALP) championed the bill, saying it ''locks in that progress, ensuring our South West native forests are protected from large-scale harvesting'' and calling it ''a landmark moment for WA Labor and a major step forward for protecting our native forests.''',1);
INSERT INTO "position" VALUES(1626,'western-australia-parwinder-kaur-statewide','faith','Sikh. Kaur became the first Sikh woman elected to an Australian parliament and the first politician in Australia to be sworn in on Sikh scripture (the Gutka Sahib), standing barefoot with her head covered. She said "Gurbani has helped shape my life" and "In Gurbani, we pray for sarbat da bhala (wellbeing for all)" and stated that identifying openly with her religious beliefs helps her serve all Australians.',1);
INSERT INTO "position" VALUES(1627,'western-australia-steve-thomas-statewide','voluntary_assisted_dying','Steve Thomas voted AGAINST the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Noes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1628,'western-australia-neil-thomson-statewide','abortion','Voted NO (Noes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, opposing the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The bill nonetheless passed the Council 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1629,'western-australia-brian-walker-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1630,'western-australia-brian-walker-statewide','drugs_law_order','Leader of the Legalise Cannabis WA Party and a GP, Walker is the WA Parliament''s leading advocate for cannabis law reform. On 19 March 2026 he introduced the Misuse of Drugs (Lawful Personal Use of Cannabis) Amendment Bill 2026 in the Legislative Council, which would amend the Misuse of Drugs Act 1981 to allow adults to cultivate up to six cannabis plants at their primary residence, possess up to 50 grams for personal use, and gift up to 50 grams to other adults (no commercial sale, no public use, no use around children), and would void existing infringement notices for conduct made lawful. He framed it as ''treating adults like adults'' and argued the decades-long prohibition is ''without merit'' since medicinal cannabis was legalised in 2016. He became party leader in May 2024 and was re-elected in the 2025 state election.',1);
INSERT INTO "position" VALUES(1631,'western-australia-pierre-yang-statewide','faith','Catholic. In his inaugural speech to the Legislative Council (25 May 2017) Yang said "I am proud to be Labor and I am proud to be Catholic," thanked Father Timothy Corcoran of Thornlie Sacred Heart Catholic Church for bringing him to the Catholic faith, and spoke of the similarities between Labor values and Catholic traditions.',1);
INSERT INTO "position" VALUES(1632,'western-australia-pierre-yang-statewide','abortion','Voted YES (Ayes) on the third reading of the Abortion Legislation Reform Bill 2023 in the WA Legislative Council on 20 September 2023, supporting the bill''s passage. The bill decriminalised abortion (removing it from the Criminal Code), removed mandatory counselling and the doctor-referral requirement, and raised the gestational limit for additional restrictions from 20 to 23 weeks. The third reading passed 25 Ayes to 6 Noes.',1);
INSERT INTO "position" VALUES(1633,'western-australia-pierre-yang-statewide','voluntary_assisted_dying','Pierre Yang voted FOR the Voluntary Assisted Dying Bill 2019 in the WA Legislative Council. On the conscience (free) vote, the member is recorded in the Ayes at the bill''s second reading on 23 October 2019 (passed 25-10) and at the third reading on 5 December 2019 (passed 24-11).',1);
INSERT INTO "position" VALUES(1634,'western-australia-pierre-yang-statewide','gender_lgbtq','Labor MLC. In the November 2025 Legislative Council debate on Australian Christians MLC Maryka Groenewald''s motion seeking public disclosure of the Child and Adolescent Gender Diversity Service''s Standards of Care, Yang opposed the motion and voted against it, saying: "These concerns are not about secrecy; they are about safeguarding the wellbeing of patients." The motion was defeated 19-17.',1);
INSERT INTO "position" VALUES(1635,'victoria-2026-andrew-lethlean-bendigo-east','drugs_law_order','Lists community safety as a key campaign priority, stating that "crime is making people feel unsafe" and calling for "safer communities".',1);
INSERT INTO "position" VALUES(1636,'victoria-2026-liza-shaw-bendigo-west','gender_lgbtq','As Greens candidate for Bendigo West, Shaw lists fighting for LGBTQIA+ equality as a campaign priority, stating she will "fight for First Nations justice and LGBTQIA+ equality".',1);
INSERT INTO "position" VALUES(1637,'victoria-2026-saravina-afaj-box-hill','gender_lgbtq','Her Victorian Socialists candidate page states she has "been involved in campaigns against racism, homophobia and transphobia" and stands for "gender and racial equality and the protection of marginalised peoples."',1);
INSERT INTO "position" VALUES(1638,'victoria-2026-jessica-smith-brighton','gender_lgbtq','States on her Victorian Socialists candidate page that she has campaigned for marriage equality.',1);
INSERT INTO "position" VALUES(1639,'victoria-2026-naomi-farmer-brunswick','gender_lgbtq','Farmer lists her involvement in the "equal marriage" (marriage equality) campaign among the community campaigns she has been part of, alongside Palestine solidarity and refugee rights.',1);
INSERT INTO "position" VALUES(1640,'victoria-2026-michal-kedem-essendon','drugs_law_order','Victorian Socialists candidate for Essendon and a community lawyer, Kedem calls for redirecting funding away from policing and prisons, stating: "We need more funding for healthcare, education including childcare, and housing, not more police, prisons, defence or deportations." Her profile describes her work on police accountability and opposing the criminalisation of vulnerable people.',1);
INSERT INTO "position" VALUES(1641,'victoria-2026-jasmine-duff-footscray','gender_lgbtq','On her Victorian Socialists candidate page, Duff states she has "campaigned for equal marriage, climate action, Indigenous justice, and for peace and justice for the people of Palestine," indicating support for LGBTIQ+ equality including same-sex marriage.',1);
INSERT INTO "position" VALUES(1642,'victoria-2026-andrew-cheeseman-frankston','gender_lgbtq','Cheeseman''s Victorian Socialists candidate profile states he has been an activist for 24 years, including campaigning for marriage equality.',1);
INSERT INTO "position" VALUES(1643,'victoria-2026-courtney-millett-kalkallo','drugs_law_order','Millett''s Victorian Socialists candidate page advocates for communities ''supported to thrive without resorting to fear-based "law and order" politics'', emphasising care rather than punishment.',1);
INSERT INTO "position" VALUES(1644,'victoria-2026-connor-buchanan-mulgrave','gender_lgbtq','Buchanan''s Victorian Socialists candidate page states he opposes homophobia and transphobia and opposes attacks on trans rights.',1);
INSERT INTO "position" VALUES(1645,'victoria-2026-kath-larkin-northcote','gender_lgbtq','States on her Victorian Socialists candidate page that she has been involved in campaigning for marriage equality, LGBTIQ+ rights, and women''s rights.',1);
INSERT INTO "position" VALUES(1646,'victoria-2026-rowdy-bugter-oakleigh','gender_lgbtq','On his Victorian Socialists candidate page, Bugter says he wants to "fight against the billionaire-owned media that divides the working class by pushing racism, homophobia and transphobia as ''common sense'' ideas" and to build solidarity between workers of all backgrounds and identities.',1);
INSERT INTO "position" VALUES(1647,'victoria-2026-taylor-laine-point-cook','gender_lgbtq','Laine lists advocating for the queer community as part of their ongoing activism.',1);
INSERT INTO "position" VALUES(1648,'victoria-2026-hutch-hussein-polwarth','faith','Hussein regards herself as a "cultural Muslim". She was the first person from a Muslim background to serve as Victorian Labor state president and has been involved in the Muslim Women''s Project.',1);
INSERT INTO "position" VALUES(1649,'victoria-2026-john-stanley-warrandyte','abortion','States on his Victorian Socialists candidate page that he and the party have campaigned for abortion rights.',1);
INSERT INTO "position" VALUES(1650,'victoria-2026-sue-munro-werribee','abortion','Munro lists supporting reproductive freedom for women among her community campaigns and says Werribee''s hospital should provide reproductive freedom to women.',1);
INSERT INTO "position" VALUES(1651,'victoria-2026-sue-munro-werribee','gender_lgbtq','Munro lists supporting the LGBTQ community among her community campaign involvements.',1);
INSERT INTO "position" VALUES(1652,'victoria-2026-sue-munro-werribee','drugs_law_order','Munro says Werribee needs sensible responses to crime and addiction, arguing that people in poverty with no hope are not healed by prison and typically come out more harmed.',1);
